#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation always produces a different permutation
    // (unless n=1, but n>=2 is guaranteed) and has the same fingerprint.
    // The sums of adjacent elements for p are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    // The sums of adjacent elements for p_reversed are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // These two sets of sums are identical, just in reverse order.
    // Therefore, their sorted versions (fingerprints) will be identical.
    // Since n >= 2, p and p_reversed are different permutations unless p is a palindrome,
    // but even if p is a palindrome, the problem guarantees a solution exists,
    // and reversing is the simplest approach that works for all n >= 2.
    // The problem statement implies that p_reversed is always a valid different permutation.
    // For example, if p = [1,2], p_reversed = [2,1]. F(p) = [3], F(p_reversed) = [3].
    // If p = [1,2,3], p_reversed = [3,2,1]. F(p) = sort([3,5]) = [3,5]. F(p_reversed) = sort([5,3]) = [3,5].

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

