#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    int initial_a1 = a[0];
    int max_a1 = initial_a1;

    // Iterate through piles from 2 to n (index 1 to n-1)
    for (int i = 1; i < n; ++i) {
        int pile_idx = i; // 0-indexed
        int pile_num = i + 1; // 1-indexed
        int haybales_in_pile = a[pile_idx];
        int cost_per_haybale = pile_idx; // distance from pile_idx to 0

        if (cost_per_haybale == 0) { // Should not happen for i > 0
            continue;
        }

        // Calculate how many haybales can be moved from this pile
        // given the remaining days.
        // Each haybale costs `cost_per_haybale` days.
        int haybales_to_move = 0;
        if (d >= cost_per_haybale) {
            haybales_to_move = std::min(haybales_in_pile, d / cost_per_haybale);
        }

        max_a1 += haybales_to_move;
        d -= haybales_to_move * cost_per_haybale;

        if (d <= 0) {
            break; // No more days left
        }
    }

    std::cout << max_a1 << std::endl;
}

