#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
        return;
    }

    // For n > 1, we can construct a number.
    // A simple construction is to use '2' as the first digit,
    // and '3' for all subsequent digits, except the last one.
    // The last digit can be '9'.
    // This forms a number like 233...39.
    // Let's check divisibility:
    // 1. Divisibility by 2: The number ends in 9, so it's not divisible by 2.
    // 2. Divisibility by 3: The sum of digits is 2 + (n-2)*3 + 9.
    //    Sum = 2 + 3n - 6 + 9 = 3n + 5.
    //    For this to be divisible by 3, 3n + 5 must be divisible by 3.
    //    This means 5 must be divisible by 3, which is false.
    //    So, the number is not divisible by 3.
    // 3. Divisibility by 9: The sum of digits is 3n + 5.
    //    For this to be divisible by 9, 3n + 5 must be divisible by 9.
    //    This is generally not true. For example, if n=2, sum=11. If n=3, sum=14.
    //    If n=4, sum=17.
    //    The only case where 3n+5 is divisible by 9 is if 3n+5 = 9k.
    //    3n = 9k - 5. This implies 9k-5 must be divisible by 3, which means 5 must be divisible by 3. False.
    //    So, the number is not divisible by 9.
    //
    // This construction works for n >= 2.
    // Example:
    // n=2: 29 (2+9=11, not div by 3 or 9. Not div by 2)
    // n=3: 239 (2+3+9=14, not div by 3 or 9. Not div by 2)
    // n=4: 2339 (2+3+3+9=17, not div by 3 or 9. Not div by 2)

    std::cout << '2';
    for (int i = 0; i < n - 2; ++i) {
        std::cout << '3';
    }
    std::cout << '9' << std::endl;
}

