#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // The flags `has_pos_one` and `has_neg_one` must reflect the state
            // of elements *to the left* of `i`.
            // If a[i] was 1, it can no longer be used for future elements (i.e., elements to its right, which we've already processed).
            // Same for -1.
            if (a[i] == 1) has_pos_one = false;
            if (a[i] == -1) has_neg_one = false;
            continue;
        }

        if (a[i] < b[i]) {
            // Need to increase a[i]. This requires a `1` to its left.
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            // Need to decrease a[i]. This requires a `-1` to its left.
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }

        // Update flags for elements to the left of current `i`.
        // The current `a[i]` value is effectively "used up" or "transformed"
        // and cannot be used to modify elements to its right (which are already processed).
        // So, if a[i] was 1 or -1, it no longer contributes to `has_pos_one` or `has_neg_one`
        // for elements to its left.
        if (a[i] == 1) has_pos_one = false;
        if (a[i] == -1) has_neg_one = false;
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

