    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_gap = 0;
        int last_r_pos = 0; // Represents the position of the last 'R' or the starting point (0)
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                max_gap = std::max(max_gap, (i + 1) - last_r_pos);
                last_r_pos = i + 1;
            }
        }
        // After iterating through the string, consider the gap from the last 'R' to n+1
        // If no 'R's were found, last_r_pos remains 0, and the gap is n+1 - 0 = n+1.
        // If 'R's were found, last_r_pos is the position of the last 'R', and the gap is (n+1) - last_r_pos.
        max_gap = std::max(max_gap, (n + 1) - last_r_pos);
        std::cout << max_gap << "\n";
    }
    return 0;
}

