#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            max_val = std::max(max_val, a[i][j]);
        }
        p[i] = max_val;
    }

    // Check if n is present in p. If not, it means the maximum value in the permutation is n.
    // If n is not present in p, it means that for some p_k, max_{j!=k} min(p_k, p_j) was not n.
    // This implies that p_k must be n, and all other p_j must be less than n.
    // In this case, max_{j!=k} min(n, p_j) = max_{j!=k} p_j = n-1 (if n-1 is the largest among others).
    // So, if n is not found in the current p, it means one of the p_i values should be n.
    // The one that should be n is the one whose current p_i value is n-1 (or the largest value found).
    // This is because if p_k = n, then max_{j!=k} min(p_k, p_j) = max_{j!=k} p_j.
    // Since p is a permutation of 1..n, the largest value among p_j (j!=k) would be n-1.
    // So, if p_k = n, then the calculated p[k] would be n-1.
    // We need to find the maximum value in the current p and increment it to n if it's not already n.

    int max_in_p = 0;
    for (int val : p) {
        max_in_p = std::max(max_in_p, val);
    }

    if (max_in_p < n) { // This means n is not present in the current p values.
                        // One of the elements whose p[i] was calculated as max_in_p should actually be n.
                        // Since there's only one 'n' in the permutation, and all other values are < n,
                        // the max_in_p must be n-1.
                        // So, we find an element whose p[i] is max_in_p and set it to n.
        for (int i = 0; i < n; ++i) {
            if (p[i] == max_in_p) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

