#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i+1]
    // This marks the end of the initial non-increasing suffix
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is non-increasing.
    // If i=0, the whole array is non-increasing.

    // Find the rightmost index `j` such that a[j] > a[j+1]
    // This marks the end of the initial non-decreasing suffix
    // We start from `i` because any elements to the right of `i` are already part of a non-increasing suffix.
    // We are looking for the first element from the right that breaks the non-decreasing property
    // when scanning from right to left.
    int j = i;
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now, a[j...n-1] is a "good" suffix.
    // The elements a[j...i-1] are non-decreasing, and a[i...n-1] are non-increasing.
    // This means a[j...n-1] can be sorted by picking elements from ends.

    std::cout << j << std::endl;
}

