int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0) {
            std::cout << "Y 0.000000000 0.000000000\n";
        } else if (d < 4) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4 * d;
            // Since d >= 4, discriminant >= 0, so sqrt is always real.
            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // Both a1 and b1 must be non-negative.
            // Since d >= 4, d + sqrt_discriminant is positive.
            // For b1, d - sqrt_discriminant:
            // We know d^2 - 4d >= 0 => d^2 >= 4d.
            // Since d >= 4, d is positive, so we can divide by d: d >= 4.
            // This means d >= sqrt(4d).
            // So d - sqrt(4d) >= 0.
            // Since sqrt_discriminant = sqrt(d^2 - 4d), and d^2 - 4d <= d^2,
            // sqrt(d^2 - 4d) <= d.
            // Thus, d - sqrt(d^2 - 4d) >= 0.
            // So both a1 and b1 are non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    std::vector<long long> left_min_val(n);
    left_min_val[0] = 0; // a[0] must be at least 0
    for (int i = 1; i < n; ++i) {
        left_min_val[i] = std::max(left_min_val[i - 1] + 1, 0LL); // a[i] must be > a[i-1]
    }

    std::vector<long long> right_min_val(n);
    right_min_val[n - 1] = 0; // a[n-1] must be at least 0
    for (int i = n - 2; i >= 0; --i) {
        right_min_val[i] = std::max(right_min_val[i + 1] + 1, 0LL); // a[i] must be > a[i+1]
    }

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        // For a peak at index k, we need:
        // 1. a[0] < a[1] < ... < a[k]
        // 2. a[k] > a[k+1] > ... > a[n-1]
        // This means a[k] must be able to satisfy both conditions.
        // Specifically, a[k] must be at least left_min_val[k] (for the increasing part)
        // AND a[k] must be at least right_min_val[k] (for the decreasing part).
        // So, a[k] must be at least max(left_min_val[k], right_min_val[k]).
        // If the original a[k] is less than this required minimum, it's not possible for this k.
        if (a[k] >= std::max(left_min_val[k], right_min_val[k])) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

