            // If a[right_ptr] is not greater than a[left_ptr],
            // we cannot use a[right_ptr] for a[left_ptr].
            // We try the next available element for placement (increment right_ptr).
            // left_ptr stays, hoping a larger element will come.
            right_ptr++;
        }
    }

