    }

    // Case 4: Final toy in Box 4 (P_large: value >= 1)
    // This requires an even number of negative factors.
    // And the absolute value of the product must be >= 1.
    // If A+D == 0, then all toys are in B or C. Product is always in (-1, 1).
    // So if A+D == 0, Box 4 is impossible.
    if (A + D > 0) { // At least one toy with |value| >= 1 initially
        // To get to Box 4 (positive, |value| >= 1):
        // Need even number of negative factors.
        // If B is even, we can make the final product positive.
        // If B is odd, we need A to be odd to make the final product positive.
        // So, (A+B) % 2 == 0 is required for positive product.
        if ((A + B) % 2 == 0) {
            ans4 = "Ya";
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

