#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a sub-array is a permutation of its length
// `arr` is the full array, `start_idx` is the starting index of the sub-array,
// `len` is the length of the sub-array.
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) return false; // Permutations must have non-zero length
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        int max_overall = 0;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] > max_overall) {
                max_overall = a[i];
            }
        }

        // Precompute max prefix and max suffix values
        std::vector<int> max_prefix(n);
        max_prefix[0] = a[0];
        for (int i = 1; i < n; ++i) {
            max_prefix[i] = std::max(max_prefix[i - 1], a[i]);
        }

        std::vector<int> max_suffix(n);
        max_suffix[n - 1] = a[n - 1];
        for (int i = n - 2; i >= 0; --i) {
            max_suffix[i] = std::max(max_suffix[i + 1], a[i]);
        }

        std::vector<std::pair<int, int>> results;

        // Check for split point l1
        // l1 ranges from 1 to n-1
        for (int l1 = 1; l1 < n; ++l1) {
            int l2 = n - l1;

            // Optimization: Check if max element in p1 is l1 and max element in p2 is l2
            // This is a necessary condition for a permutation.
            if (max_prefix[l1 - 1] != l1 || max_suffix[l1] != l2) {
                continue;
            }

            // Check if p1 is a permutation of length l1
            // Use a frequency array for efficiency
            std::vector<bool> seen_p1(l1 + 1, false);
            bool p1_is_perm = true;
            for (int i = 0; i < l1; ++i) {
                int val = a[i];
                if (val < 1 || val > l1 || seen_p1[val]) {
                    p1_is_perm = false;
                    break;
                }
                seen_p1[val] = true;
            }
            if (!p1_is_perm) {
                continue;
            }

            // Check if p2 is a permutation of length l2
            std::vector<bool> seen_p2(l2 + 1, false);
            bool p2_is_perm = true;
            for (int i = 0; i < l2; ++i) {
                int val = a[l1 + i];
                if (val < 1 || val > l2 || seen_p2[val]) {
                    p2_is_perm = false;
                    break;
                }
                seen_p2[val] = true;
            }
            if (p2_is_perm) {
                results.push_back({l1, l2});
            }
        }

        std::cout << results.size() << "\n";
        for (const auto& p : results) {
            std::cout << p.first << " " << p.second << "\n";
        }
    }
    return 0;
}

