char get_winning_move(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char ch : s) {
            counts[ch]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Iterate in a fixed order to ensure consistent tie-breaking if needed,
        // though problem statement implies any optimal is fine.
        // R, P, S is a common order.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }

        // If all counts are 0 (empty string, not possible by constraints n>=1),
        // or if there's only one type of character, this will pick it.
        // If n=1, counts will have one entry, max_count will be 1.

        char my_optimal_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << my_optimal_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    // We need current_sum + B = 2 * (current_xor ^ B)
    // Let B be the elements we append.
    // We can always append at most 3 elements.
    // A simple strategy is to append two elements: current_xor and current_sum + current_xor.
    // Let's try to append two elements: X_0 and S_0 + X_0.
    // New sum S' = S_0 + X_0 + (S_0 + X_0) = 2 * (S_0 + X_0)
    // New XOR X' = X_0 ^ X_0 ^ (S_0 + X_0) = 0 ^ (S_0 + X_0) = S_0 + X_0
    // So S' = 2 * X' is satisfied.
    // This strategy always works and uses 2 elements.

    // The problem statement says "append at most 3 elements".
    // If the array is already good, we can append 0 elements.
    // If not, we can append 2 elements.
    // The example output for [1,1] is 3 elements: 2 6 2.
    // Initial: S=2, X=0. S != 2X.
    // Append 2, 6, 2:
    // New S = 2 + 2 + 6 + 2 = 12
    // New X = 0 ^ 2 ^ 6 ^ 2 = 0 ^ 2 ^ 6 ^ 2 = 6
    // 12 = 2 * 6. This is good.

    // Let's use the strategy of appending two elements: current_xor and current_sum + current_xor.
    // This is guaranteed to work.
    // Let X = current_xor.
    // Let S = current_sum.
    // We want to find b1, b2 such that S + b1 + b2 = 2 * (X ^ b1 ^ b2).
    // Choose b1 = X.
    // Then S + X + b2 = 2 * (X ^ X ^ b2)
    // S + X + b2 = 2 * (0 ^ b2)
    // S + X + b2 = 2 * b2
    // S + X = b2
    // So, the two elements are X and S + X.

    // Let's verify this:
    // New sum S' = S + X + (S + X) = 2 * (S + X)
    // New XOR X' = X ^ X ^ (S + X) = 0 ^ (S + X) = S + X
    // Condition S' = 2 * X' becomes 2 * (S + X) = 2 * (S + X), which is true.

    // The problem asks for "at most 3 elements".
    // This strategy uses 2 elements.
    // The values can be large, up to 10^9 for initial elements, so S can be up to 10^5 * 10^9 = 10^14.
    // X can be up to 2^60 approx.
    // S+X can be up to 10^14 + 2^60, which fits in long long (10^18).

    std::cout << 2 << std::endl;
    std::cout << current_xor << " " << current_sum + current_xor << std::endl;
}

