int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it can be "jumped over" by all 'a's
            // currently to its left (represented by count_a).
            // Each such 'a' will perform an operation with this 'b'.
            // The number of operations is count_a.
            total_steps = (total_steps + count_a) % MOD;

            // After all 'a's to its left have jumped over this 'b',
            // this 'b' effectively becomes two 'b's for future 'a's
            // that are even further to the left.
            // So, the number of 'a's that will jump over future 'b's
            // (which are to the left of current 'b') will be doubled.
            // This is because each 'a' that jumps over this 'b'
            // effectively creates a new 'b' to its left.
            // So, count_a effectively doubles for the next 'b' encountered.
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's
            // that are waiting to jump over 'b's to their right.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
