long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1 coin
                // If Chanek takes 1, N becomes N-1 (odd).
                // Opponent will take 1, N becomes N-2 (even).
                // Chanek will take N/2.
                // Chanek gets 1 + N/2. Opponent gets 1.
                // This is not quite right. The opponent will play optimally.
                // If N is even, Chanek can take N/2.
                // If N is even, Chanek can take 1.

                // Let's analyze the options for Chanek when N is even:
                // 1. Take N/2 coins.
                //    Chanek gets N/2. Remaining coins: N/2.
                //    Now it's opponent's turn with N/2 coins.
                //    Opponent will try to maximize their score.
                //    If N/2 is odd, opponent takes 1. N/2-1 coins left.
                //    If N/2 is even, opponent takes N/4. N/4 coins left.
                //    This path is good for Chanek if N/2 is large.

                // 2. Take 1 coin.
                //    Chanek gets 1. Remaining coins: N-1 (odd).
                //    Now it's opponent's turn with N-1 coins.
                //    Opponent must take 1 (since N-1 is odd).
                //    Remaining coins: N-2 (even).
                //    Now it's Chanek's turn with N-2 coins.
                //    This path is good for Chanek if N-2 is large and even.

                // The key insight for even N:
                // If N is even, Chanek can take N/2.
                // If N/2 is odd, the opponent will take 1.
                // If N/2 is even, the opponent can take N/4.
                // The opponent will try to leave Chanek with as few coins as possible.

                // Consider the case where N is even.
                // Chanek wants to maximize his score.
                // Option A: Take N/2.
                //   Chanek gets N/2. Remaining N/2. Opponent's turn.
                // Option B: Take 1.
                //   Chanek gets 1. Remaining N-1. Opponent's turn. Opponent must take 1.
                //   Remaining N-2. Chanek's turn.

                // If N is a power of 2 (N = 2^k, k > 0):
                // Chanek takes N/2. N becomes N/2.
                // Opponent takes N/4. N becomes N/4.
                // ...
                // This continues until N becomes 1.
                // Chanek gets N/2 + N/8 + N/32 + ...
                // Opponent gets N/4 + N/16 + N/64 + ...
                // Total Chanek coins = N * (1/2 + 1/8 + 1/32 + ...) = N * ( (1/2) / (1 - 1/4) ) = N * (1/2) / (3/4) = N * (2/3).
                // Total Opponent coins = N * (1/4 + 1/16 + 1/64 + ...) = N * ( (1/4) / (1 - 1/4) ) = N * (1/4) / (3/4) = N * (1/3).
                // So if N is a power of 2, Chanek gets 2/3 N.

                // If N is even but not a power of 2:
                // N = 2^k * M, where M is odd and M > 1.
                // Chanek can take N/2. N becomes N/2 = 2^(k-1) * M.
                // Opponent's turn. N/2 is even if k > 1, odd if k = 1.
                // If k=1, N = 2 * M (M odd, M > 1).
                //   Chanek takes N/2 = M. Chanek gets M. Remaining M.
                //   Opponent's turn with M (odd). Opponent takes 1. Remaining M-1.
                //   Chanek's turn with M-1 (even).
                //   Chanek's total from this path: M + (what he gets from M-1).
                //   Opponent's total from this path: 1 + (what he gets from M-1).
                //   This is better for Chanek than taking 1.
                //   If Chanek takes 1: Chanek gets 1. Remaining N-1 (odd).
                //   Opponent takes 1. Remaining N-2 (even). Chanek's turn.
                //   Chanek's total from this path: 1 + (what he gets from N-2).

                // The optimal strategy for Chanek when N is even:
                // If N is even, Chanek can take N/2.
                // If N/2 is odd, then the opponent must take 1. This leaves N/2 - 1 (even) for Chanek.
                // Chanek gets N/2. Opponent gets 1.
                // If N/2 is even, then the opponent can take N/4. This leaves N/4 (even) for Chanek.
                // Chanek gets N/2. Opponent gets N/4.

                // The crucial observation is that if N is even, Chanek can always take N/2.
                // This is generally better than taking 1, because N/2 is much larger than 1.
                // The only time taking 1 might be better is if taking N/2 sets up the opponent for a huge gain.
                // However, the opponent also wants to maximize their own score.
                // If Chanek takes N/2, the opponent faces N/2 coins.
                // If Chanek takes 1, the opponent faces N-1 coins (odd), so opponent takes 1. Then Chanek faces N-2 coins.

                // Let's consider the game state (N, current_player_score, other_player_score).
                // This is a greedy approach.
                // If N is odd, Chanek must take 1.
                // If N is even:
                //   If N is a power of 2 (N = 2^k):
                //     Chanek takes N/2. Opponent takes N/4. Chanek takes N/8...
                //     Chanek gets 2/3 N.
                //   If N is even but not a power of 2 (N = 2^k * M, M odd > 1):
                //     Chanek takes N/2. N becomes N/2.
                //     Opponent's turn with N/2.
                //     If k=1, N=2M. Chanek takes M. N becomes M (odd).
                //     Opponent takes 1. N becomes M-1 (even).
                //     Chanek's turn with M-1.
                //     In this case, Chanek gets M.
                //     If Chanek took 1 instead: N becomes N-1 (odd).
                //     Opponent takes 1. N becomes N-2 (even).
                //     Chanek's turn with N-2.
                //     M vs 1. M is better.

                // It seems the greedy strategy is:
                // If N is odd, take 1.
                // If N is even, take N/2.
                // Let's test this.
                // N=5: Chanek (odd) takes 1. C=1, N=4. Opponent (even) takes 4/2=2. O=2, N=2. Chanek (even) takes 2/2=1. C=1+1=2, N=1. Opponent (odd) takes 1. O=2+1=3, N=0.
                // Chanek gets 2. This matches example.

                // N=6: Chanek (even) takes 6/2=3. C=3, N=3. Opponent (odd) takes 1. O=1, N=2. Chanek (even) takes 2/2=1. C=3+1=4, N=1. Opponent (odd) takes 1. O=1+1=2, N=0.
                // Chanek gets 4. This matches example.

                // This greedy strategy seems to work for the examples.
                // Let's try to prove it.
                // When it's Chanek's turn with N coins:
                // Case 1: N is odd.
                //   Chanek must take 1. N becomes N-1 (even). Opponent's turn.
                //   Chanek gets 1 + (coins from N-1 when opponent starts).
                // Case 2: N is even.
                //   Option A: Take N/2.
                //     Chanek gets N/2. N becomes N/2. Opponent's turn.
                //     Chanek gets N/2 + (coins from N/2 when opponent starts).
                //   Option B: Take 1.
                //     Chanek gets 1. N becomes N-1 (odd). Opponent's turn.
                //     Opponent must take 1. N becomes N-2 (even). Chanek's turn.
                //     Chanek gets 1 + (coins from N-2 when Chanek starts).

                // Let C(N) be Chanek's score if it's his turn with N coins.
                // Let O(N) be Chanek's score if it's opponent's turn with N coins.
                // C(N) = max(
                //   1 + O(N-1)  (if N is odd, this is the only choice)
                //   N/2 + O(N/2) (if N is even)
                // )
                // O(N) = (total coins taken from N) - C_opponent(N)
                // C_opponent(N) = max(
                //   1 + C(N-1) (if N is odd, opponent takes 1)
                //   N/2 + C(N/2) (if N is even, opponent takes N/2)
                // )
                // This is getting complicated. The problem states "both players will try to maximize the number of coins they have".
                // This means if it's Chanek's turn, he maximizes his score. If it's opponent's turn, opponent maximizes their score.

                // Let's re-evaluate the greedy strategy:
                // If N is odd: Chanek takes 1. N becomes N-1.
                // If N is even:
                //   If N is a power of 2 (N = 2^k):
                //     Chanek takes N/2. N becomes N/2.
                //     Opponent takes N/4. N becomes N/4.
                //     ...
                //     This continues until N=1.
                //     Chanek gets N/2 + N/8 + N/32 + ...
                //     Opponent gets N/4 + N/16 + N/64 + ...
                //     Chanek gets 2/3 N.
                //   If N is even but not a power of 2 (N = 2^k * M, M odd > 1):
                //     Chanek takes N/2. N becomes N/2 = 2^(k-1) * M.
                //     Now it's opponent's turn with N/2.
                //     If k=1, N=2M. Chanek takes M. N becomes M (odd).
                //     Opponent takes 1. N becomes M-1 (even).
                //     Chanek's turn with M-1.
                //     Chanek gets M + (what he gets from M-1).
                //     Opponent gets 1 + (what he gets from M-1).
                //     This is the greedy strategy.

                // Let's consider the alternative for even N: Chanek takes 1.
                // Chanek gets 1. N becomes N-1 (odd).
                // Opponent's turn with N-1. Opponent takes 1. N becomes N-2 (even).
                // Chanek's turn with N-2.
                // Chanek gets 1 + (what he gets from N-2).
                // Opponent gets 1 + (what he gets from N-2).

                // Compare taking N/2 vs taking 1 when N is even.
                // If N is even and not a power of 2 (N = 2^k * M, M odd > 1):
                //   Option 1 (take N/2): Chanek gets N/2. Opponent gets 1 (if k=1) or N/4 (if k>1).
                //   Option 2 (take 1): Chanek gets 1. Opponent gets 1.
                //   The remaining coins are N/2 or N-2.
                //   The key is that if N is even and not a power of 2, taking N/2 leads to a state where the opponent faces N/2.
                //   If N/2 is odd (i.e., N = 2 * M, M odd > 1), then opponent takes 1.
                //   Chanek gets M. Opponent gets 1.
                //   If Chanek took 1 instead: Chanek gets 1. Opponent takes 1.
                //   Chanek gets M vs 1. M > 1, so M is better.
                //   If N/2 is even (i.e., N = 2^k * M, k > 1, M odd > 1), then opponent takes N/4.
                //   Chanek gets N/2. Opponent gets N/4.
                //   If Chanek took 1 instead: Chanek gets 1. Opponent takes 1.
                //   Chanek gets N/2 vs 1. N/2 is much larger than 1.

                // The only tricky case is when N is a power of 2.
                // N = 2^k.
                // Greedy strategy: Chanek takes N/2. N becomes N/2.
                // Opponent takes N/4. N becomes N/4.
                // ...
                // Chanek gets N/2 + N/8 + ... = N * (2/3).
                // Opponent gets N/4 + N/16 + ... = N * (1/3).
                // What if Chanek takes 1?
                // Chanek gets 1. N becomes N-1 (odd).
                // Opponent takes 1. N becomes N-2 (even).
                // Chanek's turn with N-2.
                // This path seems worse for Chanek. He gets 1, and then has to play on N-2.
                // The opponent gets 1, and then has to play on N-2.
                // The total coins taken by Chanek from N-2 will be less than 2/3 * (N-2).
                // So 1 + 2/3 * (N-2) is less than 2/3 * N.
                // Example: N=4.
                // Greedy: Chanek takes 2. C=2, N=2. Opponent takes 1. O=1, N=1. Chanek takes 1. C=2+1=3, N=0.
                // Chanek gets 3. (2/3 * 4 = 2.66, so this is not exactly 2/3 N, because the game ends when N=1).
                // Let's trace N=4:
                // C: N=4. Takes 2. C_score=2. N=2.
                // O: N=2. Takes 1. O_score=1. N=1.
                // C: N=1. Takes 1. C_score=2+1=3. N=0.
                // Chanek gets 3. Opponent gets 1. Total 4.
                // What if Chanek takes 1?
                // C: N=4. Takes 1. C_score=1. N=3.
                // O: N=3. Takes 1. O_score=1. N=2.
                // C: N=2. Takes 1. C_score=1+1=2. N=1.
                // O: N=1. Takes 1. O_score=1+1=2. N=0.
                // Chanek gets 2. Opponent gets 2. Total 4.
                // So for N=4, taking N/2 (2) is better for Chanek (3 vs 2).

                // The greedy strategy seems to be correct.
                // If N is odd, take 1.
                // If N is even:
                //   If N is a power of 2, take N/2.
                //   If N is even but not a power of 2, take N/2.
                // So, if N is even, always take N/2.

                // This simplifies to:
                // If N is odd, take 1.
                // If N is even, take N/2.

                // Let's re-verify the power of 2 case.
                // N = 2^k.
                // Chanek takes N/2. N becomes N/2.
                // Opponent takes N/4. N becomes N/4.
                // ...
                // This continues until N becomes 1.
                // The player whose turn it is when N=1 takes 1.
                // The sequence of coins taken by Chanek: N/2, N/8, N/32, ...
                // The sequence of coins taken by Opponent: N/4, N/16, N/64, ...
                // The last coin (1) is taken by Chanek if k is odd, by Opponent if k is even.
                // Example N=4 (k=2, even):
