#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let i be the number of items taken from the left (0 <= i <= n)
    // Then n-i items are taken from the right
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;
        long long left_items_count = i;
        long long right_items_count = n - i;

        // Energy for items taken from left
        current_energy += prefix_sum[left_items_count] * l;

        // Energy for items taken from right
        current_energy += (prefix_sum[n] - prefix_sum[n - right_items_count]) * r;

        // Add penalties
        if (left_items_count > right_items_count) {
            // More items from left. The last few items must have been from left.
            // The difference is (left_items_count - right_items_count).
            // If this difference is 1, no extra penalty.
            // If this difference is > 1, then (left_items_count - right_items_count - 1) times
            // we took a left item after a left item.
            current_energy += (left_items_count - right_items_count - 1) * Ql;
        } else if (right_items_count > left_items_count) {
            // More items from right. The last few items must have been from right.
            // The difference is (right_items_count - left_items_count).
            // If this difference is 1, no extra penalty.
            // If this difference is > 1, then (right_items_count - left_items_count - 1) times
            // we took a right item after a right item.
            current_energy += (right_items_count - left_items_count - 1) * Qr;
        }
        // If left_items_count == right_items_count, no extra penalty.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

