long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;

    // Find prime factors of q
    std::vector<long long> q_prime_factors;
    long long temp_q = q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            q_prime_factors.push_back(i);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        q_prime_factors.push_back(temp_q);
    }

    // Iterate through each prime factor r of q
    for (long long r : q_prime_factors) {
        long long current_p = p;
        // Divide current_p by r until it's no longer divisible by q
        // Or until current_p is no longer divisible by r
        while (current_p % q == 0) {
            current_p /= r;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

