                last1 = d[i];
            } else if (d[i] > x) {
                // Must be color 2
                if (d[i] < last2) {
                    possible_x = false;
                    break;
                }
                colors[i] = 2;
                last2 = d[i];
            } else { // d[i] == x
                // Can be color 1 or 2. Prefer color 2 if it maintains sorted order.
                // If d[i] (which is x) is put into S1, it must be >= last1.
                // If d[i] (which is x) is put into S2, it must be >= last2.
                // Also, if S1 is non-empty and S2 is non-empty, last1 <= first2.
                // Here, first2 would be x. So last1 <= x.
                // If we put x into S1, last1 becomes x.
                // If we put x into S2, last2 becomes x.

                // Strategy: put 'x' into color 2 if it's valid, otherwise color 1.
                // This means if last2 <= x, we can put it in color 2.
                // If we put it in color 1, it must be that last1 <= x.
                // The critical condition is that last1 (if S1 is non-empty) must be <= first2 (if S2 is non-empty).
                // If we put x into color 1, then last1 becomes x.
                // If we put x into color 2, then last2 becomes x.
                // The overall condition is that the last digit of S1 must be <= the first digit of S2.
                // If we put x into color 1, then any subsequent x must be color 1 or 2.
                // If we put x into color 2, then any subsequent x must be color 2.

                // Let's try a greedy choice for 'x' digits:
                // If d[i] == x, and we can put it in color 2 (i.e., d[i] >= last2),
                // then we put it in color 2. This keeps last1 as small as possible.
                if (d[i] >= last2) {
                    colors[i] = 2;
                    last2 = d[i];
                } else if (d[i] >= last1) {
                    colors[i] = 1;
                    last1 = d[i];
                } else {
                    possible_x = false;
                    break;
                }
            }
        }

        if (possible_x) {
            // Final check: last digit of S1 must be <= first digit of S2.
            // This is implicitly handled by the greedy choice for 'x' digits.
            // If last1 is the last digit of S1, and first2 is the first digit of S2,
            // then last1 <= first2 must hold.
            // Our construction ensures that all digits colored 1 are <= x, and all digits colored 2 are >= x.
            // So, if S1 is non-empty and S2 is non-empty, the last digit of S1 will be <= x,
            // and the first digit of S2 will be >= x. Thus, last1 <= first2 is guaranteed.
            // The only edge case is if last1 was updated by a digit < x, and first2 by a digit > x.
            // But the logic for d[i] == x handles this.
            // If last1 is the maximum digit assigned to color 1, and first2 is the minimum digit assigned to color 2,
            // then last1 <= x and first2 >= x. So last1 <= first2.
            // The only thing to check is if the sequence of 1s is sorted and sequence of 2s is sorted.
            // This is handled by `d[i] < last1` and `d[i] < last2` checks.

            for (int i = 0; i < n; ++i) {
                std::cout << colors[i];
            }
            std::cout << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

