#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char u = s[i];
        char v = s[i+1];
        adj[u].insert(v);
        adj[v].insert(u);
        used_in_s.insert(u);
        used_in_s.insert(v);
    }
    if (s.length() == 1) { // Handle single character password
        used_in_s.insert(s[0]);
    }

    bool possible = true;
    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout_str = "";
    std::set<char> visited;
    char start_node = '\0';

    // Find a starting node (degree 1 or isolated)
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj.count(c) && adj[c].size() == 1) {
            start_node = c;
            break;
        }
    }
    if (start_node == '\0' && !used_in_s.empty()) { // All nodes in s have degree 2, or s has one char
        if (used_in_s.size() > 1) { // If s has multiple chars, and all have degree 2, it's a cycle.
                                    // A cycle cannot be laid out as a single path.
            std::cout << "NO\n";
            return;
        } else { // s has only one character, e.g., "a"
            start_node = *used_in_s.begin();
        }
    } else if (start_node == '\0' && used_in_s.empty()) { // s is empty or length 1, but this case is handled by s.length() == 1
                                                          // If s.length() == 1, used_in_s is not empty.
                                                          // This branch should not be reached for valid inputs.
        start_node = 'a'; // Default to 'a' if no characters in s
    }


    if (start_node != '\0') {
        char current = start_node;
        char prev = '\0';

        while (current != '\0' && visited.find(current) == visited.end()) {
            layout_str += current;
            visited.insert(current);

            char next_node = '\0';
            if (adj.count(current)) {
                for (char neighbor : adj[current]) {
                    if (neighbor != prev) {
                        next_node = neighbor;
                        break;
                    }
                }
            }
            prev = current;
            current = next_node;
        }
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout_str += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long sum_arithmetic_series(long long n) {
    if (n <= 0) {
        return 0;
    }
    long long MOD = 1000000007;
    long long term1 = n % MOD;
    long long term2 = (n + 1) % MOD;
    long long sum = (term1 * term2) % MOD;
    // Multiply by modular inverse of 2
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 8) / 2 = 500000004
    long long inv2 = 500000004;
    sum = (sum * inv2) % MOD;
    return sum;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate Sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    long long sum_r = sum_arithmetic_series(b - 1);

    // Calculate Sum_{k=1 to a} (k * b + 1)
    // This is b * Sum_{k=1 to a} k + Sum_{k=1 to a} 1
    // = b * (a * (a+1) / 2) + a
    long long sum_k_b_plus_1;
    long long sum_k = sum_arithmetic_series(a); // a * (a+1) / 2

    long long term_b_sum_k = (b % MOD * sum_k) % MOD;
    long long term_a = a % MOD;

    sum_k_b_plus_1 = (term_b_sum_k + term_a) % MOD;

    // Total sum = (Sum_{k=1 to a} (k * b + 1)) * (Sum_{r=1 to b-1} r)
    long long total_sum = (sum_k_b_plus_1 * sum_r) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
