int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int c_idx = 0; c_idx < 26; ++c_idx) { // Iterate through possible first characters t[0]
        const std::vector<int>& k_candidates = char_indices[c_idx];
        int num_k_candidates = k_candidates.size();

        if (num_k_candidates == 0) {
            continue; // No k values result in this t[0]
        }
        if (num_k_candidates == 1) {
            total_win_prob += 1.0; // If only one k, Vasya wins for sure
            continue;
        }

        // If num_k_candidates > 1, Vasya needs to pick a position p
        // to maximize the probability of winning for this specific t[0].
        double max_win_prob_for_char = 0.0;

        // Iterate through all possible positions p (1 to L-1)
        for (int p = 1; p < L; ++p) {
            std::vector<std::vector<int>> groups;
            std::vector<bool> visited(num_k_candidates, false);

            for (int i = 0; i < num_k_candidates; ++i) {
                if (visited[i]) {
                    continue;
                }
                std::vector<int> current_group;
                current_group.push_back(k_candidates[i]);
                visited[i] = true;

                char char_at_p = s[(k_candidates[i] + p) % L];

                for (int j = i + 1; j < num_k_candidates; ++j) {
                    if (!visited[j] && s[(k_candidates[j] + p) % L] == char_at_p) {
                        current_group.push_back(k_candidates[j]);
                        visited[j] = true;
                    }
                }
                groups.push_back(current_group);
            }

            // Calculate win probability for this p
            double current_p_win_prob = 0.0;
            for (const auto& group : groups) {
                if (group.size() == 1) {
                    current_p_win_prob += 1.0;
                }
            }
            max_win_prob_for_char = std::max(max_win_prob_for_char, current_p_win_prob / num_k_candidates);
        }
        total_win_prob += max_win_prob_for_char * num_k_candidates;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
