#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    int k = static_cast<int>(std::sqrt(n));
    if (k * k < n) {
        k++;
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int block_start = (n - 1) / k * k;
        while (block_start > i) {
            block_start -= k;
        }

        int current_block_idx = (i - block_start);
        int value = block_start + k - current_block_idx;

        if (value > n) { // This element would be outside the permutation range
            // Adjust for the last potentially incomplete block
            // The last block might have fewer than k elements.
            // We need to map i to the correct value within its block.
            // Example: n=7, k=3. Blocks: [1,2,3], [4,5,6], [7].
            // i=0 -> block_start=0, current_block_idx=0, value=0+3-0=3
            // i=1 -> block_start=0, current_block_idx=1, value=0+3-1=2
            // i=2 -> block_start=0, current_block_idx=2, value=0+3-2=1
            // i=3 -> block_start=3, current_block_idx=0, value=3+3-0=6
            // i=4 -> block_start=3, current_block_idx=1, value=3+3-1=5
            // i=5 -> block_start=3, current_block_idx=2, value=3+3-2=4
            // i=6 -> block_start=6, current_block_idx=0, value=6+3-0=9 (too large)
            // For i=6, block_start=6. The block is [7].
            // The values in the last block are n, n-1, ..., block_start+1.
            // We want to map i=6 to 7.
            // The values in the block are (block_start+1) to n.
            // The elements in the block are i from block_start to n-1.
            // The values should be assigned in decreasing order.
            // For i=block_start, value should be n.
            // For i=block_start+1, value should be n-1.
            // For i=i, value should be n - (i - block_start).
            value = n - (i - block_start);
        }
        p[i] = value;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

