#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize current state for each bit
    // For each bit j (0-9):
    // state_0[j] = result if input bit j is 0
    // state_1[j] = result if input bit j is 1
    // Initially, if input bit j is 0, result is 0. If input bit j is 1, result is 1.
    std::vector<int> state_0(10); // Stores the final value of bit j if initial bit j was 0
    std::vector<int> state_1(10); // Stores the final value of bit j if initial bit j was 1
    for (int j = 0; j < 10; ++j) {
        state_0[j] = 0;
        state_1[j] = 1;
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int j = 0; j < 10; ++j) {
            int bit_val = (val >> j) & 1; // j-th bit of the constant 'val'

            if (op_char == '&') {
                state_0[j] &= bit_val;
                state_1[j] &= bit_val;
            } else if (op_char == '|') {
                state_0[j] |= bit_val;
                state_1[j] |= bit_val;
            } else { // op_char == '^'
                state_0[j] ^= bit_val;
                state_1[j] ^= bit_val;
            }
        }
    }

    // Now, for each bit j, we know (state_0[j], state_1[j])
    // This pair determines the transformation for bit j:
    // (0,0) -> bit j always becomes 0
    // (0,1) -> bit j remains unchanged (x_j -> x_j)
    // (1,0) -> bit j becomes inverted (x_j -> !x_j)
    // (1,1) -> bit j always becomes 1

    // We need to find a minimal sequence of operations (&, |, ^)
    // that achieves these transformations for all bits.
    // We can use at most 3 operations: one &, one |, one ^.
    // Let's try to construct the constants for these three operations.

    int and_const = 1023; // Initial value for AND operation (all bits 1)
    int or_const = 0;     // Initial value for OR operation (all bits 0)
    int xor_const = 0;    // Initial value for XOR operation (all bits 0)

    for (int j = 0; j < 10; ++j) {
        if (state_0[j] == 0 && state_1[j] == 0) {
            // Bit j always becomes 0.
            // This can be achieved by ANDing with 0.
            and_const &= ~(1 << j); // Set j-th bit of and_const to 0
        } else if (state_0[j] == 0 && state_1[j] == 1) {
            // Bit j remains unchanged.
            // This is achieved by ANDing with 1, ORing with 0, XORing with 0.
            // and_const already has 1 at j-th bit (default)
            // or_const already has 0 at j-th bit (default)
            // xor_const already has 0 at j-th bit (default)
        } else if (state_0[j] == 1 && state_1[j] == 0) {
            // Bit j becomes inverted.
            // This is achieved by XORing with 1.
            xor_const |= (1 << j); // Set j-th bit of xor_const to 1
        } else { // state_0[j] == 1 && state_1[j] == 1
            // Bit j always becomes 1.
            // This can be achieved by ORing with 1.
            or_const |= (1 << j); // Set j-th bit of or_const to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (or_const != 0) {
        result_ops.push_back({'|', or_const});
    }
    if (and_const != 1023) { // If and_const is 1023, it means no bit was forced to 0, so no & op needed
        result_ops.push_back({'&', and_const});
    }
    if (xor_const != 0) {
        result_ops.push_back({'^', xor_const});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

