int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use for the alternating part to generate k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between left and right pointers.
    // The sequence will look like: 1, k+1, 2, k, 3, k-1, ...
    // Differences generated: |1-(k+1)|=k, |(k+1)-2|=k-1, |2-k|=k-2, ...
    // This continues until left and right pointers cross or meet.
    bool use_left = true;
    while (left <= right) {
        if (use_left) {
            std::cout << left << " ";
            left++;
        } else {
            std::cout << right << " ";
            right--;
        }
        use_left = !use_left;
    }

    // After generating k distinct differences, the remaining numbers
    // (from k+2 to n) should be appended in increasing order to
    // ensure only one new difference (which is 1) is introduced,
    // or no new differences if k=1 and we already have 1.
    // The last number printed from the alternating sequence is either
    // (k+1)/2 or (k+1)/2 + 1, or similar.
    // The next number to print is k+2. The difference will be 1.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << " ";
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> p(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        p[i] = (a[i] == 1 ? 1 : -1);
    }

    // Calculate prefix sums for the left side (jars 0 to n-1)
    // and suffix sums for the right side (jars n to 2n-1)
    // The sums are relative to the initial state of the left/right segment.

    // Left side: jars 0 to n-1
    // `left_balance[k]` stores the balance of jars 0 to k-1 (k jars removed from left)
    // `left_balance[0]` is 0 (no jars removed)
    // `left_balance[k]` for k > 0 is sum(p[0]...p[k-1])
    std::map<int, int> left_balance_to_count;
    left_balance_to_count[0] = 0; // 0 jars removed, balance 0
    int current_balance_left = 0;
    for (int i = 0; i < n; ++i) {
        current_balance_left += p[i];
        if (left_balance_to_count.find(current_balance_left) == left_balance_to_count.end()) {
            left_balance_to_count[current_balance_left] = i + 1;
        }
    }

    // Right side: jars n to 2n-1
    // `right_balance[k]` stores the balance of jars 2n-1 down to 2n-k (k jars removed from right)
    // `right_balance[0]` is 0 (no jars removed)
    // `right_balance[k]` for k > 0 is sum(p[2n-1]...p[2n-k])
    std::map<int, int> right_balance_to_count;
    right_balance_to_count[0] = 0; // 0 jars removed, balance 0
    int current_balance_right = 0;
    for (int i = 2 * n - 1; i >= n; --i) {
        current_balance_right += p[i];
        if (right_balance_to_count.find(current_balance_right) == right_balance_to_count.end()) {
            right_balance_to_count[current_balance_right] = (2 * n - 1) - i + 1;
        }
    }

    int min_removed = 2 * n; // Max possible jars removed

    // Iterate through all possible balances from the left side
    // For each `left_bal` (balance of jars removed from left)
    // and `left_count` (number of jars removed from left to achieve `left_bal`)
    // we need to find a `right_bal` such that `left_bal + right_bal = initial_total_balance`.
    // The `initial_total_balance` is the sum of all jars from 0 to 2n-1.
    // However, the problem is about the remaining jars.
    // Let `B_total` be the initial balance of all $2n$ jars.
    // Let `B_left_removed` be the balance of jars removed from the left.
    // Let `B_right_removed` be the balance of jars removed from the right.
    // We want the balance of remaining jars to be 0.
    // `B_remaining = B_total - B_left_removed - B_right_removed = 0`
    // So, `B_left_removed + B_right_removed = B_total`.

    int initial_total_balance = 0;
    for (int val : p) {
        initial_total_balance += val;
    }

    for (auto const& [left_bal, left_count] : left_balance_to_count) {
        int required_right_bal = initial_total_balance - left_bal;
        if (right_balance_to_count.count(required_right_bal)) {
            int right_count = right_balance_to_count[required_right_bal];
            min_removed = std::min(min_removed, left_count + right_count);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

