    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L[i]: minimum steps for a[i] to become 0 due to left propagation
    // L[i] = 0 if a[i] == 0
    // L[i] = L[i-1] + 1 if a[i] == 1 and a[i-1] == 0
    // L[i] = 0 if a[i] == 1 and a[i-1] == 1 (this 1 is stable from left)
    // This is equivalent to: L[i] = (a[i] == 1 && a[i-1] == 0) ? L[i-1] + 1 : 0;
    // But we need to handle the case where a[i] is already 0.
    // A simpler way: L[i] is the length of the alternating 1010... sequence ending at i, if a[i]=1.
    // If a[i]=0, L[i]=0. If a[i]=1, and a[i-1]=0, then L[i]=L[i-1]+1. If a[i]=1 and a[i-1]=1, L[i]=0.
    // This is not quite right. L[i] should be the number of steps for a[i] to become 0 if it's part of a 1010... pattern.
    // Let's redefine L[i] as the length of the alternating sequence ending at i, if a[i] is 1.
    // If a[i] is 0, L[i] is 0.
    // If a[i] is 1:
    //   If a[i-1] is 0, then L[i] = L[i-1] + 1.
    //   If a[i-1] is 1, then L[i] = 1. (This 1 is stable from left)
    // This is still not quite right. L[i] should be the number of steps for a[i] to become 0.
    // If a[i] is 0, it's already 0, so 0 steps.
    // If a[i] is 1:
    //   If a[i-1] is 1, then a[i] is stable from left, so it won't become 0 from left.
    //   If a[i-1] is 0, then a[i] can become 0 from left. The number of steps is L[i-1]+1.
    // Let's use the definition from the problem analysis:
    // L[i] = 0 if a[i] == 0
    // L[i] = L[i-1] + 1 if a[i] == 1 and a[i-1] == 0
    // L[i] = 0 if a[i] == 1 and a[i-1] == 1
    // This is for the length of the alternating sequence of 1s and 0s.
    // The number of steps for a[i] to become 0 is ceil(L[i]/2).

    // L[i] stores the length of the alternating 1010... sequence ending at i, if a[i]=1.
    // If a[i]=0, L[i]=0.
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            L[i] = 0;
        } else { // a[i] == 1
            if (a[i-1] == 0) {
                L[i] = L[i-1] + 1;
            } else { // a[i-1] == 1
                L[i] = 1;
            }
        }
    }

    // R[i] stores the length of the alternating ...0101 sequence ending at i, if a[i]=1.
    // If a[i]=0, R[i]=0.
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            R[i] = 0;
        } else { // a[i] == 1
            if (a[i+1] == 0) {
                R[i] = R[i+1] + 1;
            } else { // a[i+1] == 1
                R[i] = 1;
            }
        }
    }

    int max_steps = 0;
    std::vector<int> b = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 1) {
            if (L[i] == 0 && R[i] == 0) { // a[i]=1, a[i-1]=1, a[i+1]=1
                // This 1 is stable, no change.
            } else if (L[i] == 0) { // a[i]=1, a[i-1]=1, a[i+1]=0 (or end of sequence)
                // This 1 is stable from left, but can be changed from right.
                // R[i] is length of 1010... sequence starting at i.
                // Steps to become 0 is ceil(R[i]/2).
                int steps = (R[i] + 1) / 2;
                max_steps = std::max(max_steps, steps);
                if (R[i] % 2 == 1) { // Odd length, a[i] becomes 0
                    b[i] = 0;
                }
            } else if (R[i] == 0) { // a[i]=1, a[i-1]=0, a[i+1]=1 (or start of sequence)
                // This 1 is stable from right, but can be changed from left.
                // L[i] is length of ...0101 sequence ending at i.
                // Steps to become 0 is ceil(L[i]/2).
                int steps = (L[i] + 1) / 2;
                max_steps = std::max(max_steps, steps);
                if (L[i] % 2 == 1) { // Odd length, a[i] becomes 0
                    b[i] = 0;
                }
            } else { // a[i]=1, a[i-1]=0, a[i+1]=0
                // This 1 is part of a 010 pattern. It will become 0.
                // Steps to become 0 is min(ceil(L[i]/2), ceil(R[i]/2)).
                // Since L[i] and R[i] are lengths of alternating sequences starting/ending at a[i]=1,
                // and a[i-1]=0, a[i+1]=0, it means L[i] and R[i] are both 1.
                // So steps = 1.
                // This is actually simpler: if a[i-1]=0 and a[i+1]=0, then a[i] becomes 0 in 1 step.
                // This is covered by the general case:
                // If a[i-1]=0, a[i]=1, a[i+1]=0, then b[i]=median(0,1,0)=0.
                // This happens in 1 step.
                // The max_steps calculation for L[i] and R[i] already handles this.
                // If L[i] is 1, steps = 1. If R[i] is 1, steps = 1.
                // So max_steps will be at least 1.
                // And b[i] will be 0.
                int steps_L = (L[i] + 1) / 2;
                int steps_R = (R[i] + 1) / 2;
                max_steps = std::max(max_steps, std::min(steps_L, steps_R));
                b[i] = 0; // This 1 will definitely become 0
            }
        }
    }

    std::cout << max_steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
