    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        bool possible = true;
        long long prev_val = 0; // This is the minimum possible value for b_i

        for (int i = 0; i < n; ++i) {
