#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9
// and y can accumulate many such values.
// x is an index, so it fits in int.

// Memoization table for results:
// dp[x][0] stores the final y value if starting at x and the next step is 'add a[x]'
// dp[x][1] stores the final y value if starting at x and the next step is 'subtract a[x]'
// We also need to store if it terminates or not.
// A pair {y_value, terminates_flag} could work, or use a special value like -1 for non-termination.
// Let's use -1 for non-termination, and actual y value otherwise.
// dp[x][0] = result of (x + a[x], y + a[x]) then (x + a[x] - a[x+a[x]], y + a[x] + a[x+a[x]])
// dp[x][1] = result of (x - a[x], y + a[x]) then (x - a[x] + a[x-a[x]], y + a[x] + a[x-a[x]])
// The problem states: "The program increases both x and y by a value equal to a_x simultaneously."
// This is the first step. So we always start with the 'add' operation.
// The state should be (current_x, current_y, last_op_was_add).
// Or, more simply, (current_x, current_y, is_add_step).

// Let's define a function `solve(current_x, current_y, is_add_step)`
// This is a recursive function with memoization.
// The `current_y` is not part of the state for memoization because `y` is cumulative.
// The `y` value we are interested in is the *additional* `y` accumulated from `current_x` onwards.
// So, `dp[x][is_add_step]` will store the *additional* `y` accumulated from `x` onwards.
// If it doesn't terminate, we can store a special value like -2 (since y is always positive).

// dp[x][0] stores the additional y if we are at index x and the next operation is x = x + a[x]
// dp[x][1] stores the additional y if we are at index x and the next operation is x = x - a[x]
// visited[x][0] and visited[x][1] to detect cycles.

std::vector<long long> a_values;
std::vector<std::vector<long long>> dp;
std::vector<std::vector<bool>> visited;
int N;

// Function to calculate the additional y from a given state (x, is_add_step)
// Returns -1 if non-terminating, otherwise the additional y value.
long long calculate_y(int x, bool is_add_step) {
    // Base cases for termination
    if (x <= 0 || x > N) {
        return 0; // Program terminates, no further y accumulated
    }

    // Check for cycles
    if (visited[x][is_add_step]) {
        return -1; // Cycle detected, non-terminating
    }

    // Check memoization table
    if (dp[x][is_add_step] != 0) { // 0 means not computed yet, or 0 additional y
                                   // We need a distinct value for 'not computed'
                                   // Let's use a sentinel value like -2 for 'not computed'
        return dp[x][is_add_step];
    }

    // Mark as visited to detect cycles
    visited[x][is_add_step] = true;

    long long current_a_val = a_values[x];
    long long next_y_add;
    int next_x;

    if (is_add_step) { // Current step is x = x + a[x], y = y + a[x]
        next_x = x + current_a_val;
        next_y_add = current_a_val;
        // After this, the next step is x = x - a[x_new], y = y + a[x_new]
        // So, we call calculate_y with (next_x, false)
        long long res = calculate_y(next_x, false);
        if (res == -1) { // Non-terminating
            dp[x][is_add_step] = -1;
        } else {
            dp[x][is_add_step] = next_y_add + res;
        }
    } else { // Current step is x = x - a[x], y = y + a[x]
        next_x = x - current_a_val;
        next_y_add = current_a_val;
        // After this, the next step is x = x + a[x_new], y = y + a[x_new]
        // So, we call calculate_y with (next_x, true)
        long long res = calculate_y(next_x, true);
        if (res == -1) { // Non-terminating
            dp[x][is_add_step] = -1;
        } else {
            dp[x][is_add_step] = next_y_add + res;
        }
    }

    // Unmark visited (important for multiple runs with different a[1])
    // No, this is not needed. The DP table and visited array are reset for each a[1] run.
    // Or, if we want to optimize, we can clear visited for each run, but keep DP.
    // The problem states "for each i (1 <= i <= n - 1) we run the program on the sequence i, a_2, a_3, ..., a_n".
    // This means a[1] changes, so the entire DP table needs to be recomputed or cleared.
    // However, a[2]...a[N] remain constant.
    // The DP state (x, is_add_step) depends on a[x]. If a[1] changes, then a[1] changes.
    // But if x != 1, a[x] is constant.
    // So, dp[x][is_add_step] for x > 1 can be reused.
    // Only dp[1][true] needs to be recomputed.
    // The visited array must be cleared for each run.

    visited[x][is_add_step] = false; // Backtrack for current path, allowing other paths to use this node.
                                     // This is crucial if we want to reuse DP values for x > 1.
                                     // If we clear visited for each run, this is not needed.
                                     // Let's clear visited for each run for simplicity.

    return dp[x][is_add_step];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    a_values.resize(N + 1);
    // a_values[0] is unused, a_values[1] is set by the loop
    // a_values[2] to a_values[N] are read from input
    for (int i = 2; i <= N; ++i) {
        std::cin >> a_values[i];
    }

    // Initialize dp table with a sentinel value indicating 'not computed'
    // -2 is a good choice since y values are non-negative.
    // dp[x][0] for x+a[x] step, dp[x][1] for x-a[x] step
    dp.resize(N + 1, std::vector<long long>(2, -2));

    // For each starting value of a[1]
    for (int i = 1; i < N; ++i) {
        a_values[1] = i;

        // Clear visited array for each run
        visited.assign(N + 1, std::vector<bool>(2, false));

        // The program starts with x=1, y=0.
        // The first operation is x = x + a[x], y = y + a[x].
        // So we call calculate_y(1, true)
        long long initial_a1_val = a_values[1];
        long long result = calculate_y(1, true);

        if (result == -1) {
            std::cout << -1 << "\n";
        } else {
            // The total y is initial_a1_val + result
            // because calculate_y(1, true) returns the sum of a_values from the second step onwards.
            // The first a_values[1] is added to y before the recursive call.
            std::cout << initial_a1_val + result << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Precompute positions of '1's
    std::vector<int> ones_pos;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            ones_pos.push_back(i);
        }
    }

    // Iterate through all possible starting positions of '1's
    for (int i = 0; i < ones_pos.size(); ++i) {
        int l_one = ones_pos[i]; // Current '1' is at index l_one
        long long current_val = 0;

        // Iterate through possible ending positions for substrings starting with this '1'
        // The maximum length we need to check is limited by MAX_LEN_CHECK
        // because beyond that, length will be much smaller than value.
        // MAX_LEN_CHECK is around 60 for long long, but we can be more conservative.
        // For a string of length L, the value is at most 2^L - 1.
        // We are looking for length = value.
        // If length > 60, then 2^length - 1 is much larger than length.
        // So we only need to check substrings up to length around 60.
        // The actual limit is when 2^k - 1 >= N (max string length).
        // log2(N) is around log2(2e5) which is about 17.6.
        // So we only need to check substrings of length up to ~18-20.
        // Let's use a slightly larger bound, say 20.
        // The maximum value of a 20-bit number is 2^20 - 1 = 1048575.
        // If the length is 20, the value can be up to 1048575.
        // If the length is 18, the value can be up to 2^18 - 1 = 262143.
        // The maximum length of s is 2e5.
        // If a substring has length L, its value is at most 2^L - 1.
        // We need L = value.
        // If L > 18, then 2^L - 1 > 2^18 - 1 = 262143.
        // But the maximum possible length of a substring is N = 2e5.
        // So if L > 18, then value > 262143, which is greater than N.
        // Thus, we only need to check substrings of length up to 18.
        // Let's use a safe upper bound like 20 or 22 to be absolutely sure.
        // The maximum length of a substring is N.
        // If length L = value, then L <= N.
        // Also, value <= 2^L - 1.
        // So L <= 2^L - 1. This is always true for L >= 1.
        // The critical part is that if L is large, value becomes much larger than L.
        // For example, if L=20, value can be up to 2^20-1.
        // If L=18, value can be up to 2^18-1 = 262143.
        // Since N <= 2e5, any substring with length > 18 cannot have its value equal to its length.
        // Because if length > 18, then value >= 2^18 = 262144, which is > N.
        // So we only need to check substrings of length up to 18.
        // The loop for `r` will go from `l_one` up to `min(n-1, l_one + 18 - 1)`.
        // This means `r - l_one + 1` (length) will be at most 18.
        // Let's use a slightly larger constant, say 22, to be safe and avoid off-by-one issues with log.
        // log2(2e5) is approx 17.6. So 18 is the minimum length where 2^L > 2e5.
        // So we check lengths up to 18.
        // The loop for `r` should go up to `l_one + 18 - 1`.
        // The maximum length of a substring is `n`.
        // The maximum value of `r` is `n-1`.
        // So `r` goes from `l_one` to `min(n-1, l_one + 18 - 1)`.
        // Let's use a constant `MAX_BITS_TO_CHECK = 20` to be safe.
        // This means `r - l_one + 1` (length) will be at most `MAX_BITS_TO_CHECK`.
        // So `r` goes from `l_one` to `min(n-1, l_one + MAX_BITS_TO_CHECK - 1)`.
        // The maximum value of `current_val` will be `2^MAX_BITS_TO_CHECK - 1`.
        // If `MAX_BITS_TO_CHECK = 20`, `current_val` can be up to `10^6`.
        // If `MAX_BITS_TO_CHECK = 18`, `current_val` can be up to `262143`.
        // Since `n <= 2e5`, `current_val` can exceed `n`.
        // We need `current_val == length`.
        // If `current_val > n`, then it cannot be equal to `length` because `length <= n`.
        // So we can stop early if `current_val > n`.

        for (int r = l_one; r < n; ++r) {
            int len = r - l_one + 1;

            // If length exceeds a certain threshold, the value will be too large.
            // For N=2e5, if length > 18, then value >= 2^18 = 262144 > N.
            // So length cannot equal value.
            if (len > 18) { // A safe upper bound for length to check
                break;
            }

            current_val = (current_val << 1) | (s[r] - '0');

            // If current_val exceeds N, it can't be equal to length (which is <= N).
            // Also, if current_val becomes 0 (e.g., "000"), it's not a good substring
            // because it starts with '1' (l_one).
            // The only case where current_val can be 0 is if the substring is "0",
            // but we are iterating from '1's.
            // So current_val will always be >= 1.
            if (current_val > n) { // Optimization: if value exceeds max possible length, stop.
                break;
            }

            if (current_val == len) {
                good_substrings_count++;
            }
        }
    }

    // Handle substrings starting with '0's
    // These substrings must have length = value.
    // Since they start with '0', their value is the same as the substring starting at the first '1'
    // or 0 if all characters are '0'.
    // Example: "00101", f("00101") = 5. Length = 5. Good.
    // The value is determined by the '1's.
    // The length is `r - l + 1`.
    // Let `l_zero` be the starting index of a substring.
    // Let `l_one` be the index of the first '1' in `s[l_zero...r]`.
    // If no '1' exists, `s[l_zero...r]` consists only of '0's.
    // In this case, `f(s[l_zero...r]) = 0`.
    // For `f(s[l_zero...r]) = 0` to be good, `r - l_zero + 1 = 0`.
    // This is impossible since length must be at least 1.
    // So, substrings consisting only of '0's are never good.

    // Therefore, any good substring starting with '0' must contain at least one '1'.
    // Let `s[l...r]` be a good substring.
    // If `s[l] == '0'`, then `f(s[l...r])` is the same as `f(s[first_one_idx...r])`
    // where `first_one_idx` is the index of the first '1' in `s[l...r]`.
    // Let `k = first_one_idx`.
    // The length of `s[l...r]` is `r - l + 1`.
    // The value `f(s[l...r])` is `f(s[k...r])`.
    // We need `r - l + 1 = f(s[k...r])`.
    // This means `r - l + 1 = r - k + 1`.
    // This implies `l = k`.
    // So, a good substring `s[l...r]` starting with '0' implies `l` must be the index of the first '1' in `s[l...r]`.
    // This is a contradiction. If `s[l] == '0'`, then `l` cannot be the index of the first '1'.
    // The only way `l = k` is if `s[l]` is '1'.
    // This means that if a substring `s[l...r]` is good, it must start with '1'.
    // Wait, this logic is flawed.
    // Example: s = "0110", substring "011" (l=0, r=2).
    // Length = 3. f("011") = 3. This is good.
    // Here, l=0, first_one_idx=1. So l != first_one_idx.
    // The condition is `r - l + 1 = f(s_l \dots s_r)`.
    // Let `k` be the index of the first '1' in `s[l...r]`.
    // Then `f(s[l...r]) = f(s[k...r])`.
    // So we need `r - l + 1 = f(s[k...r])`.
    // We already counted substrings `s[k...r]` where `s[k]` is '1' and `r - k + 1 = f(s[k...r])`.
    // Let `val_kr = f(s[k...r])`.
    // We need `r - l + 1 = val_kr`.
    // This means `l = r + 1 - val_kr`.
    // For this to be a valid starting position for a substring `s[l...r]` that starts with '0's,
    // `l` must be less than `k`.
    // Also, `s[l...k-1]` must all be '0's.
    // The number of leading zeros is `k - l`.
    // So, for each `s[k...r]` that we found to be good (i.e., `r - k + 1 = val_kr`),
    // we need to check how many leading zeros can be prepended.
    // The length of `s[k...r]` is `val_kr`.
    // If we prepend `p` zeros, the new substring is `s[k-p...r]`.
    // Its length is `val_kr + p`.
    // Its value is still `val_kr`.
    // For it to be good, `val_kr + p = val_kr`, which implies `p = 0`.
    // This means only substrings starting with '1' can be good.
    // This is the correct logic. My previous example "011" was wrong.
    // f(011) = 3. Length of "011" is 3. So "011" is good.
    // Here, l=0, r=2. k=1.
    // f(s[k...r]) = f(s[1...2]) = f("11") = 3.
    // Length of s[l...r] = r - l + 1 = 2 - 0 + 1 = 3.
    // So 3 = 3. This is good.
    // The number of leading zeros is `k - l = 1 - 0 = 1`.
    // The length of `s[k...r]` is `r - k + 1 = 2 - 1 + 1 = 2`.
    // The value `f(s[k...r])` is `f("11") = 3`.
    // So `s[k...r]` itself is NOT good because `2 != 3`.
    // This means my initial loop only counts substrings `s[k...r]` where `s[k]` is '1' AND `r - k + 1 = f(s[k...r])`.
    // The example "011" is good, but "11" is not.
    // So the initial loop does not count "011".

    // Let's re-evaluate.
    // For each substring `s[l...r]`:
    // 1. Find `k`, the index of the first '1' in `s[l...r]`. If no '1', `k = r+1`.
    // 2. Calculate `val = f(s[k...r])`. If `k = r+1`, `val = 0`.
    // 3. Check if `r - l + 1 == val`.

    // We can iterate over all possible `r` (end index).
    // For each `r`, iterate `l` backwards from `r` to `0`.
    // This is O(N^2), too slow. N=2e5.

    // Let's fix `r`.
    // We need to find `l` such that `r - l + 1 = f(s[k...r])`.
    // `k` is the index of the first '1' in `s[l...r]`.
    // This means `s[l...k-1]` are all '0's, and `s[k]` is '1'.
    // If `s[r]` is '0', then `f(s[k...r])` is `f(s[k...r-1]) / 2`.
    // If `s[r]` is '1', then `f(s[k...r])` is `f(s[k...r-1]) / 2 + 2^(r-k)`.

    // Let's iterate `r` from `0` to `n-1`.
    // For each `r`, we want to find `l` such that `s[l...r]` is good.
    // We need to find `k` (first '1' in `s[l...r]`).
    // `val = f(s[k...r])`.
    // `len = r - l + 1`.
    // We need `len = val`.
    // This means `l = r + 1 - val`.
    // For a given `r`, `val` depends on `k`.
    // `k` depends on `l`.
    // This is a circular dependency.

    // Let's fix `k` (the index of the first '1' in the substring).
    // This means `s[k]` is '1'.
    // We iterate `k` from `0` to `n-1`. If `s[k]` is '0', we skip it.
    // For each `k` where `s[k] == '1'`:
    //   We consider substrings `s[l...r]` where `l <= k <= r` and `s[l...k-1]` are all '0's.
    //   The value `val = f(s[k...r])`.
    //   The length `len = r - l + 1`.
    //   We need `r - l + 1 = val`.
    //   This implies `l = r + 1 - val`.
    //   We also need `l <= k`.
    //   And `s[l...k-1]` must be all '0's.
    //   Let `prev_one_idx` be the index of the '1' immediately before `k`. If no such '1', `prev_one_idx = -1`.
    //   Then `s[l...k-1]` are all '0's if and only if `l > prev_one_idx`.
    //   So we need `prev_one_idx < l <= k`.
    //   Substituting `l = r + 1 - val`:
    //   `prev_one_idx < r + 1 - val <= k`.

    // Let's iterate `k` (index of the first '1' in the substring) from `0` to `n-1`.
    // If `s[k] == '0'`, continue.
    // `prev_one_idx` is the index of the '1' before `k`.
    // We can precompute `prev_one[i]` for all `i`.
    std::vector<int> prev_one(n);
    int last_one = -1;
    for (int i = 0; i < n; ++i) {
        prev_one[i] = last_one;
        if (s[i] == '1') {
            last_one = i;
        }
    }

    for (int k = 0; k < n; ++k) {
        if (s[k] == '0') continue; // k must be the index of a '1'

        long long current_val = 0;
        // Iterate `r` (end index) starting from `k`.
        // The length of `s[k...r]` is `r - k + 1`.
        // As before, we only need to check `r` such that `r - k + 1` is small (e.g., up to 18-20).
        for (int r = k; r < n; ++r) {
            int len_kr = r - k + 1; // Length of substring s[k...r]

            if (len_kr > 18) { // Optimization: if length of s[k...r] is too large, value will exceed N.
                break;
            }

            current_val = (current_val << 1) | (s[r] - '0');

            // If current_val exceeds N, it can't be equal to `r - l + 1` (which is <= N).
            if (current_val > n) {
                break;
            }

            // Now we have `k`, `r`, and `val = current_val`.
            // We need to find `l` such that:
            // 1. `l <= k`
            // 2. `s[l...k-1]` are all '0's (i.e., `l > prev_one[k]`)
            // 3. `r - l + 1 = val` => `l = r + 1 - val`

            // Check if `l = r + 1 - val` satisfies the conditions:
            int l = r + 1 - static_cast<int>(current_val);

            if (l <= k && l > prev_one[k]) {
                // This `l` is a valid starting position for a good substring `s[l...r]`.
                good_substrings_count++;
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

