    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i goes to the dentist

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply reduction from current_v_cry
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply reduction from children who left earlier in this step
            children[j].p -= total_d_cry_from_leaving;

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_from_leaving += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // All f(a_i, a_j) = a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: One element in S1, rest in S2. Or vice versa.
    // Let a[0] be in S1, and a[1], ..., a[n-1] be in S2.
    // Possible f values:
    // 1. a_i + a_j for a_i, a_j in S2: min = a[1].value + a[2].value, max = a[n-2].value + a[n-1].value
    // 2. a[0].value + a_j + h for a_j in S2: min = a[0].value + a[1].value + h, max = a[0].value + a[n-1].value + h
    // Overall min_f = min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    // Overall max_f = max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)
    // This is the general case where we split the sorted array at some point.
    // Let S1 = {a[0], ..., a[k-1]} and S2 = {a[k], ..., a[n-1]}
    // The critical observation is that the minimum possible sum is always a[0] + a[1] (either same group or different group with h).
    // The maximum possible sum is always a[n-2] + a[n-1] + h (if a[n-2] and a[n-1] are in different groups)
    // OR a[n-2] + a[n-1] (if all are in the same group).
    //
    // Consider the partition where a[0] is in S1 and all other elements are in S2.
    // min_f:
    //   - a[1]+a[2] (if n >= 3, both in S2)
    //   - a[0]+a[1]+h (a[0] in S1, a[1] in S2)
    //   So, min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h) (if n >= 3)
    //   If n=2, only a[0]+a[1]+h is possible.
    // max_f:
    //   - a[n-2]+a[n-1] (both in S2)
    //   - a[0]+a[n-1]+h (a[0] in S1, a[n-1] in S2)
    //   So, max_f = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)
    //
    // The goodness for this partition is max_f - min_f.
    //
    // Let's analyze the two main candidates for optimal partition:
    // 1. All elements in one group (e.g., all 1s). Goodness is (a[n-1]+a[n-2]) - (a[0]+a[1]).
    // 2. The smallest element a[0] is in group 1, and all other elements a[1]...a[n-1] are in group 2.
    //    min_f = min(a[0].value + a[1].value + h, a[1].value + a[2].value) (if n >= 3, else just a[0]+a[1]+h)
    //    max_f = max(a[0].value + a[n-1].value + h, a[n-1].value + a[n-2].value)
    //    Goodness = max_f - min_f.

    long long min_f_val_split;
    if (n == 2) {
        min_f_val_split = a[0].value + a[1].value + h;
    } else {
        min_f_val_split = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
    }
    long long max_f_val_split = std::max(a[0].value + a[n - 1].value + h, a[n - 2].value + a[n - 1].value);
    long long goodness2 = max_f_val_split - min_f_val_split;

    std::vector<int> partition2(n);
    partition2[a[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[a[i].original_index] = 2;
    }

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <vector>
#include <algorithm>

// Function to calculate parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    int initial_parity_a = calculate_parity(a);
    int parity_b = calculate_parity(b);

    // The minimum length 'a' can be reduced to is 1 (if it's not empty).
    // The maximum length 'a' can grow to is |b| + (|a| - 1) if we only append and never remove.
    // However, we can only append if the current string 'a' has a certain parity.
    // A key observation: after appending parity(a), the new string a' will always have parity(a') = 0.
    // Example: if parity(a) is 0, a + '0' has parity 0.
    // Example: if parity(a) is 1, a + '1' has parity 0.
    // So, if we want to append, we can always make the string have parity 0.
    // If we need to append again, we must first make the string have parity 1 (by removing a '1' from the front)
    // or parity 0 (by removing a '0' from the front).

    // Let's simplify. We can always make the string 'a' have parity 0 by appending its parity.
    // If initial_parity_a is 0, we can append '0' to get a string with parity 0.
    // If initial_parity_a is 1, we can append '1' to get a string with parity 0.
    // So, effectively, we can always reach a state where the string has parity 0, and its length is at least |a|.
    // If we need to match 'b', we need to consider two scenarios for the final parity of 'a':
    // 1. 'a' has parity 0.
    // 2. 'a' has parity 1.

    // Let's count the number of '1's in the initial string 'a'.
    int ones_in_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_in_a++;
