        // Or if p[p_start_idx] is too far to the left of h[i-1]-T, this head cannot cover it.
        // The second condition is implicitly handled by the greedy choice below.
        if (p[p_start_idx] > h[i-1] + T) {
            // This head cannot cover the next required track.
            // So, dp[i] remains dp[i-1] (or -1 if dp[i-1] was -1).
            // We need to update dp[i] to be at least dp[i-1]
            dp[i] = std::max(dp[i], dp[i-1]);
            continue;
        }

        // Find the maximum index p_end_idx such that p[p_end_idx] can be covered by h[i-1]
        // This means p[p_end_idx] <= h[i-1] + T
        // And p[p_end_idx] must be covered by h[i-1]
        // The range covered by h[i-1] is [h[i-1] - T, h[i-1] + T]
        // We want to cover tracks from p_start_idx up to some p_end_idx.
        // The crucial part is that the head h[i-1] must be able to reach *both* p_start_idx and p_end_idx.
        // This means h[i-1] must be within [p_start_idx - T, p_end_idx + T] AND [p_end_idx - T, p_start_idx + T]
        // More simply, the interval [p_start_idx, p_end_idx] must be contained within [h[i-1]-T, h[i-1]+T].
        // This is not quite right. A head at h_k can cover any track p_j if |h_k - p_j| <= T.
        // If it covers a range [p_a, p_b], then it must be able to reach both p_a and p_b.
        // This means h_k must be in [p_a - T, p_a + T] AND [p_b - T, p_b + T].
        // So, h_k must be in [max(p_a - T, p_b - T), min(p_a + T, p_b + T)].
        // For a head to cover the interval [p_a, p_b], its position h_k must satisfy:
        // p_b - h_k <= T  => h_k >= p_b - T
        // h_k - p_a <= T  => h_k <= p_a + T
        // So, h_k must be in [p_b - T, p_a + T].
        // For such an h_k to exist, we need p_b - T <= p_a + T, which means p_b - p_a <= 2T.
        // And the head h[i-1] must be able to reach this interval [p_b - T, p_a + T].
        // The head h[i-1] can cover the interval [p_start_idx, p_end_idx] if:
        // 1. p_end_idx >= p_start_idx
        // 2. p[p_end_idx] - p[p_start_idx] <= 2 * T
        // 3. h[i-1] is within [p[p_start_idx] - T, p[p_end_idx] + T]
        //    AND h[i-1] is within [p[p_end_idx] - T, p[p_start_idx] + T]
        // This simplifies to:
        // max(p[p_start_idx], p[p_end_idx]) - h[i-1] <= T
        // h[i-1] - min(p[p_start_idx], p[p_end_idx]) <= T
        // Since p is sorted, p[p_start_idx] is min and p[p_end_idx] is max.
        // So, p[p_end_idx] - h[i-1] <= T  AND  h[i-1] - p[p_start_idx] <= T.

        // We want to find the largest p_end_idx such that h[i-1] can cover [p_start_idx, p_end_idx].
        // This means:
        // p[p_end_idx] <= h[i-1] + T
        // p[p_start_idx] >= h[i-1] - T
        // The second condition is already checked by `p[p_start_idx] > h[i-1] + T` above.
        // If p[p_start_idx] is covered by h[i-1], then h[i-1] - p[p_start_idx] <= T.
        // So we need to find the largest p_end_idx such that p[p_end_idx] <= h[i-1] + T.
        // And also, the entire range [p[p_start_idx], p[p_end_idx]] must be coverable by *some* head.
        // The head h[i-1] can cover the range [p[p_start_idx], p[p_end_idx]] if:
        // 1. p[p_end_idx] - h[i-1] <= T
        // 2. h[i-1] - p[p_start_idx] <= T
        // These two conditions define the range of tracks h[i-1] can cover.
        // We want to maximize p_end_idx.
        // The first condition means p[p_end_idx] <= h[i-1] + T.
        // The second condition means p[p_start_idx] >= h[i-1] - T.
        // We already know p[p_start_idx] >= h[i-1] - T (from the initial check for p_start_idx).
        // So we just need to find the largest p_end_idx such that p[p_end_idx] <= h[i-1] + T.

        // Use binary search to find the largest p_end_idx.
        auto it = std::upper_bound(p.begin() + p_start_idx, p.end(), h[i-1] + T);
        int current_p_end_idx = std::distance(p.begin(), it) - 1;

        // Update dp[i] with the maximum index covered using i heads.
        // It's either the same as dp[i-1] (if this head doesn't extend coverage)
        // or current_p_end_idx (if this head covers up to current_p_end_idx).
        dp[i] = std::max(dp[i-1], current_p_end_idx);
    }

    return dp[n] == m - 1;
}


