    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible difference between p_m and h_1, or p_1 and h_n.
                               // Max p_i is 10^10, min h_i is 1. Max diff is 10^10.
                               // Max p_i is 10^10, max h_i is 10^10. Max diff is 10^10.
                               // So 10^10 is a safe upper bound. 2e10+7 is even safer.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

