    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long good_pairs = 0;

    // max_r_for_l[i] stores the maximum r such that the substring s[i...r-1]
    // does NOT contain any bad pattern.
    // Initialize with n, meaning s[i...n-1] is good.
    std::vector<int> max_r_for_l(n + 1);
    std::iota(max_r_for_l.begin(), max_r_for_l.end(), 0); // max_r_for_l[i] = i initially
    // This is actually max_r_for_l[i] = i-1, meaning s[i...i-1] is good (empty string)
    // We want max_r_for_l[i] to be the largest r such that s[i-1...r-1] is good.
    // Let's use 0-indexed for max_r_for_l, so max_r_for_l[i] is max r (0-indexed)
    // such that s[i...r] is good.
    // Initialize max_r_for_l[i] = n-1 for all i.
    for (int i = 0; i < n; ++i) {
        max_r_for_l[i] = n - 1;
    }

