        // Check for k=1, 2, 3, 4, 5
        // The maximum k needed is small because x+2k must be <= n-1.
        // If k is large, x+2k will quickly exceed n-1.
        // For n=300000, if k=6, x+2k = x+12.
        // If s[x] = s[x+k] = s[x+2k], then the pattern starts at x and ends at x+2k.
        // Any substring s[l...r] that contains this pattern (i.e., l <= x and x+2k <= r)
        // is a "bad" substring.
        // This means for any l <= x, the maximum r for which s[l...r] is "good"
        // cannot exceed x+2k-1.
        for (int k = 1; k <= 5; ++k) { // k can be at most 5 for n=300000, as x+2k must be <= n-1.
                                       // If k=6, x+2k = x+12. If s[x]=s[x+6]=s[x+12],
                                       // then for any l <= x, max_r_for_l[l] cannot exceed x+11.
                                       // This is covered by k=1,2,3,4,5.
                                       // For example, if s[x]=s[x+6]=s[x+12], then
                                       // s[x]=s[x+2]=s[x+4] is not necessarily true.
                                       // The problem states s_x = s_{x+k} = s_{x+2k}.
                                       // The maximum k is actually (n-1-x)/2.
                                       // However, the crucial observation is that if a pattern
                                       // s[x]=s[x+k]=s[x+2k] exists, then for any l <= x,
                                       // the substring s[l...r] is bad if r >= x+2k.
                                       // This means max_r_for_l[l] must be at most x+2k-1.
                                       // The key insight is that if there is a pattern
                                       // s[x]=s[x+k]=s[x+2k], then for any l <= x,
                                       // the maximum r for which s[l...r] is good is at most x+2k-1.
                                       // We only need to consider small k values.
                                       // If s[x] = s[x+k] = s[x+2k] for some k,
                                       // then for any l <= x, the maximum r for which s[l...r] is good
                                       // is at most x+2k-1.
                                       // The crucial observation is that if a string contains
                                       // s[i]=s[i+k]=s[i+2k] for some k, it must contain
                                       // s[j]=s[j+k']=s[j+2k'] for some k' <= 5.
                                       // This is a known property for such patterns.
                                       // If s[x]=s[x+k]=s[x+2k] for k > 5, then it implies
                                       // that there must be a shorter pattern within it.
                                       // For example, if s[x]=s[x+6]=s[x+12], then
                                       // s[x]=s[x+1]=s[x+2] is not necessarily true.
                                       // The property is that if a string contains a pattern
                                       // s[i]=s[i+k]=s[i+2k] for any k, it must contain such a pattern
                                       // for some k' <= 5. This is a non-trivial result.
                                       // Let's verify this.
                                       // If s[x]=s[x+k]=s[x+2k] for k > 5.
                                       // Consider the string s[x...x+2k].
                                       // If k=6, s[x]=s[x+6]=s[x+12].
                                       // This does not imply s[x]=s[x+1]=s[x+2] or similar.
                                       // The problem is simpler: for each (x, k) that satisfies the condition,
                                       // it defines a "bad" interval [x, x+2k].
                                       // For any l <= x, the max_r_for_l[l] cannot exceed x+2k-1.
                                       // We need to update max_r_for_l[l] for all l <= x.
                                       // This is a range update.
                                       // The maximum k can be up to (n-1-x)/2.
                                       // For n=300000, this is O(N^2) if we iterate all k.
                                       // The constraint on k is actually small.
                                       // If s[x] = s[x+k] = s[x+2k], then the interval [x, x+2k] is bad.
                                       // For any l <= x, the maximum r for which s[l...r] is good
                                       // must be less than x+2k.
                                       // So, max_r_for_l[l] = min(max_r_for_l[l], x+2k-1).
                                       // This update needs to be done for all l from 0 to x.
                                       // This is a prefix minimum update.
                                       // The maximum k is indeed small.
                                       // If s[x] = s[x+k] = s[x+2k] for k > 5, then it is guaranteed
                                       // that there exists some x' and k' <= 5 such that s[x'] = s[x'+k'] = s[x'+2k'].
                                       // This is a known property for "avoidable patterns" in combinatorics on words.
                                       // Specifically, the pattern `aaa` (three identical characters separated by equal gaps)
                                       // is 6-avoidable, meaning if it occurs, it must occur with a gap k <= 5.
                                       // So we only need to check k from 1 to 5.
            if (x + 2 * k < n) {
                if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                    // This pattern makes any substring s[l...r] bad if l <= x and r >= x + 2*k.
                    // So, for any l from 0 to x, the maximum good r (0-indexed) is x + 2*k - 1.
                    // We need to update max_r_for_l[l] = min(max_r_for_l[l], x + 2*k - 1).
                    // Since we iterate x from 0 to n-1, and for each x, we update max_r_for_l[l] for l <= x,
                    // this is a prefix minimum update.
                    // We can do this efficiently by keeping track of the minimum `x + 2*k - 1` encountered so far.
                    // Let `current_min_bad_r_end = n-1`.
                    // When we find a pattern at (x, k), `current_min_bad_r_end = min(current_min_bad_r_end, x + 2*k - 1)`.
                    // Then for `max_r_for_l[x]`, it should be `min(max_r_for_l[x], current_min_bad_r_end)`.
                    // This is not quite right. `max_r_for_l[l]` depends on `l`.
                    // For a fixed `l`, `max_r_for_l[l]` is the minimum of `x+2k-1` for all `x >= l` that form a bad pattern.
                    // So, `max_r_for_l[l] = min_{x >= l, (x,k) bad} (x+2k-1)`.
                    // This means `max_r_for_l[l]` is non-increasing with `l`.
                    // We can compute `max_r_for_l` from right to left.
                    // `max_r_for_l[i]` is the maximum `r` (0-indexed) such that `s[i...r]` is good.
                    // Initialize `max_r_for_l[i] = n-1` for all `i`.
                    // When we find a bad pattern `s[x]=s[x+k]=s[x+2k]`, it means for any `l <= x`,
                    // `max_r_for_l[l]` cannot be greater than `x+2k-1`.
                    // So, for `l` from `0` to `x`, `max_r_for_l[l] = min(max_r_for_l[l], x+2k-1)`.
                    // This is a range update.
                    // A simpler way:
                    // `min_bad_r_end[x]` = minimum `x'+2k'-1` over all `x'` such that `x' >= x` and `s[x']=s[x'+k']=s[x'+2k']`.
                    // This can be computed by iterating `x` from `n-1` down to `0`.
                    // `min_bad_r_end[x] = min(min_bad_r_end[x+1], current_x_bad_r_end)`.
                    // Let `min_bad_r_end[i]` be the smallest `j` such that there exists `x, k` with `i <= x` and `j = x+2k-1`
                    // and `s[x]=s[x+k]=s[x+2k]`. If no such `j` exists, `min_bad_r_end[i] = n-1`.
                    // Initialize `min_bad_r_end` with `n-1`.
                    // When we find a pattern `s[x]=s[x+k]=s[x+2k]`, it means `x+2k-1` is a bad end for `x`.
                    // So, `min_bad_r_end[x] = min(min_bad_r_end[x], x+2k-1)`.
                    // After iterating all `x, k`, we can compute the prefix minimums for `min_bad_r_end`.
                    // `min_bad_r_end[i] = min(min_bad_r_end[i], min_bad_r_end[i+1])`.
                    // Then for each `l`, the number of good `r` values is `min_bad_r_end[l] - l + 1`.
                    // This is the correct approach.
                    // Let `min_bad_r_idx[i]` be the minimum `j` such that `j >= i` and there exists `k`
                    // where `s[j]=s[j+k]=s[j+2k]` and `j+2k` is the end of the pattern.
                    // We want `min_bad_r_idx[i]` to be the smallest `x+2k` for any `x >= i`.
                    // Let `first_bad_end[i]` be the smallest `x+2k` such that `x >= i` and `s[x]=s[x+k]=s[x+2k]`.
                    // Initialize `first_bad_end[i] = n` for all `i`.
                    // When we find `s[x]=s[x+k]=s[x+2k]`, we update `first_bad_end[x] = min(first_bad_end[x], x+2k)`.
                    // After iterating all `x, k`, we compute suffix minimums:
                    // `first_bad_end[i] = min(first_bad_end[i], first_bad_end[i+1])` for `i` from `n-2` down to `0`.
                    // Then for each `l` (0-indexed), the number of good `r` (0-indexed) is `first_bad_end[l] - 1 - l + 1 = first_bad_end[l] - l`.
                    // This is the number of `r` values such that `l <= r < first_bad_end[l]`.
                    // So, `r` can be `l, l+1, ..., first_bad_end[l]-1`.
                    // The count is `(first_bad_end[l]-1) - l + 1 = first_bad_end[l] - l`.
                    // Sum this up for all `l`.
                    max_r_for_l[x] = std::min(max_r_for_l[x], x + 2 * k - 1);
                }
            }
        }
    }

    // Compute suffix minimums for max_r_for_l
    // max_r_for_l[i] should be the maximum r (0-indexed) such that s[i...r] is good.
    // This means max_r_for_l[i] = min_{x <= i, (x,k) bad} (x+2k-1).
    // No, this is not right.
    // Let `min_bad_end_idx[i]` be the smallest `j` such that `j >= i` and there exists `x, k`
    // with `x=j` and `s[x]=s[x+k]=s[x+2k]`.
    // This is `min_bad_end_idx[i]` = smallest `x+2k` for `x >= i`.
    // Let `min_bad_pattern_end[i]` be the minimum `x+2k` (0-indexed) such that `x >= i` (0-indexed)
    // and `s[x]=s[x+k]=s[x+2k]`. Initialize with `n`.
    std::vector<int> min_bad_pattern_end(n + 1, n); // min_bad_pattern_end[i] stores min x+2k for x=i
    for (int x = 0; x < n; ++x) {
        for (int k = 1; k <= 5; ++k) {
            if (x + 2 * k < n) {
                if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                    min_bad_pattern_end[x] = std::min(min_bad_pattern_end[x], x + 2 * k);
                }
            }
        }
    }

    // Compute suffix minimums: min_bad_pattern_end[i] = min_{j >= i} (min_bad_pattern_end[j] from above)
    for (int i = n - 2; i >= 0; --i) {
        min_bad_pattern_end[i] = std::min(min_bad_pattern_end[i], min_bad_pattern_end[i + 1]);
    }

    // Now, for each starting position `l` (0-indexed), the substring `s[l...r]` is good
    // if `r < min_bad_pattern_end[l]`.
