    // The number of such `r` values is `(min_bad_pattern_end[l]-1) - l + 1 = min_bad_pattern_end[l] - l`.
    for (int l = 0; l < n; ++l) {
        good_pairs += (min_bad_pattern_end[l] - l);
    }

    std::cout << total_pairs - good_pairs << std::endl;

    return 0;
}

// The crucial observation about k <= 5:
// This is a known result in combinatorics on words. The pattern `xxx` (three identical characters separated by equal gaps)
// is 6-avoidable. This means that if a string contains `s[i]=s[i+k]=s[i+2k]` for some `k`,
// then it must contain such a pattern for some `k' <= 5`.
// For example, if `s[x]=s[x+6]=s[x+12]`, it is guaranteed that there exists some `x'` and `k' <= 5`
// such that `s[x']=s[x'+k']=s[x'+2k']`.
// This is a strong claim and simplifies the problem significantly.
// Without this property, the solution would be O(N^2) or require more advanced data structures.
// With this property, the inner loop runs at most 5 times, making the overall complexity O(N).

// Let's re-verify the logic for `min_bad_pattern_end`.
// `min_bad_pattern_end[i]` is the smallest `j` such that `j >= i` and `s[j]=s[j+k]=s[j+2k]` for some `k`,
// and `j+2k` is the end of this pattern.
// No, `min_bad_pattern_end[i]` should be the smallest `x+2k` such that `x >= i` and `s[x]=s[x+k]=s[x+2k]`.
// Let `min_bad_end_for_start_x[x]` be the smallest `x+2k` for the given `x`.
// `min_bad_end_for_start_x[x] = min_{k=1..5, s[x]=s[x+k]=s[x+2k]} (x+2k)`. If no such k, it's `n`.
// This is what the first loop computes into `min_bad_pattern_end[x]`.
// Then, `min_bad_pattern_end[i]` should be the smallest `x+2k` for any `x >= i`.
// This is correctly computed by the suffix minimums:
// `min_bad_pattern_end[i] = min(min_bad_pattern_end[i], min_bad_pattern_end[i+1])`.
// So, for a given `l` (0-indexed start of substring), any `r` (0-indexed end of substring)
// such that `r >= min_bad_pattern_end[l]` will make the substring `s[l...r]` bad.
// Therefore, for `s[l...r]` to be good, we must have `r < min_bad_pattern_end[l]`.
// The possible values for `r` are `l, l+1, ..., min_bad_pattern_end[l]-1`.
// The number of such `r` values is `(min_bad_pattern_end[l]-1) - l + 1 = min_bad_pattern_end[l] - l`.
// This logic is sound.

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s[0...i-1] and s[i...N-1].
    // We can rearrange them to s[i...N-1] + s[0...i-1].
    // This new string must be a palindrome and not equal to s.
    // Since s is a palindrome, s[0...i-1] + s[i...N-1] == reverse(s[i...N-1]) + reverse(s[0...i-1]).
    // We are looking for s[i...N-1] + s[0...i-1] to be a palindrome.
    // This means s[i...N-1] + s[0...i-1] == reverse(s[0...i-1]) + reverse(s[i...N-1]).
    // This is equivalent to checking if s[i...N-1] + s[0...i-1] is a palindrome.
    // Also, the new string must not be equal to s.
    // If s[i...N-1] + s[0...i-1] == s, then s is a periodic string.
    // For example, if s = "ababa", cut at i=2 gives "ab" and "aba". Rearranged: "abaab". This is not "ababa".
    // If s = "otto", cut at i=2 gives "ot" and "to". Rearranged: "toot". This is a palindrome and not "otto". k=1.
    // If s = "kinnikkinnik", cut at i=6 gives "kinnik" and "kinnik". Rearranged: "kinnikkinnik". This is "s".
    // But if cut at i=3 gives "kin" and "nikkinnik". Rearranged: "nikkinnikkin". This is a palindrome and not "s". k=1.

    for (int i = 1; i < n; ++i) { // i is the cut point, s[0...i-1] and s[i...N-1]
        std::string s_prime = s.substr(i) + s.substr(0, i);
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // With k=2, we have 3 pieces.
