int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The first class will have students from index 0 to n-1.
        // Its median will be a[n-1].
        // The second class will have students from index n to 2n-1.
        // Its median will be a[n].
        // This partition ensures both classes have n students.
        // Since n is the number of students halved, the total number of students is 2n.
        // If n students are in each class, and n is odd, then this is a valid partition.
        // If n is even, this is not a valid partition.
        // However, the problem statement implies that the optimal partition
        // will always involve taking the n smallest elements for one class
        // and the n largest elements for the other class, regardless of n's parity.
        // The median of the first n elements (0 to n-1) is a[(n-1)/2] if n is odd.
        // The median of the last n elements (n to 2n-1) is a[n + (n-1)/2] if n is odd.
        // But the problem is simpler: the median of a sorted array of 2k+1 elements is b_{k+1}.
        // For a class of size S, the median is the element at index (S-1)/2 in 0-indexed sorted array.
        // The key insight is that to minimize the difference between medians, we should make the medians as close as possible.
        // This happens when the elements are split as evenly as possible around the middle.
        // The two middle elements of the entire sorted array are a[n-1] and a[n].
        // If we can make these two elements the medians of the two classes, that would be ideal.
        // This is achieved by putting a[0]...a[n-1] into one class and a[n]...a[2n-1] into the other.
        // Each class would have n students.
        // The median of the first class (a[0]...a[n-1]) would be a[n-1] if n is odd.
        // The median of the second class (a[n]...a[2n-1]) would be a[n] if n is odd.
        // The problem statement says "each class has odd number of students".
        // This means n must be odd for this specific split to be valid.
        // However, the problem is simpler than that. The minimum difference is always between a[n-1] and a[n].
        // This is because any other choice of medians would involve elements further apart.
        // For example, if we pick a[i] and a[j] as medians, with i < n-1 or j > n, then |a[j]-a[i]| would be larger.
        // The minimum difference is achieved by taking the (n-1)-th element and the n-th element (0-indexed)
        // from the fully sorted array of 2n students.
        // These are a[n-1] and a[n].
        long long diff = a[n] - a[n - 1];
        std::cout << diff << "\n";
    }
    return 0;
}

