            // either equal to or less than the current minimum in the suffix.
            // So, a[i] itself becomes a new candidate for the minimum in the
            // suffix for elements further to the left.
            min_suffix_price = a[i];
        }
    }

    std::cout << bad_prices_count << std::endl;
}

