void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_minus_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // Update has_one and has_minus_one for elements a[i+1] onwards
        // This is important because a[i] can be used to modify a[j] for j > i.
        // If a[i] is 1, then has_one remains true.
        // If a[i] is -1, then has_minus_one remains true.
        // If a[i] is 0, it doesn't change the ability to add 1 or -1.
        // The current a[i] value is what matters for future operations, not b[i].
        // However, the problem states "Add a_i to a_j". This means the *original* a_i.
        // The example "transform it only to [1, -1, -1], [1, 0, 0] and [1, -1, 1] by one operation"
        // implies that a_i is the original value.
        // "Add a_i to a_j" means a_j becomes a_j + (original a_i).
        // If it meant a_j becomes a_j + (current a_i), then the problem would be much harder.
        // The phrasing "Add a_i to a_j" usually refers to the value at index i in the current state.
        // But the problem statement "array a contains only elements from the set {-1, 0, 1}"
        // and the example "if you are given array [1, -1, 0], you can transform it only to [1, -1, -1], [1, 0, 0] and [1, -1, 1] by one operation."
        // This example is crucial.
        // [1, -1, 0]
        // (1,2): a_2 = a_2 + a_1 = -1 + 1 = 0. Array becomes [1, 0, 0].
        // (1,3): a_3 = a_3 + a_1 = 0 + 1 = 1. Array becomes [1, -1, 1].
        // (2,3): a_3 = a_3 + a_2 = 0 + (-1) = -1. Array becomes [1, -1, -1].
        // This confirms that a_i refers to the *current* value of a[i].
        // So, the `has_one` and `has_minus_one` flags should be updated based on the *original* values of a[k] for k <= i.
        // My initial logic was correct: `has_one` and `has_minus_one` track if there's *any* original 1 or -1 at an index less than or equal to the current index `i`.
        // This is because once an a[k] (k < i) becomes 1 or -1, it can be used for future operations.
        // But the problem states "array a contains only elements from the set {-1, 0, 1}". This is the *initial* state.
        // The operation "Add a_i to a_j" means the value of a_i *at the time of the operation*.
        // If a_i itself was modified, its value might change.
        // However, the constraint $i < j$ means $a_i$ is never modified by operations involving $a_k$ where $k > i$.
        // $a_i$ can only be modified by $a_k$ where $k < i$.
        // This means that for any $a_j$, the values $a_1, a_2, \dots, a_{j-1}$ are the ones that can be added to $a_j$.
        // And these $a_1, \dots, a_{j-1}$ themselves might have been modified.
        // This makes the problem much more complex.
        // Let's re-read: "Add a_i to a_j. In other words, j-th element of the array becomes equal to a_i + a_j."
        // The example: "[1, -1, 0] -> [1, -1, -1], [1, 0, 0] and [1, -1, 1] by one operation."
        // This example implies that the values of a_i used in the operation are the *original* values.
        // If a_i could be modified, then the set of possible values for a_i would expand beyond {-1, 0, 1}.
        // For example, if a_1=1, a_2=1, then a_2 could become 1+1=2. Then if we use a_2 to modify a_3, we could add 2.
        // But the problem says "array a contains only elements from the set {-1, 0, 1}". This is a strong hint that the *source* of additions must be from this set.
        // The most natural interpretation for competitive programming is that $a_i$ refers to the *original* value of $a_i$.
        // If $a_i$ refers to the *current* value of $a_i$, then the problem is much harder and the example is misleading.
        // Let's stick to the interpretation that $a_i$ refers to the *original* value of $a_i$.
        // In this case, `has_one` and `has_minus_one` should track if there was an original 1 or -1 *before* index `i`.
        // So, `has_one` and `has_minus_one` should be updated *after* checking `a[i]` vs `b[i]`.

        // Update has_one and has_minus_one for the next iteration (for index i+1)
        // These flags track if there's an original 1 or -1 at an index k < i+1.
        // So, for the current index `i`, we check if `a[k]` for `k < i` contains 1 or -1.
        // The flags `has_one` and `has_minus_one` are initialized based on `a[0]`.
        // Then for `i=1`, they reflect `a[0]`.
        // For `i=2`, they reflect `a[0]` and `a[1]`.
        // So, the flags should be updated *before* the check for `a[i]`.
        // Let's re-evaluate the loop structure.

        // Initial state: has_one and has_minus_one reflect elements up to a[0].
        // For i=0, a[0] must equal b[0]. No operations possible.
        // For i=1, we can use a[0] to modify a[1].
        // So, `has_one` and `has_minus_one` should reflect elements `a[0]...a[i-1]`.
        // Let's re-initialize them for each test case and update them correctly.
    }

    // Re-thinking the loop and flags:
    // `can_add_one` and `can_add_minus_one` should track if there's *any* $a_k=1$ or $a_k=-1$ for $k < i$.
    // This is because $a_k$ (for $k < i$) can be added to $a_i$.
    // The values $a_k$ themselves are not changed by operations $a_p \leftarrow a_p + a_q$ where $q < p < k$.
    // This is because $a_k$ is only changed by $a_p$ where $p < k$.
    // The problem statement is ambiguous. "Add $a_i$ to $a_j$" could mean the original $a_i$ or the current $a_i$.
    // If it means the original $a_i$, then `has_one` and `has_minus_one` should be global for the whole array `a`.
    // If it means the current $a_i$, then $a_i$ can be modified by $a_k$ ($k<i$), and then $a_i$ (modified) can be added to $a_j$ ($j>i$).
    // The example: "[1, -1, 0] -> [1, -1, -1], [1, 0, 0] and [1, -1, 1] by one operation."
    // This example shows that the values used for addition are the *original* values.
    // If $a_i$ could be modified and then used, then $a_i$ could become, say, 2. Then we could add 2.
    // But the problem says "array a contains only elements from the set {-1, 0, 1}". This is the initial state.
    // If the values used for addition were allowed to be modified, then the set of possible values for $a_i$ would expand.
    // This implies that the $a_i$ in "Add $a_i$ to $a_j$" refers to the *original* $a_i$.
    // If this is the case, then `has_one` and `has_minus_one` should be computed once for the entire array `a`.

    // Let's re-evaluate with the assumption that $a_i$ refers to the *original* $a_i$.
    // This means `has_one` and `has_minus_one` are determined by the initial `a` array.
    // `has_one_global` = true if any `a[k]` (original) is 1.
    // `has_minus_one_global` = true if any `a[k]` (original) is -1.
    // This is what my first implementation attempt did.
    // Let's re-run the logic with this interpretation.

    // `has_one` and `has_minus_one` are already computed for the entire array `a` at the beginning.
    // `has_one` is true if there is *any* 1 in the original `a` array.
    // `has_minus_one` is true if there is *any* -1 in the original `a` array.
    // This is the simplest interpretation and usually what's intended unless specified otherwise.

    // The example "In the first test-case we can choose (i, j)=(2, 3) twice and after that choose (i, j)=(1, 2) twice too. These operations will transform [1, -1, 0] -> [1, -1, -2] -> [1, 1, -2]"
    // Initial: a = [1, -1, 0], b = [1, 1, -2]
    // has_one = true (from a[0]=1)
    // has_minus_one = true (from a[1]=-1)

    // i=0: a[0]=1, b[0]=1. OK.
    // i=1: a[1]=-1, b[1]=1. Need to increase a[1] by 2.
    //      Since has_one is true, we can add 1 to a[1] twice.
    //      This means a[1] can become -1 + 1 + 1 = 1. OK.
    // i=2: a[2]=0, b[2]=-2. Need to decrease a[2] by 2.
    //      Since has_minus_one is true, we can add -1 to a[2] twice.
    //      This means a[2] can become 0 + (-1) + (-1) = -2. OK.
    // All checks pass. Output YES. This matches the example.

    // Example 2: a = [0, 1, 1], b = [0, 2, 2]
    // has_one = true (from a[1]=1)
    // has_minus_one = false
    // i=0: a[0]=0, b[0]=0. OK.
    // i=1: a[1]=1, b[1]=2. Need to increase a[1] by 1.
    //      Can we use a[0]=0 to increase a[1]? No.
    //      This is the key. The `has_one` and `has_minus_one` flags must be for elements *before* the current index `i`.
    //      So, for `a[i]`, we can only use `a[k]` where `k < i`.
    //      This means the flags must be updated iteratively.

    // Let's refine the flags:
    // `can_add_one_from_left`: true if there exists an original `a[k] = 1` for some `k < i`.
    // `can_add_minus_one_from_left`: true if there exists an original `a[k] = -1` for some `k < i`.

    bool current_can_add_one = false;
    bool current_can_add_minus_one = false;

    // For i=0, a[0] must equal b[0]. No operations possible.
    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    // After checking a[0], update flags for elements that can be used for a[1] onwards.
    if (a[0] == 1) {
        current_can_add_one = true;
    } else if (a[0] == -1) {
        current_can_add_minus_one = true;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!current_can_add_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!current_can_add_minus_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // Update flags for the next iteration (for index i+1)
        // The original a[i] can now be used to modify a[j] for j > i.
        if (a[i] == 1) {
            current_can_add_one = true;
        } else if (a[i] == -1) {
            current_can_add_minus_one = true;
        }
    }

    std::cout << "YES\n";
}

