int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The area of the whole carrot is A_total = (1/2) * base * height = (1/2) * 1 * h = h/2.
    // We want to divide this into n equal pieces.
    // So, each piece has area A_piece = A_total / n = (h/2) / n = h / (2n).

    // Consider a smaller triangle formed by a cut at distance x from the apex.
    // By similar triangles, if the height is x, the base is x/h.
    // The area of this smaller triangle is A_x = (1/2) * (x/h) * x = x^2 / (2h).

    // We need to find x_i such that the area from the apex to x_i is i * A_piece.
    // So, x_i^2 / (2h) = i * (h / (2n)).
    // x_i^2 = i * (h^2 / n).
    // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n).

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

