void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i-1]
    // This marks the end of the initial non-decreasing suffix.
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // Now `a[i...n-1]` is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[j] > a[j-1]
    // This marks the end of the initial non-increasing suffix.
    // We start from `i` because any elements to the right of `i` are already part of a non-decreasing sequence.
    // If we want to form a "mountain" shape, the peak must be to the left of `i`.
    // So we look for the non-increasing part starting from `i`.
    int j = i;
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }
    // Now `a[j...i-1]` is non-increasing (if `j < i`).
    // `a[j...n-1]` is the longest suffix that can be made good.
    // The elements `a[0...j-1]` must be removed.

    std::cout << j << std::endl;
}

