    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int target_open = k / 2;
    int target_close = k / 2;

    for (char c : s) {
        if (c == '(') {
            if (open_count < target_open) {
                result += '(';
                open_count++;
            }
        } else { // c == ')'
            // We can add a ')' if we still need one AND
            // if we have an unmatched '(' in our result string
            // (i.e., open_count > close_count) AND
            // if we still need to add ')' (close_count < target_close)
            // The condition open_count > close_count ensures regularity.
            // The condition close_count < target_close ensures we don't exceed k/2 closing brackets.
            // The problem guarantees a solution exists, so this greedy choice works.
            if (close_count < target_close && open_count > close_count) {
                result += ')';
                close_count++;
            }
        }
        if (result.length() == k) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

