int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
        } else if (d < 4) {
            std::cout << "N\n";
        } else {
            // We need to solve a + b = d and a * b = d
            // This leads to the quadratic equation: x^2 - d*x + d = 0
            // Using the quadratic formula: x = (d +/- sqrt(d^2 - 4d)) / 2
            double discriminant = d * d - 4 * d;

            // Since d >= 4, discriminant will be non-negative.
            // d^2 - 4d >= 0 for d >= 4 or d <= 0.
            // Given d is non-negative, d=0 or d>=4.
            // We already handled d=0. So for d>=4, discriminant is non-negative.

            double sqrt_discriminant = std::sqrt(discriminant);

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            // Both a and b must be non-negative.
            // Since d >= 4, d is positive.
            // sqrt_discriminant = sqrt(d(d-4)).
            // If d >= 4, then d-4 >= 0, so sqrt_discriminant >= 0.
            // Thus, a = (d + sqrt_discriminant) / 2.0 will always be positive.
            // For b = (d - sqrt_discriminant) / 2.0 to be non-negative, we need d - sqrt_discriminant >= 0.
            // d >= sqrt_discriminant
            // d^2 >= discriminant
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true since d is non-negative.
            // So both a and b will always be non-negative for d >= 4.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
