        // If B=0 and C=0, then all toys are in (-inf, -1] or [1, inf). Their product will always be in (-inf, -1] or [1, inf).
        // So, if B=0 and C=0, Box 2 is impossible.
        if (B == 0 && C == 0) {
            return false;
        }
        // Otherwise, if A+B is odd and (B > 0 or C > 0), it's possible.
        return true;
    }
    // If A + B is even, the final product will be positive. So Box 2 is impossible.
    return false;
}

