int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int j = 0; // Pointer for elements to be placed (the 'b' array elements)
    for (int i = 0; i < n; ++i) { // Pointer for original positions (the 'a' array elements)
        // We are trying to find an element a[j] from the sorted array
        // to place at position i (which originally held a[i])
        // such that a[j] > a[i].
        // Since both arrays are sorted, if a[j] > a[i], then any a[k] with k > j
        // will also be > a[i] (or equal if a[k] == a[j]).
        // We want to use the smallest possible a[j] that satisfies the condition
        // to save larger elements for larger a[i] values.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] such that a[j] > a[i]
            count++;
            j++; // Move to the next element for the 'b' array
        } else {
            // No more elements in 'a' (from index j onwards) are greater than a[i].
            // Since 'a' is sorted, no subsequent a[k] (k > i) will be able to find
            // a greater element either. So we can break.
            break;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

