// Function to check if a subarray is a permutation
// This version checks for distinctness and max value.
// It assumes values are positive.
bool is_permutation(const std::vector<int>& arr, int start_idx, int end_idx, int length) {
    if (length == 0) return true; // Empty sequence is vacuously a permutation
    if (length < 0) return false; // Should not happen with correct logic

    std::vector<bool> seen(length + 1, false);
    int max_val = 0;
    for (int i = start_idx; i < end_idx; ++i) {
        int val = arr[i];
        if (val <= 0 || val > length || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == length;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    int max_overall = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] > max_overall) {
            max_overall = a[i];
        }
    }

    std::vector<std::pair<int, int>> results;

    // Precompute prefix permutation validity
    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max_prefix = 0;
    bool possible_prefix = true;
    for (int l1 = 1; l1 <= n; ++l1) {
        int val = a[l1 - 1];
        if (val > l1 || seen_prefix[val]) {
            possible_prefix = false;
        }
        if (possible_prefix) {
            seen_prefix[val] = true;
            if (val > current_max_prefix) {
                current_max_prefix = val;
            }
            if (current_max_prefix == l1) {
                is_prefix_perm[l1] = true;
            }
        }
    }

    // Precompute suffix permutation validity
    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    int current_max_suffix = 0;
    bool possible_suffix = true;
    for (int l2 = 1; l2 <= n; ++l2) {
        int val = a[n - l2];
        if (val > l2 || seen_suffix[val]) {
            possible_suffix = false;
        }
        if (possible_suffix) {
            seen_suffix[val] = true;
            if (val > current_max_suffix) {
                current_max_suffix = val;
            }
            if (current_max_suffix == l2) {
                is_suffix_perm[l2] = true;
            }
        }
    }

    // Check all possible split points
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

