void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    // We need to append elements.
    // Let S_0 be current_sum and X_0 be current_xor_sum.
    // We want S_0 + b_1 + b_2 = 2 * (X_0 ^ b_1 ^ b_2).
    // A common strategy is to make X_0 ^ b_1 ^ b_2 = X_0.
    // This means b_1 ^ b_2 = 0, so b_1 = b_2.
    // Let b_1 = b_2 = X_0.
    // Then the new XOR sum is X_0 ^ X_0 ^ X_0 = X_0.
    // The new sum is S_0 + X_0 + X_0 = S_0 + 2*X_0.
    // We need S_0 + 2*X_0 = 2 * X_0.
    // This implies S_0 = 0, which is not generally true.

    // Let's try to make the final XOR sum X_f such that S_f = 2 * X_f.
    // Consider appending two elements: X_0 and S_0 + X_0.
    // Let b_1 = X_0.
    // Let b_2 = S_0 + X_0.
    // New XOR sum: X_f = X_0 ^ b_1 ^ b_2 = X_0 ^ X_0 ^ (S_0 + X_0) = S_0 + X_0.
    // New sum: S_f = S_0 + b_1 + b_2 = S_0 + X_0 + (S_0 + X_0) = 2*S_0 + 2*X_0.
    // We need S_f = 2 * X_f.
    // So, 2*S_0 + 2*X_0 = 2 * (S_0 + X_0).
    // This equation is always true!
    // So, we can always append two elements: X_0 and S_0 + X_0.

    // The problem states we can append at most 3 elements.
    // The strategy above uses 2 elements.
    // The elements are X_0 and S_0 + X_0.
    // X_0 can be up to 2^30 (approx) if all a_i are 10^9.
    // S_0 can be up to 10^5 * 10^9 = 10^14.
    // So S_0 + X_0 can be up to 10^14 + 2^30, which fits in long long.
    // The problem states appended elements can be up to 10^18.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

