long long solve() {
    long long n;
    std::cin >> n;
    long long chanek_coins = 0;
    long long turn = 0; // 0 for Chanek, 1 for Opponent

    while (n > 0) {
        if (n % 2 == 1) { // N is odd
            if (turn == 0) { // Chanek's turn
                chanek_coins += 1;
            }
            n -= 1;
        } else { // N is even
            // If N is 2, taking 1 or N/2 (which is 1) leads to the same outcome.
            // The remaining 1 coin will be taken by the opponent.
            // Chanek gets 1, Opponent gets 1.
            if (n == 2) {
                if (turn == 0) {
                    chanek_coins += 1;
                }
                n -= 1; // N becomes 1, next turn opponent takes 1.
            } else {
                // N is even and N > 2
                // Option 1: Take N/2 coins
                // Option 2: Take 1 coin (N becomes odd)

                // If N/2 is odd, taking N/2 leaves an odd number of coins (N/2).
                // The next player will be forced to take 1.
                // If N/2 is even, taking N/2 leaves an even number of coins (N/2).
                // The next player might take N/4 or 1.

                // Consider the strategy:
                // If N is even, and N is not a power of 2 (i.e., N has an odd factor > 1),
                // then N/2 is not a power of 2 either (unless N/2 is 1).
                // If N is a power of 2 (e.g., 4, 8, 16, ...), then N/2 is also a power of 2.
                // In this case, taking N/2 repeatedly leads to N, N/2, N/4, ..., 2, 1.
                // The player who takes N/2 from N=2 gets 1 coin.

                // If N is a power of 2 (N = 2^k, k >= 2):
                // Chanek takes N/2. N becomes N/2.
                // Opponent takes (N/2)/2. N becomes N/4.
                // This continues until N becomes 2.
                // The player whose turn it is when N=2 takes 1 coin.
                // If k is even, Chanek takes N/2, N/8, ..., 2. Chanek gets N/2 + N/8 + ... + 2.
                // If k is odd, Chanek takes N/2, N/8, ..., 4. Opponent takes 2.
                // This means if N is a power of 2, the first player (Chanek) will always take N/2.
                // The total coins taken by Chanek will be N/2 + N/8 + ... + 2 (if k is even) or N/2 + N/8 + ... + 4 (if k is odd).
                // The total coins taken by Opponent will be N/4 + N/16 + ... + 2 (if k is odd) or N/4 + N/16 + ... + 1 (if k is even).
                // In this scenario, Chanek always takes N/2.

                // If N is even but not a power of 2:
                // N = 2^k * M, where M is odd and M > 1.
                // If Chanek takes N/2, N becomes 2^(k-1) * M.
                // If Chanek takes 1, N becomes 2^k * M - 1 (odd).
                // If Chanek takes N/2, the game continues with N/2.
                // If Chanek takes 1, the opponent is forced to take 1.
                // This means Chanek gets 1, and then the opponent gets 1, and so on.
                // This is generally worse for Chanek.

                // Optimal strategy for even N:
                // If N is a power of 2 (N = 2^k, k >= 1):
                //   Both players will always choose to take N/2.
                //   The coins will be split such that the first player gets N/2 + N/8 + ...
                //   and the second player gets N/4 + N/16 + ...
                //   The last coin (from N=2) is taken by the player whose turn it is.
                //   This means the player who starts with N=2^k gets 2^k - (2^k/3) if k is even, or (2^k/3) if k is odd.
                //   More simply, the first player gets 2^k * (2/3) approximately.
                //   The total coins are N. The first player gets 2/3 of N, second player gets 1/3 of N.
                //   This is because 2^k + 2^(k-2) + ... = 2^k * (1 + 1/4 + 1/16 + ...) = 2^k * (1 / (1 - 1/4)) = 2^k * (4/3).
                //   And 2^(k-1) + 2^(k-3) + ... = 2^(k-1) * (1 + 1/4 + 1/16 + ...) = 2^(k-1) * (4/3).
                //   So the first player gets 2^k * (4/3) / 2 = 2^k * (2/3) if they take N/2.
                //   This is not quite right. The sum is N/2 + N/8 + ... + 1 (if k is odd) or + 2 (if k is even).
                //   The sum of geometric series 2^k + 2^(k-2) + ... + 2^0 (if k is even) or + 2^1 (if k is odd)
                //   is (2^(k+2)-1)/3 if k is even, or (2^(k+1)-2)/3 if k is odd.
                //   The player who takes N/2 gets sum of 2^i where i has same parity as k-1.
                //   The total coins are N. The first player gets (N - 1)/3 + 1 if N is 2^k and k is odd.
                //   The first player gets (N - 2)/3 + 2 if N is 2^k and k is even.
                //   This is complex. Let's simplify.
                //   If N is a power of 2, taking N/2 is always optimal.
                //   The total coins taken by Chanek will be N/2 + N/8 + ...
                //   The total coins taken by Opponent will be N/4 + N/16 + ...
                //   The sum of all coins is N.
                //   Chanek's share: N/2 + N/8 + ...
                //   Opponent's share: N/4 + N/16 + ...
                //   Let S_C be Chanek's share, S_O be Opponent's share.
                //   S_C = N/2 + S_O/2. S_O = N/4 + S_C/2.
                //   S_C = N/2 + (N/4 + S_C/2)/2 = N/2 + N/8 + S_C/4.
                //   3/4 * S_C = N/2 + N/8 = 5N/8.
                //   S_C = 5N/6. This is wrong.
                //   Let's re-evaluate.
                //   If N is a power of 2, say N=2^k.
                //   Chanek takes 2^(k-1). N becomes 2^(k-1).
                //   Opponent takes 2^(k-2). N becomes 2^(k-2).
                //   ...
                //   This continues until N becomes 1.
                //   The last coin (1) is taken by the player whose turn it is when N=1.
                //   The total coins taken by Chanek are 2^(k-1) + 2^(k-3) + ...
                //   The total coins taken by Opponent are 2^(k-2) + 2^(k-4) + ...
                //   The sum of these two series is N.
                //   Let S_C(k) be Chanek's coins if starting with 2^k.
                //   S_O(k) be Opponent's coins if starting with 2^k.
                //   S_C(k) = 2^(k-1) + S_O(k-1)
                //   S_O(k) = 2^(k-2) + S_C(k-2)
                //   S_C(k) + S_O(k) = 2^k.
                //   S_C(k) = 2^(k-1) + (2^(k-1) - S_C(k-1)) = 2^k - S_C(k-1).
                //   S_C(0) = 0 (N=1, Chanek takes 1, but this is for N=2^k, so k>=1)
                //   S_C(1) = 1 (N=2, Chanek takes 1, N=1, Opponent takes 1. Chanek gets 1)
                //   S_C(2) = 2^2 - S_C(1) = 4 - 1 = 3 (N=4, Chanek takes 2, N=2. Opponent takes 1, N=1. Chanek takes 1. Chanek: 2+1=3)
                //   S_C(3) = 2^3 - S_C(2) = 8 - 3 = 5 (N=8, Chanek takes 4, N=4. Opponent takes 2, N=2. Chanek takes 1, N=1. Opponent takes 1. Chanek: 4+1=5)
                //   S_C(k) = (2^k + 1)/3 if k is odd.
                //   S_C(k) = (2^k + 2)/3 if k is even.
                //   This is for the case where N is a power of 2.

                // If N is even and not a power of 2:
                // N = 2^k * M, where M is odd and M > 1.
                // Chanek's turn.
                // Option A: Take N/2. N becomes 2^(k-1) * M.
                // Option B: Take 1. N becomes 2^k * M - 1 (odd).
                // If Chanek takes 1, N becomes odd. Opponent takes 1. N becomes even.
                // This is like a sequence of (take 1, take 1) until N becomes 2^k * M - (some even number).
                // This is generally not optimal for Chanek because it gives coins to the opponent.
                // The best strategy for Chanek is to take N/2.
                // Why? Because taking N/2 leaves an even number of coins (2^(k-1) * M).
                // The opponent will then face an even number of coins.
                // If Chanek takes 1, N becomes odd. Opponent takes 1. N becomes even.
                // This means Chanek gets 1, Opponent gets 1.
                // If Chanek takes N/2, Chanek gets N/2.
                // N/2 is always greater than 1 for N > 2.
                // So Chanek should always take N/2 if N is even and N > 2.

                // This simplifies the logic:
                // If N is odd: take 1.
                // If N is even: take N/2. (Unless N=2, then take 1, which is N/2 anyway).

                // Let's re-check the example N=6.
                // Chanek's turn, N=6. Even. Take N/2 = 3. Chanek: 3. N=3.
                // Opponent's turn, N=3. Odd. Take 1. Opponent: 1. N=2.
                // Chanek's turn, N=2. Even. Take N/2 = 1. Chanek: 3+1=4. N=1.
                // Opponent's turn, N=1. Odd. Take 1. Opponent: 1+1=2. N=0.
                // Chanek: 4, Opponent: 2. Total: 6.
                // This matches the example output.

                // Let's re-check the example N=5.
                // Chanek's turn, N=5. Odd. Take 1. Chanek: 1. N=4.
                // Opponent's turn, N=4. Even. Take N/2 = 2. Opponent: 2. N=2.
                // Chanek's turn, N=2. Even. Take N/2 = 1. Chanek: 1+1=2. N=1.
                // Opponent's turn, N=1. Odd. Take 1. Opponent: 2+1=3. N=0.
                // Chanek: 2, Opponent: 3. Total: 5.
                // This matches the example output.

                // The strategy seems to be:
                // If N is odd, take 1.
                // If N is even, take N/2.

                // Let's implement this simple greedy strategy.
                if (turn == 0) { // Chanek's turn
                    chanek_coins += n / 2;
                }
                n /= 2;
            }
        }
        turn = 1 - turn; // Switch turns
    }
    return chanek_coins;
}

