int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long b_count = 0;
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % mod;
        } else { // s[i] == 'a'
            // Each 'a' needs to pass all 'b's to its right.
            // When 'a' passes one 'b', it becomes 'bba'.
            // The original 'a' is gone, but a new 'a' is created.
            // This new 'a' is effectively at the same position as the original 'a'
            // but now has one more 'b' to its right (the 'b' it just passed, plus the new 'b').
            // So, an 'a' at position i will interact with b_count 'b's to its right.
            // Each such interaction adds b_count steps.
            // After these b_count steps, the 'a' effectively becomes 'b's and one 'a'
            // which is now to the right of all original 'b's.
            // The number of 'b's to its right effectively doubles for the next 'a' to its left.
            total_steps = (total_steps + b_count) % mod;
            b_count = (b_count * 2) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];
    int days_left = d;

    for (int i = 1; i < n; ++i) {
        int pile_idx = i + 1; // 1-indexed pile number
        int haybales_in_pile = a[i];
        int days_to_move_one = i; // Cost to move from pile (i+1) to pile 1

        if (days_left <= 0) {
            break;
        }

        if (haybales_in_pile == 0) {
            continue;
        }

        // Calculate how many haybales can be moved from this pile
        // based on available days.
        // Each haybale costs 'days_to_move_one' days.
        int max_haybales_from_this_pile_by_days = days_left / days_to_move_one;

        // The actual number of haybales moved is limited by
        // what's available in the pile and what can be moved within days.
        int haybales_to_move = std::min(haybales_in_pile, max_haybales_from_this_pile_by_days);

        current_a1 += haybales_to_move;
        days_left -= haybales_to_move * days_to_move_one;
    }

    std::cout << current_a1 << std::endl;
}

