int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) { // Exclude a[i][i] which is 0
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic is derived from the problem statement:
        // For a given i, max_{j!=i} min(p_i, p_j)
        // If p_i = n, then min(p_i, p_j) = p_j. So max_{j!=i} p_j = n-1.
        // If p_i < n, then there exists some p_k > p_i.
        // For such p_k, min(p_i, p_k) = p_i.
        // For any p_j < p_i, min(p_i, p_j) = p_j.
        // So max_{j!=i} min(p_i, p_j) will be p_i.
        // This is because if p_i is not n, there must be at least one element larger than p_i.
        // If there are elements larger than p_i, say p_k, then min(p_i, p_k) = p_i.
        // If all other elements p_j are smaller than p_i, then max_{j!=i} min(p_i, p_j) = max_{j!=i} p_j.
        // But this would imply p_i is the largest, which contradicts p_i < n.
        // So, if p_i < n, there must be some p_k > p_i.
        // Thus, max_{j!=i} min(p_i, p_j) will be p_i.
        // The only exception is when p_i = n, in which case max_{j!=i} min(p_i, p_j) = n-1.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

