int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char first_char_t = s[k_actual];
        int char_code = first_char_t - 'a';

        const std::vector<int>& possible_k_values = char_indices[char_code];

        if (possible_k_values.size() == 1) {
            total_win_prob += 1.0; // k is uniquely determined
            continue;
        }

        // Vasya needs to choose an optimal position p (1 to L-1)
        // to maximize the probability of winning for this specific k_actual.
        // The probability for this k_actual is 1/L.
        // We need to find the best p that maximizes the number of unique k's.

        int max_unique_k_count = 0;

        for (int p = 1; p < L; ++p) {
            // For a fixed p, what is t[p]?
            // t[p] = s[(k_actual + p) % L]
            char second_char_t = s[(k_actual + p) % L];

            int current_unique_k_count = 0;
            for (int k_candidate : possible_k_values) {
                // Check if this k_candidate is consistent with t[0] and t[p]
                // t[0] is s[k_candidate] (already checked by being in possible_k_values)
                // t[p] is s[(k_candidate + p) % L]
                if (s[(k_candidate + p) % L] == second_char_t) {
                    current_unique_k_count++;
                }
            }
            // If only one k_candidate is consistent, Vasya wins for this k_actual and p.
            if (current_unique_k_count == 1) {
                max_unique_k_count = std::max(max_unique_k_count, 1);
                // If we found a p that guarantees a win for this k_actual, we don't need to check other p's.
                // This is because we only care if *there exists* a p that makes it unique.
                // If max_unique_k_count becomes 1, it means Vasya can win for this k_actual.
                break; 
            }
        }
        total_win_prob += static_cast<double>(max_unique_k_count);
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_balance = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // and suffix sums for the right side (jars n+1 to 2n).
    // We want to find a state where the balance of remaining jars is 0.
    // This means the balance of removed jars must be equal to the initial_balance.
    // Let S_L be the balance of jars removed from the left (1 to k).
    // Let S_R be the balance of jars removed from the right (2n-m+1 to 2n).
    // We need S_L + S_R = initial_balance.
    // We want to minimize k + m.

    // Map to store the minimum number of jars removed from the left (k)
    // to achieve a certain balance S_L.
    // Key: S_L, Value: k
    std::map<int, int> left_removed_min_k;
    left_removed_min_k[0] = 0; // 0 jars removed from left, balance 0

    int current_balance_left = 0;
    for (int k = 0; k < n; ++k) {
        if (a[n - 1 - k] == 1) { // Jars from n down to 1
            current_balance_left++;
        } else {
            current_balance_left--;
        }
        if (left_removed_min_k.find(current_balance_left) == left_removed_min_k.end()) {
            left_removed_min_k[current_balance_left] = k + 1;
        }
    }

    int min_total_removed = 2 * n; // Max possible jars removed

    // Case 1: No jars removed from the right side (m=0).
    // We need S_L = initial_balance.
    if (left_removed_min_k.count(initial_balance)) {
        min_total_removed = std::min(min_total_removed, left_removed_min_k[initial_balance]);
    }

    // Iterate through possible removals from the right side (m jars).
    // Calculate S_R and then look up required S_L = initial_balance - S_R.
    int current_balance_right = 0;
    for (int m = 0; m < n; ++m) {
        if (a[n + m] == 1) { // Jars from n+1 up to 2n
            current_balance_right++;
        } else {
            current_balance_right--;
        }

        int required_balance_left = initial_balance - current_balance_right;
        if (left_removed_min_k.count(required_balance_left)) {
            min_total_removed = std::min(min_total_removed, left_removed_min_k[required_balance_left] + (m + 1));
        }
    }

    // Case 2: No jars removed from the left side (k=0).
    // This is covered by the loop above if we consider m=0 for the right side,
    // but we need to explicitly check if initial_balance can be achieved with only right removals.
    // The loop above calculates `current_balance_right` for `m+1` jars removed.
    // We need to check if `initial_balance` can be achieved by removing `m+1` jars from the right
    // and 0 jars from the left. This means `initial_balance == current_balance_right`.
    // This is implicitly handled by `left_removed_min_k[0] = 0` and checking `required_balance_left = initial_balance - current_balance_right`.
    // If `required_balance_left` is 0, then `left_removed_min_k[0]` will give 0.
    // So, if `initial_balance == current_balance_right`, then `required_balance_left` is 0,
    // and `min_total_removed` will be updated with `0 + (m+1)`.
    // This means the initial check `if (left_removed_min_k.count(initial_balance))` covers the case where only left jars are removed.
    // The loop for `m` covers cases where both left and right jars are removed, AND where only right jars are removed (when `required_balance_left` is 0).

    std::cout << min_total_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

