int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits 0-9 are 1
    int current_or_mask = 0;    // All bits 0-9 are 0
    int current_xor_mask = 0;   // All bits 0-9 are 0

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        if (op_char == '&') {
            current_and_mask &= val;
            current_or_mask &= val;
            current_xor_mask &= val;
        } else if (op_char == '|') {
            current_and_mask |= val;
            current_or_mask |= val;
            current_xor_mask |= val;
        } else if (op_char == '^') {
            current_and_mask ^= val;
            current_or_mask ^= val;
            current_xor_mask ^= val;
        }
    }

    // Now we have the final state of (0, 1) after all operations.
    // Let f(x) be the final function.
    // f(0) = (0 & current_and_mask) | current_or_mask ^ current_xor_mask
    // f(1023) = (1023 & current_and_mask) | current_or_mask ^ current_xor_mask

    // We need to find A, B, C such that for any x in [0, 1023]:
    // (x & A) | B ^ C = (x & current_and_mask) | current_or_mask ^ current_xor_mask

    // Let's determine the final values for a bit that is initially 0 and a bit that is initially 1.
    // For an input bit 'b_in':
    // If b_in = 0, the final bit is (0 & current_and_mask_bit) | current_or_mask_bit ^ current_xor_mask_bit
    // If b_in = 1, the final bit is (1 & current_and_mask_bit) | current_or_mask_bit ^ current_xor_mask_bit

    // Let's call the result for an input bit 0 as `res_0_bit` and for an input bit 1 as `res_1_bit`.
    // `res_0_bit` = `current_or_mask_bit` ^ `current_xor_mask_bit`
    // `res_1_bit` = `current_and_mask_bit` | `current_or_mask_bit` ^ `current_xor_mask_bit`

    // We want to find A, B, C such that:
    // For input bit 0: (0 & A_bit) | B_bit ^ C_bit = B_bit ^ C_bit = res_0_bit
    // For input bit 1: (1 & A_bit) | B_bit ^ C_bit = A_bit | B_bit ^ C_bit = res_1_bit

    // From the first equation, B_bit ^ C_bit = res_0_bit.
    // Substitute this into the second equation: A_bit | res_0_bit = res_1_bit.

    // We can choose B and C. A simple choice is to set C = 0.
    // Then B_bit = res_0_bit.
    // And A_bit | res_0_bit = res_1_bit.
