    // A_bit can be 0 if res_1_bit is 0 and res_0_bit is 0.
    // A_bit can be 0 if res_1_bit is 1 and res_0_bit is 1.
    // In general, A_bit = res_1_bit & (~res_0_bit) is not quite right.
    // A_bit must be 1 if res_1_bit is 1 and res_0_bit is 0.
    // A_bit can be 0 or 1 if res_1_bit is 1 and res_0_bit is 1.
    // A_bit must be 0 if res_1_bit is 0.

    // Let's define the final A, B, C values.
    int final_A = 0;
    int final_B = 0;
    int final_C = 0;

    for (int bit = 0; bit < 10; ++bit) {
        int res_0_bit = ((current_or_mask >> bit) & 1) ^ ((current_xor_mask >> bit) & 1);
        int res_1_bit = (((current_and_mask >> bit) & 1) | ((current_or_mask >> bit) & 1)) ^ ((current_xor_mask >> bit) & 1);

        // We want (x_bit & A_bit) | B_bit ^ C_bit
        // Let's try to achieve this with at most 3 operations.
        // The general form is (x & A) | B ^ C.
        // For each bit:
        // If x_bit = 0: B_bit ^ C_bit = res_0_bit
        // If x_bit = 1: A_bit | B_bit ^ C_bit = res_1_bit

        // Case 1: res_0_bit = 0, res_1_bit = 0
        // B_bit ^ C_bit = 0  => B_bit = C_bit
        // A_bit | 0 = 0      => A_bit = 0
        // We can choose B_bit = 0, C_bit = 0. So A_bit=0, B_bit=0, C_bit=0.
        // (x_bit & 0) | 0 ^ 0 = 0. Correct.

        // Case 2: res_0_bit = 0, res_1_bit = 1
        // B_bit ^ C_bit = 0  => B_bit = C_bit
        // A_bit | 0 = 1      => A_bit = 1
        // We can choose B_bit = 0, C_bit = 0. So A_bit=1, B_bit=0, C_bit=0.
        // (x_bit & 1) | 0 ^ 0 = x_bit. Correct.

        // Case 3: res_0_bit = 1, res_1_bit = 0
        // B_bit ^ C_bit = 1  => B_bit != C_bit
        // A_bit | 1 = 0      => IMPOSSIBLE. This means A_bit must be 0 and 1 must be 0, which is false.
        // This implies that the form (x & A) | B ^ C is not general enough to represent all 4 possible (res_0_bit, res_1_bit) pairs.
        // Let's re-evaluate. The problem states "no more than 5 lines".
        // The problem is asking for a program that does the same thing.
        // The final state of a bit `b` depends on its initial state `x_b`.
        // Let `f_b(x_b)` be the final state of bit `b`.
        // There are 4 possible functions for each bit:
        // 1. f_b(0)=0, f_b(1)=0  (always 0)
        // 2. f_b(0)=0, f_b(1)=1  (identity)
        // 3. f_b(0)=1, f_b(1)=0  (NOT)
        // 4. f_b(0)=1, f_b(1)=1  (always 1)

        // Let's find which of these 4 functions each bit `i` corresponds to.
        int type = (res_0_bit << 1) | res_1_bit; // 00, 01, 10, 11

        // We can represent these 4 functions using 3 operations:
        // (x & A) | B ^ C
        //
        // Type 0 (0,0): f_b(x_b) = 0
        //   A_b=0, B_b=0, C_b=0. (x_b & 0) | 0 ^ 0 = 0.
        // Type 1 (0,1): f_b(x_b) = x_b
        //   A_b=1, B_b=0, C_b=0. (x_b & 1) | 0 ^ 0 = x_b.
        // Type 2 (1,0): f_b(x_b) = !x_b
        //   A_b=1, B_b=0, C_b=1. (x_b & 1) | 0 ^ 1 = x_b ^ 1 = !x_b.
        // Type 3 (1,1): f_b(x_b) = 1
        //   A_b=0, B_b=1, C_b=0. (x_b & 0) | 1 ^ 0 = 1.

        // So, for each bit:
        if (type == 0) { // (0,0)
            // A_b=0, B_b=0, C_b=0
        } else if (type == 1) { // (0,1)
            // A_b=1, B_b=0, C_b=0
            final_A |= (1 << bit);
        } else if (type == 2) { // (1,0)
            // A_b=1, B_b=0, C_b=1
            final_A |= (1 << bit);
            final_C |= (1 << bit);
        } else if (type == 3) { // (1,1)
            // A_b=0, B_b=1, C_b=0
            final_B |= (1 << bit);
        }
    }

    std::vector<std::pair<char, int>> ops;
    if (final_A != 1023) { // If A is not all 1s, we need an AND operation.
                           // If A is 1023, then (x & 1023) is just x for x in [0,1023].
        ops.push_back({'&', final_A});
    }
    if (final_B != 0) {
        ops.push_back({'|', final_B});
    }
    if (final_C != 0) {
        ops.push_back({'^', final_C});
    }

    std::cout << ops.size() << "\n";
    for (const auto& p : ops) {
        std::cout << p.first << " " << p.second << "\n";
    }

    return 0;
}

