// Memoization tables
// dp_val[i][0] stores the final y value if starting at x=i with an 'add' step (type 2)
// dp_val[i][1] stores the final y value if starting at x=i with a 'subtract' step (type 3)
// dp_val[i][0/1] = -2 indicates not computed yet
// dp_val[i][0/1] = -1 indicates infinite loop
std::vector<std::vector<long long>> dp_val;

// dp_next_x[i][0] stores the final x value if starting at x=i with an 'add' step (type 2)
// dp_next_x[i][1] stores the final x value if starting at x=i with a 'subtract' step (type 3)
// These are used to detect cycles and for path compression.
std::vector<std::vector<int>> dp_next_x;

// visited[i][0/1] is used during DFS to detect cycles
std::vector<std::vector<bool>> visited;

int N;
std::vector<long long> A; // A[0] is unused, A[1]...A[N] are actual values

// Recursive function to calculate the final y and x values
// current_x: the current position x
// is_add_step: true if the next operation is x = x + A[x], false if x = x - A[x]
// current_a_val: the value A[current_x] that was used to reach current_x
//                (this is important because A[x] is used in the *next* step)
std::pair<long long, int> solve(int current_x, bool is_add_step) {
    // Check for termination conditions
    if (current_x <= 0 || current_x > N) {
        return {0, current_x}; // Base case: terminated, no further y added, x is the termination point
    }

    // Check memoization table
    int step_idx = is_add_step ? 0 : 1;
    if (dp_val[current_x][step_idx] != -2) {
        return {dp_val[current_x][step_idx], dp_next_x[current_x][step_idx]};
    }

    // Detect cycle
    if (visited[current_x][step_idx]) {
        dp_val[current_x][step_idx] = -1; // Mark as infinite loop
        dp_next_x[current_x][step_idx] = -1; // Mark as infinite loop
        return {-1, -1};
    }

    visited[current_x][step_idx] = true; // Mark as currently visiting

    long long a_val = A[current_x];
    int next_x;
    long long y_added_this_step = a_val;

    if (is_add_step) {
        next_x = current_x + a_val;
    } else {
        next_x = current_x - a_val;
    }

    // Recurse for the next step (which is the opposite type)
    std::pair<long long, int> result = solve(next_x, !is_add_step);

    visited[current_x][step_idx] = false; // Unmark after visiting

    if (result.first == -1) { // If infinite loop detected in subsequent steps
        dp_val[current_x][step_idx] = -1;
        dp_next_x[current_x][step_idx] = -1;
        return {-1, -1};
    } else {
        dp_val[current_x][step_idx] = y_added_this_step + result.first;
        dp_next_x[current_x][step_idx] = result.second;
        return {dp_val[current_x][step_idx], dp_next_x[current_x][step_idx]};
    }
}

