struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line; // To mark if child has left

    Child(long long v_val, long long d_val, long long p_val, int idx)
        : v(v_val), d(d_val), p(p_val), original_idx(idx), in_line(true) {}
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children;
    children.reserve(n);
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children.emplace_back(v_val, d_val, p_val, i + 1);
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue; // This child has already left
        }

        cured_children_indices.push_back(children[i].original_idx);

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving = 0; // Accumulates d_j from children leaving due to chain reaction

        // Apply v_i effect and initial chain reaction
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry from previous children leaving
            children[j].p -= total_d_cry_from_leaving;

            // Apply current_v_cry effect
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_from_leaving += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

