            //     // If prev_val is 0, and we can reach 0, we choose 0.
            //     // If prev_val > 0, we choose current_a.
            //     // This is equivalent to: if prev_val is 0, and (m - current_a) % m <= x, then prev_val remains 0.
            //     // Else, prev_val becomes current_a.
            //     if (prev_val == 0 && (m - current_a) % m <= x) {
