            //     }
            //   Else (`(current_a + x) % m < prev_val`): // Cannot reach prev_val by wrapping
            //     prev_val = current_a; // Must use current_a
            //
            // This can be simplified.
            // We want to find the smallest `new_val` such that `new_val >= prev_val` and `new_val = (current_a + k) % m` for some `k <= x`.
            //
            // If `current_a >= prev_val`:
            //   We can always choose `new_val = current_a` (by `k=0` operations). This is valid.
            //   However, if we can achieve `prev_val` itself by incrementing `current_a` (i.e., `(prev_val - current_a + m) % m <= x`),
            //   then we can set `new_val = prev_val`. This is better (smaller or equal).
            //   So, if `(prev_val - current_a + m) % m <= x`, `prev_val` remains `prev_val`.
            //   Else, `prev_val` becomes `current_a`.
            //
            // If `current_a < prev_val`:
            //   We *must* increment `current_a`.
            //   We need `(current_a + k) % m >= prev_val` for some `k <= x`.
            //   The smallest `k` to make `current_a + k >= prev_val` (without wrapping) is `prev_val - current_a`.
            //   If `prev_val - current_a <= x`:
            //     We can set `new_val = prev_val`. So `prev_val` remains `prev_val`.
            //   Else (`prev_val - current_a > x`):
            //     We cannot reach `prev_val` without wrapping. We must wrap.
            //     This means `current_a + k >= m` for some `k <= x`.
            //     If `(current_a + x) % m < prev_val`:
            //       Even with `x` operations, we cannot reach `prev_val` by wrapping. Impossible. Return `false`.
            //     Else (`(current_a + x) % m >= prev_val`):
            //       We can reach `prev_val` by wrapping. So `prev_val` remains `prev_val`.
            //
            // This combined logic is:
            // If `current_a >= prev_val`:
            //   If `(prev_val - current_a + m) % m <= x`:
            //     // We can make `a_i` equal to `prev_val` by incrementing.
            //     // `prev_val` remains `prev_val`.
            //     continue;
            //   Else:
            //     // We cannot make `a_i` equal to `prev_val` by incrementing.
            //     // We must use `current_a` as the new value.
            //     prev_val = current_a;
            // Else (`current_a < prev_val`):
            //   If `(prev_val - current_a + m) % m <= x`:
            //     // We can make `a_i` equal to `prev_val` by incrementing.
            //     // `prev_val` remains `prev_val`.
            //     continue;
            //   Else:
            //     // We cannot make `a_i` equal to `prev_val` by incrementing.
            //     // This means it's impossible to satisfy `a_i >= prev_val`.
            //     return false;
            //
            // This is the most robust logic.

            long long diff_to_prev = (prev_val - current_a + m) % m;
            if (diff_to_prev > x) {
                // If we cannot reach prev_val by incrementing current_a by at most x,
                // then we must use current_a itself (if current_a >= prev_val).
                // If current_a < prev_val, this path means it's impossible.
                if (current_a < prev_val) {
                    return false;
                }
                // If current_a >= prev_val, we use current_a.
                prev_val = current_a;
            }
            // Else (diff_to_prev <= x), we can make current_a equal to prev_val.
            // So prev_val remains prev_val.
        } else { // current_a < prev_val
            long long diff_to_prev = (prev_val - current_a + m) % m;
            if (diff_to_prev > x) {
                // If we cannot reach prev_val by incrementing current_a by at most x,
                // then it's impossible.
                return false;
            }
            // Else (diff_to_prev <= x), we can make current_a equal to prev_val.
            // So prev_val remains prev_val.
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    std::vector<int> partition(n);

    // Case 1: All elements in one subsequence (e.g., subsequence 1).
    // No pairs are in different subsequences.
    // f(a_i, a_j) = a_i + a_j for all i, j.
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-2].value + elements[n-1].value
    // goodness = (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value)
    long long goodness1 = (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value);
    std::vector<int> best_partition(n);
    for (int i = 0; i < n; ++i) {
        best_partition[elements[i].original_index] = 1;
    }
    long long min_goodness = goodness1;

    // Case 2: Partition elements such that elements[0] is in one subsequence (e.g., 1)
    // and elements[1]...elements[n-1] are in the other (e.g., 2).
    // This is only possible if n >= 2.
    //
    // Pairs in same subsequence:
    //   - elements[i], elements[j] for i,j in [1, n-1]: f = elements[i].value + elements[j].value
    //     min_same = elements[1].value + elements[2].value (if n >= 3)
    //     max_same = elements[n-2].value + elements[n-1].value
    //   - No pairs in subsequence 1 if only elements[0] is there.
    //
    // Pairs in different subsequences:
    //   - elements[0] and elements[i] for i in [1, n-1]: f = elements[0].value + elements[i].value + h
    //     min_diff = elements[0].value + elements[1].value + h
    //     max_diff = elements[0].value + elements[n-1].value + h
    //
    // Overall min_f and max_f:
    // min_f = min(min_same, min_diff)
    // max_f = max(max_same, max_diff)

    // If n=2, elements[0] in sub1, elements[1] in sub2. Only one pair (0,1).
    // f(0,1) = elements[0].value + elements[1].value + h. min_f = max_f = this value. Goodness = 0.
    // This is covered by the general logic below.

    long long min_f_case2;
    long long max_f_case2;

    long long min_diff_val = elements[0].value + elements[1].value + h;
    long long max_diff_val = elements[0].value + elements[n-1].value + h;

    if (n == 2) {
        min_f_case2 = min_diff_val;
        max_f_case2 = max_diff_val;
    } else { // n >= 3
        long long min_same_val = elements[1].value + elements[2].value;
        long long max_same_val = elements[n-2].value + elements[n-1].value;

        min_f_case2 = std::min(min_same_val, min_diff_val);
        max_f_case2 = std::max(max_same_val, max_diff_val);
    }

    long long goodness2 = max_f_case2 - min_f_case2;

    if (goodness2 < min_goodness) {
        min_goodness = goodness2;
        best_partition[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            best_partition[elements[i].original_index] = 2;
        }
    }

    // Case 3: Partition elements such that elements[n-1] is in one subsequence (e.g., 1)
    // and elements[0]...elements[n-2] are in the other (e.g., 2).
    // This is symmetric to Case 2.
    //
    // Pairs in same subsequence:
    //   - elements[i], elements[j] for i,j in [0, n-2]: f = elements[i].value + elements[j].value
    //     min_same = elements[0].value + elements[1].value (if n >= 3)
    //     max_same = elements[n-3].value + elements[n-2].value
    //   - No pairs in subsequence 1 if only elements[n-1] is there.
    //
    // Pairs in different subsequences:
    //   - elements[n-1] and elements[i] for i in [0, n-2]: f = elements[n-1].value + elements[i].value + h
    //     min_diff = elements[0].value + elements[n-1].value + h
    //     max_diff = elements[n-2].value + elements[n-1].value + h
    //
    // Overall min_f and max_f:
    // min_f = min(min_same, min_diff)
    // max_f = max(max_same, max_diff)

    long long min_f_case3;
    long long max_f_case3;

    min_diff_val = elements[0].value + elements[n-1].value + h;
    max_diff_val = elements[n-2].value + elements[n-1].value + h;

    if (n == 2) {
        min_f_case3 = min_diff_val;
        max_f_case3 = max_diff_val;
    } else { // n >= 3
        long long min_same_val = elements[0].value + elements[1].value;
        long long max_same_val = elements[n-3].value + elements[n-2].value;

        min_f_case3 = std::min(min_same_val, min_diff_val);
        max_f_case3 = std::max(max_same_val, max_diff_val);
    }

    long long goodness3 = max_f_case3 - min_f_case3;

    if (goodness3 < min_goodness) {
        min_goodness = goodness3;
        best_partition[elements[n-1].original_index] = 1;
        for (int i = 0; i < n - 1; ++i) {
            best_partition[elements[i].original_index] = 2;
        }
    }

    // Case 4: elements[0] and elements[n-1] are in different subsequences.
    // elements[0] in sub1, elements[n-1] in sub2.
    // All other elements (elements[1]...elements[n-2]) are in sub1.
    // This is only possible if n >= 2.
    //
    // Pairs in same subsequence (sub1):
    //   - elements[0] and elements[i] for i in [1, n-2]: f = elements[0].value + elements[i].value
    //     min_same_sub1 = elements[0].value + elements[1].value (if n >= 3)
    //     max_same_sub1 = elements[0].value + elements[n-2].value (if n >= 3)
    //   - elements[i] and elements[j] for i,j in [1, n-2]: f = elements[i].value + elements[j].value
    //     min_same_sub1_mid = elements[1].value + elements[2].value (if n >= 4)
    //     max_same_sub1_mid = elements[n-3].value + elements[n-2].value (if n >= 4)
    //
    // Pairs in different subsequences:
    //   - elements[0] and elements[n-1]: f = elements[0].value + elements[n-1].value + h
    //   - elements[i] (from sub1) and elements[n-1] (from sub2) for i in [0, n-2]:
    //     f = elements[i].value + elements[n-1].value + h
    //     min_diff = elements[0].value + elements[n-1].value + h
    //     max_diff = elements[n-2].value + elements[n-1].value + h
    //
    // Overall min_f and max_f:
    // min_f = min(min_same_sub1, min_same_sub1_mid, min_diff)
    // max_f = max(max_same_sub1, max_same_sub1_mid, max_diff)

    long long min_f_case4;
    long long max_f_case4;

    min_diff_val = elements[0].value + elements[n-1].value + h;
    max_diff_val = elements[n-2].value + elements[n-1].value + h; // This is correct for n >= 2. If n=2, elements[n-2] is elements[0].

    if (n == 2) {
        min_f_case4 = min_diff_val;
        max_f_case4 = max_diff_val;
    } else { // n >= 3
        long long min_same_sub1 = elements[0].value + elements[1].value;
        long long max_same_sub1 = elements[0].value + elements[n-2].value;

        min_f_case4 = std::min(min_same_sub1, min_diff_val);
        max_f_case4 = std::max(max_same_sub1, max_diff_val);

        if (n >= 4) {
            long long min_same_sub1_mid = elements[1].value + elements[2].value;
            long long max_same_sub1_mid = elements[n-3].value + elements[n-2].value;
            min_f_case4 = std::min(min_f_case4, min_same_sub1_mid);
            max_f_case4 = std::max(max_f_case4, max_same_sub1_mid);
        }
    }

    long long goodness4 = max_f_case4 - min_f_case4;

    if (goodness4 < min_goodness) {
        min_goodness = goodness4;
        best_partition[elements[0].original_index] = 1;
        best_partition[elements[n-1].original_index] = 2;
        for (int i = 1; i < n - 1; ++i) {
            best_partition[elements[i].original_index] = 1;
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
