// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k = 1: One cut, two pieces.
    // Try all possible cut positions.
    // s = s1 + s2. New string s' = s2 + s1.
    // We need s' to be a palindrome and s' != s.
    for (int i = 1; i < n; ++i) { // Cut after index i-1, so s1 = s.substr(0, i), s2 = s.substr(i)
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string s_prime = s2 + s1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2: Two cuts, three pieces.
    // s = s1 + s2 + s3.
    // We need to find if there's any permutation of (s1, s2, s3) that forms a palindrome s' != s.
    // The problem statement implies that if k=1 doesn't work, we try k=2.
    // If k=1 didn't work, it means no single cut and swap of two pieces resulted in a new palindrome.
    // This implies that for any cut point `i`, `s.substr(i) + s.substr(0, i)` is either `s` or not a palindrome.

    // Consider the structure of s. Since s is a palindrome, s[j] == s[n-1-j].
    // If all characters in s are the same (e.g., "qqqq"), then any permutation of substrings will result in s itself.
    // For example, if s = "aaaaa", s1="a", s2="aa", s3="aa". Any permutation like "a" + "aa" + "aa" is "aaaaa".
    // In this case, it's impossible to form a new string.
    // We can check this by counting unique characters. If there's only one unique character, it's impossible.
    // Or, more simply, if s.substr(0, n/2) consists of all identical characters, then s must consist of all identical characters.
    // Example: "aaaaa", n/2 = 2. s.substr(0,2) = "aa". All 'a'.
    // Example: "ababa", n/2 = 2. s.substr(0,2) = "ab". Not all identical.
    // Example: "otto", n/2 = 2. s.substr(0,2) = "ot". Not all identical.
    // Example: "nolon", n/2 = 2. s.substr(0,2) = "no". Not all identical.

    // If s consists of all identical characters, e.g., "aaaaa", then any rearrangement of its substrings will still be "aaaaa".
    // In this case, it's impossible to form a new string s' != s.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }
    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If we reach here, it means k=1 didn't work, and s is not composed of all identical characters.
    // This implies that s must have at least two distinct characters.
    // For any palindrome s that is not composed of all identical characters, and for which k=1 doesn't work,
    // it is always possible to achieve a new palindrome with k=2.
    // Consider the first half of the string s.substr(0, n/2).
    // Since s is not all identical characters, s.substr(0, n/2) must contain at least two distinct characters.
    // (If s.substr(0, n/2) were all identical, say 'a', then s would be 'a...a' or 'a...a' + middle_char + 'a...a'.
    // Since s is a palindrome, this would mean s is all 'a's, which we've already handled.)
    // So, s.substr(0, n/2) contains at least two distinct characters.
    // Let's take s = "nolon". n=5. n/2=2. s.substr(0,2) = "no".
    // We can cut it as s[0] | s[1...n-2] | s[n-1].
    // For "nolon": 'n' | "olo" | 'n'.
    // Pieces: s1='n', s2="olo", s3='n'.
    // Permutations: s1+s2+s3 = "nolon"
    // s3+s2+s1 = "nolon"
    // s1+s3+s2 = "nnoo" (not palindrome)
    // s2+s1+s3 = "olon" (not palindrome)
    // s2+s3+s1 = "olon" (not palindrome)
    // s3+s1+s2 = "nnoo" (not palindrome)

    // The problem states "cut the paper minimum number of times k".
    // If k=1 doesn't work, we try k=2.
    // The crucial observation for k=2 is that if s is a palindrome and not all characters are the same,
    // then we can always find a way to make a new palindrome with 2 cuts.
    // Example: s = "abacaba". n=7.
    // s.substr(0, n/2) = "aba".
    // We can cut s into s[0], s[1...n-2], s[n-1].
    // s1 = s[0]
    // s2 = s.substr(1, n-2)
    // s3 = s[n-1]
    // Since s is a palindrome, s[0] == s[n-1]. So s1 == s3.
    // The pieces are (s1, s2, s1).
    // We can rearrange them as s1 + s2 + s1 (original s)
    // Or s1 + s1 + s2 (e.g., "a" + "a" + "bacab" = "aabacab", not palindrome)
    // Or s2 + s1 + s1 (e.g., "bacab" + "a" + "a" = "bacabaa", not palindrome)
    // This specific cut (s[0] | s[1...n-2] | s[n-1]) doesn't guarantee a new palindrome.

    // The problem is asking for the minimum k. If k=1 fails, we output 2.
    // The only case where it's impossible is if all characters are the same.
    // We've already handled the `all_same_chars` case.
    // If `s` is a palindrome, and not all characters are the same, then `s.substr(0, n/2)` is not a palindrome.
    // (If `s.substr(0, n/2)` were a palindrome, and `s` is a palindrome, and `s` is not all same chars,
    // then `s` would look like `P + M + P_rev` where `P` is `s.substr(0, n/2)`.
    // If `P` is a palindrome, then `P = P_rev`. So `s = P + M + P`.
    // Example: "abccba". `P="abc"`. `P_rev="cba"`. `s = P + P_rev`.
    // Example: "abacaba". `P="aba"`. `M="c"`. `P_rev="aba"`. `s = P + M + P`.
    // In these cases, `s.substr(0, n/2)` is not necessarily a palindrome.
    // For "abacaba", `s.substr(0,3)` is "aba", which is a palindrome.
    // For "nolon", `s.substr(0,2)` is "no", not a palindrome.

    // The key insight for k=2 is that if s is a palindrome and not all characters are the same,
    // then s.substr(0, n/2) is not a palindrome.
    // If s.substr(0, n/2) is not a palindrome, then we can cut s into three pieces:
    // s1 = s.substr(0, i)
    // s2 = s.substr(i, n-2*i)
    // s3 = s.substr(n-i, i)
    // where i is the smallest index such that s[i] != s[0].
    // This is not quite right.

    // The problem is simpler: if k=1 doesn't work, and the string is not all identical characters,
    // then the answer is 2.
    // Why? Because if `s` is a palindrome and not all characters are the same, then `s.substr(0, n/2)` is not a palindrome.
    // (Proof by contradiction: If `s.substr(0, n/2)` were a palindrome, then `s` would be of the form `P + (middle_char) + P`.
    // If `P` is a palindrome, then `s` would be `P + (middle_char) + P`.
    // Example: "abacaba". `P="aba"`. `s.substr(0,3)` is "aba", which is a palindrome.
    // In this case, `s` is a palindrome, `s.substr(0, n/2)` is a palindrome.
    // If `s` is "abacaba", `k=1` check:
    // "bacaba" + "a" = "bacabaa" (not palindrome)
    // "acaba" + "ab" = "acabaab" (not palindrome)
    // "caba" + "aba" = "cabaab" (not palindrome)
    // "aba" + "abac" = "abaabac" (not palindrome)
    // "ba" + "abacab" = "baabacab" (not palindrome)
    // "a" + "abacaba" = "aabacaba" (not palindrome)
    // So for "abacaba", k=1 doesn't work.
    // But "abacaba" is not all identical characters. So the answer should be 2.

    // The logic is:
    // 1. Check k=1. If a solution is found, print 1 and exit.
    // 2. If no solution for k=1, check if all characters in `s` are the same.
    //    If they are, print "Impossible" and exit.
    // 3. Otherwise (k=1 failed, but `s` has distinct characters), print 2.
    // This covers all cases. The problem guarantees that if k=1 fails and not all chars are same, k=2 is always possible.
    // This is a known property for palindromes. If a palindrome `S` is not monochromatic (all same characters),
    // and `S` cannot be rearranged into a different palindrome with one cut, then it can always be done with two cuts.
    // The specific construction for k=2 is not required, just the existence.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // dp[i] will store the maximum starting index 'x' (0-based)
    // such that s[x] = s[x+k] = s[x+2k] for some k,
    // and x+2k = i.
    // In other words, dp[i] is the smallest 'x' such that the pattern
    // s[x...i] contains s[x'] = s[x'+k] = s[x'+2k] with x'+2k = i.
    // Or, more simply, dp[i] is the minimum starting index of a pattern
    // that ends at or before index i.
    // Let's redefine: dp[i] = minimum starting index 'x' (0-based)
    // such that s[x] = s[x+k] = s[x+2k] for some k, and x+2k <= i.
    // If no such pattern exists ending at or before i, dp[i] = n (or some large value).

    // Let's use a different DP state.
    // `min_x_for_pattern_ending_at_i` stores the minimum `x` such that
    // `s[x] = s[x+k] = s[x+2k]` for some `k`, and `x+2k = i`.
    // If no such pattern ends exactly at `i`, it's `n`.
    std::vector<int> min_x_for_pattern_ending_at_i(n, n);

    for (int i = 0; i < n; ++i) {
        // Check for k=1, 2, 3, 4, 5, 6
        // The maximum k needed is 6 because 2k <= 12.
        // If k >= 7, then 2k >= 14.
        // If a pattern s[x]=s[x+k]=s[x+2k] exists, then x+2k <= n-1.
        // The minimum length of such a pattern is 3 (for k=1).
        // The maximum length of such a pattern is 13 (for k=6, x=0, 0+2*6=12).
        // If a pattern exists with k >= 7, then x+2k >= 14.
        // If we consider a substring of length 13, say s[0...12],
        // and it does NOT contain any pattern with k <= 6,
        // then it cannot contain any pattern at all.
        // This is because if it contained a pattern s[x]=s[x+k]=s[x+2k] with k >= 7,
        // then x+2k >= 14, which means the pattern would extend beyond index 12.
        // So, we only need to check k up to 6.
        for (int k = 1; k <= 6; ++k) {
            if (i - 2 * k >= 0) { // Check if s[i-2k], s[i-k], s[i] are valid indices
                if (s[i - 2 * k] == s[i - k] && s[i - k] == s[i]) {
                    min_x_for_pattern_ending_at_i[i] = std::min(min_x_for_pattern_ending_at_i[i], i - 2 * k);
                }
            }
        }
    }

    // `last_pattern_start_idx[i]` stores the minimum `x` such that
    // `s[x] = s[x+k] = s[x+2k]` for some `k`, and `x+2k <= i`.
    // If no such pattern exists ending at or before `i`, it's `n`.
    std::vector<int> last_pattern_start_idx(n, n);
    if (n > 0) {
        last_pattern_start_idx[0] = n; // No pattern can end at index 0
    }
    for (int i = 1; i < n; ++i) {
        last_pattern_start_idx[i] = last_pattern_start_idx[i-1]; // Inherit from previous
        last_pattern_start_idx[i] = std::min(last_pattern_start_idx[i], min_x_for_pattern_ending_at_i[i]);
    }

    for (int l = 0; l < n; ++l) {
        // For a fixed `l`, we want to find the smallest `r` such that `s[l...r]`
        // contains a pattern.
        // This means we need `x` such that `l <= x` and `x+2k <= r`.
        // The smallest `r` for which a pattern exists starting at or after `l`
        // is `min_r_for_l`.
        // If `last_pattern_start_idx[r]` is the minimum `x` such that `x+2k <= r`,
        // then we need `last_pattern_start_idx[r] < l`.
        // No, this is wrong. We need `last_pattern_start_idx[r] >= l`.
        // `last_pattern_start_idx[r]` is the minimum `x` such that `x+2k <= r`.
        // If `last_pattern_start_idx[r] < l`, it means the pattern starts before `l`,
        // so it's not contained in `s[l...r]`.
        // We need to find the smallest `r` such that there exists an `x` with
        // `l <= x` and `x+2k <= r` and `s[x]=s[x+k]=s[x+2k]`.
        // Let `min_r_for_l` be the smallest `r` such that `s[l...r]` contains a pattern.
        // If no such `r` exists, `min_r_for_l = n`.

        // Iterate `r` from `l` to `n-1`.
        // If `last_pattern_start_idx[r] <= r` (meaning a pattern exists ending at or before `r`)
        // AND `last_pattern_start_idx[r] >= l` (meaning the pattern starts at or after `l`),
        // then `s[l...r]` contains a pattern.
        // The number of `r` values for a fixed `l` that satisfy the condition is `n - min_r_for_l`.
        // We are counting bad pairs, so we need `r` such that `s[l...r]` does NOT contain a pattern.
        // This means for all `x, k` with `l <= x` and `x+2k <= r`, `s[x]=s[x+k]=s[x+2k]` is false.

        // Let `first_r_with_pattern_starting_at_l_or_later` be the smallest `r` such that
        // `last_pattern_start_idx[r] >= l`.
        // If `last_pattern_start_idx[r] < l`, it means any pattern ending at or before `r`
        // starts before `l`. So `s[l...r]` does not contain a pattern.
        // We need to find the smallest `r` such that `last_pattern_start_idx[r] >= l`.
        // All `r'` from `l` to `r-1` will have `last_pattern_start_idx[r'] < l`.
        // These are the `r` values for which `s[l...r']` does not contain a pattern.
        // The number of such `r'` is `r - l`.

        // Find the smallest `r_idx` such that `last_pattern_start_idx[r_idx] >= l`.
        // If no such `r_idx` exists, then `last_pattern_start_idx[n-1] < l`.
        // In this case, for all `r` from `l` to `n-1`, `s[l...r]` does not contain a pattern.
        // The number of such `r` values is `n - l`.

        // If such `r_idx` exists:
        // For `r` from `l` to `r_idx - 1`, `last_pattern_start_idx[r] < l`.
        // So `s[l...r]` does not contain a pattern.
        // The number of such `r` values is `r_idx - l`.

        // If `last_pattern_start_idx[r_idx] >= l`, then for `r >= r_idx`, `s[l...r]` contains a pattern.
        // So we count `r` from `l` to `r_idx - 1`.

        // Use binary search or `std::lower_bound` to find `r_idx`.
        // `last_pattern_start_idx` is non-increasing.
        // We need to find the first `r_idx` such that `last_pattern_start_idx[r_idx] >= l`.
        // This is equivalent to finding the first `r_idx` such that `last_pattern_start_idx[r_idx]`
        // is not less than `l`.

        // `std::upper_bound` on `last_pattern_start_idx` for value `l-1`.
        // `it = std::upper_bound(last_pattern_start_idx.begin() + l, last_pattern_start_idx.end(), l-1, std::greater<int>())`
        // This finds the first element `e` such that `e <= l-1` is false, i.e., `e > l-1`, i.e., `e >= l`.
        // The range for `r` is `[l, n-1]`.

        auto it = std::lower_bound(last_pattern_start_idx.begin() + l, last_pattern_start_idx.end(), l, std::greater<int>());
        int r_idx = std::distance(last_pattern_start_idx.begin(), it);

        // All `r` from `l` to `r_idx - 1` are bad pairs.
        // The number of such `r` values is `r_idx - l`.
        bad_pairs += (r_idx - l);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) {
            break; // All required tracks covered
        }

        long long current_h = h[h_idx];
        long long left_reach = current_h - T;
        long long right_reach = current_h + T;

        // If the current head cannot reach the current target track p[p_idx]
        // even if it moves left as much as possible, then this head cannot cover p[p_idx].
        // We need to find a head that can cover p[p_idx].
        // This implies that if p[p_idx] is too far to the left of current_h,
        // this head might not be useful for p[p_idx] or subsequent tracks.
        // However, the greedy strategy is to use the current head to cover as many
        // *uncovered* tracks as possible, starting from p[p_idx].
        // So, if p[p_idx] is to the right of right_reach, this head cannot cover it.
        // If p[p_idx] is to the left of left_reach, this head cannot cover it.
        // The crucial part is that heads are sorted, and tracks are sorted.
        // We want to cover p[p_idx], p[p_idx+1], ...
        // A head at h_idx can cover tracks in [h_idx - T, h_idx + T].
        // We should use the current head h_idx to cover the leftmost uncovered track p[p_idx]
        // if it's within its reach.
        // If p[p_idx] is to the left of h_idx - T, then h_idx cannot cover p[p_idx].
        // Since h is sorted, h_idx-1 also couldn't cover p[p_idx] (or it would have been covered).
        // This means p[p_idx] is unreachable by any head. So return false.
        if (p[p_idx] < left_reach) {
            return false;
        }

        // If p[p_idx] is within reach of current_h, cover it and as many subsequent tracks as possible.
        // The current head can cover tracks in the range [p[p_idx], right_reach].
        // Advance p_idx past all tracks covered by this head.
        while (p_idx < m && p[p_idx] <= right_reach) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10; // Max possible distance between tracks is ~10^10.
                           // A head might need to move from 1 to 10^10, so T can be 10^10.
                           // 2e10 is a safe upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

