        }

        // The reversed permutation will always have the same fingerprint.
        // We need to ensure it's a different permutation.
        // A permutation is different from its reverse if it's not a palindrome.
        // For n >= 2, a permutation [p_1, ..., p_n] is a palindrome if p_i = p_{n-i+1} for all i.
        // If p is a palindrome, then p_1 = p_n, p_2 = p_{n-1}, etc.
        // However, a permutation consists of distinct integers from 1 to n.
        // If n >= 2, p_1 cannot be equal to p_n unless n=1 (which is not allowed, n>=2).
        // For example, if p_1 = p_n, then p_1 appears twice, which is not a permutation.
        // Therefore, for n >= 2, p_1 is always different from p_n.
        // This means p is never a palindrome.
        // So, reversing p will always produce a different permutation p'.

        for (int i = n - 1; i >= 0; --i) {
            std::cout << p[i] << (i == 0 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

