void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number that satisfies the conditions.
        // The number will start with '2' and be followed by '3's.
        // Example: 23, 233, 2333, ...
        //
        // Let s be such a number.
        // The digits are 2 and 3.
        // We need s not to be divisible by 2 and not to be divisible by 3.
        //
        // If s starts with 2 and is followed by (n-1) threes:
        // s = 2 * 10^(n-1) + 3 * (10^(n-2) + ... + 10^0)
        //
        // Divisibility by 2:
        // The last digit of s is 3, which is odd. So s is not divisible by 2.
        //
        // Divisibility by 3:
        // The sum of digits of s is 2 + (n-1)*3.
        // If s is divisible by 3, then 2 + (n-1)*3 must be divisible by 3.
        // 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
        // For 3n - 1 to be divisible by 3, -1 must be divisible by 3, which is false.
        // So, s is never divisible by 3.
        //
        // Therefore, a number consisting of '2' followed by (n-1) '3's
        // satisfies all conditions for n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

