        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_R_pos = 0; // Represents the last position where the frog could land and jump right.
                            // Initially, the frog is at 0, which allows jumping right.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If we encounter an 'R' at index i (cell i+1),
                // the gap between this 'R' and the previous 'R' (or start 0)
                // is (i+1) - last_R_pos.
                // The frog must be able to jump over this gap.
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update last_R_pos to the current 'R' cell
            }
        }

        // After iterating through the string, we need to consider the gap
        // from the last 'R' cell to the target cell n+1.
        // The last_R_pos now holds the index of the last 'R' cell (or 0 if no 'R's).
        // The distance to n+1 from last_R_pos is (n + 1) - last_R_pos.
        max_gap = std::max(max_gap, (n + 1) - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

