    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            int val;
            std::cin >> val;
            if (val > max_val_in_row) {
                max_val_in_row = val;
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1 and no element is n.
    // This happens if the original permutation contained n, and its row's max was n-1.
    // In this case, the element corresponding to n should be changed from n-1 to n.
    bool found_n_minus_1 = false;
    for (int val : p) {
        if (val == n - 1) {
            found_n_minus_1 = true;
            break;
        }
    }

    if (!found_n_minus_1) {
        // This means all p[i] values are less than n-1, or some are n.
        // If there's no n-1, it implies that the original permutation did not contain n-1.
        // This is impossible for a permutation of 1 to n.
        // The only way max_val_in_row could be less than n-1 for all rows
        // is if n itself was not present in the permutation, which is also impossible.
        // The problem guarantees a solution exists.
        // The logic for p[i] = max(a[i][j]) for j!=i works for all p[i] < n.
        // If p[k] = n, then a[k][j] = p[j] for all j!=k.
        // So max(a[k][j]) for j!=k would be max(p[j] for j!=k) = n-1.
        // So, if n is in the permutation, one of the p[i] values computed will be n-1.
        // If n-1 is not found, it means that the original permutation did not contain n.
        // This implies that the maximum value in the permutation is less than n.
        // This is a contradiction since it's a permutation of 1 to n.
        // Therefore, there must be at least one n-1 in the computed p.
        // If there are multiple n-1s, it means multiple elements were n in the original permutation,
        // which is impossible.
        // So, there must be exactly one n-1 in the computed p.
        // This n-1 corresponds to the position where n was in the original permutation.
        // We need to change this n-1 to n.
        // The problem statement guarantees a solution exists.
        // The only case where max_val_in_row is not p[i] is when p[i] = n.
        // In that case, max_val_in_row is n-1.
        // So, if we find an n-1 in our computed p, it must be the position of n.
        // If there are no n-1s, it means n was not in the permutation, which is impossible.
        // So, there must be at least one n-1.
        // If there are multiple n-1s, it means multiple elements were n, which is impossible.
        // So, there is exactly one n-1.
        // This n-1 should be changed to n.
        // This logic is flawed. The problem states "if there is any p[j] such that p[j] > p[i]".
        // If p[i] = n, then there is no p[j] > p[i]. So max(a[i][j]) = max(p[j] for j!=i) = n-1.
        // If p[i] < n, then there is always some p[j] > p[i] (unless p[i] = n-1 and n is not present, but n is always present).
        // So, if p[i] < n, then max(a[i][j]) = p[i].
        // This means that all p[i] < n will be correctly identified.
        // The only element that is not correctly identified is p[k] = n, which will be identified as n-1.
        // So, the computed `p` will contain all values from 1 to n-1, but one of them will be duplicated (the one that was originally n-1),
        // and the value n will be missing, replaced by n-1.
        // Example: n=3, p={1,2,3}.
        // p[0]=1 -> max(a[0][j]) = 1
        // p[1]=2 -> max(a[1][j]) = 2
        // p[2]=3 -> max(a[2][j]) = max(p[0], p[1]) = max(1,2) = 2
        // So computed p = {1,2,2}.
        // We need to find the value that appears twice (2 in this case) and change one of its occurrences to n (3).
        // The value that appears twice is n-1.
        // So, we find the first occurrence of n-1 and change it to n.
        // This is the correct logic.

        // Find the first occurrence of n-1 and change it to n.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; // Only one such position exists
            }
        }
    }


    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

