int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams 'k' is limited by three factors:
        // 1. The total number of students available: 3 * k <= c + m + x
        // 2. The number of coders available: k <= c
        // 3. The number of mathematicians available: k <= m
        // So, k <= min(c, m, (c + m + x) / 3)
        // This gives an upper bound for k.
        // We can binary search for the maximum k that satisfies the conditions.
        // The search space for k is from 0 to 10^8 (max possible value for c, m, x).

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3}); // Initial upper bound
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians.
            // The remaining students (c - mid) coders, (m - mid) mathematicians, and x non-specialized
            // must be enough to fill the remaining 'mid' slots in each team.
            // Each team needs 3 members. 'mid' teams need 3 * mid members.
            // 'mid' coders and 'mid' mathematicians are already accounted for.
            // So, we need (3 * mid - mid - mid) = mid additional members.
            // These additional members can come from remaining coders, mathematicians, or non-specialized students.
            // Total available for these 'mid' additional slots: (c - mid) + (m - mid) + x

            if (c >= mid && m >= mid && (c - mid) + (m - mid) + x >= mid) {
                // It's possible to form 'mid' teams
                ans = mid;
                low = mid + 1;
            } else {
                // Not possible to form 'mid' teams
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

