            continue;
        }

        // Calculate the sum of last digits for the first 10 multiples of m
        // This is one full cycle of last digits
        long long sum_first_10 = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_first_10 += (static_cast<long long>(i) * m) % 10;
        }

        // Number of full cycles of 10 multiples
        long long num_cycles = count / 10;
        long long total_sum = num_cycles * sum_first_10;

        // Add the sum of remaining multiples
        long long remaining_multiples = count % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm> // For std::min and std::max

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the 0-indexed position of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1] at pos[1].
        // min_idx and max_idx are both pos[1]. Length is 1.
        // For m > 1, we expand the segment to include 'm'.
        // The new segment must contain all numbers from 1 to m.
        // This means it must contain the number 'm'.
        // We update current_min_idx and current_max_idx to cover the range
        // from the minimum index of {1, ..., m-1} to the maximum index of {1, ..., m-1},
        // and also include the index of 'm'.

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // is a permutation of 1, ..., m.
        // This means its length must be exactly m.
        // The length of the current segment is (current_max_idx - current_min_idx + 1).
        if ((current_max_idx - current_min_idx + 1) == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

