        }
        std::sort(a.begin(), a.end());

        // The median of the first class will be a[n-1]
        // The median of the second class will be a[n]
        // This is because if we take the smallest n elements for one class
        // and the largest n elements for the other,
        // the median of the first class (size 2k+1) is b_{k+1}.
        // For n elements, the median is a[n-1] (0-indexed).
        // For the remaining n elements, the median is a[n] (0-indexed).
        // This partition is always possible:
        // Class 1: {a_0, a_1, ..., a_{n-1}}
        // Class 2: {a_n, a_{n+1}, ..., a_{2n-1}}
        // Both classes have size n.
        // If n is odd, then both classes have odd size.
        // The median of Class 1 is a_{(n-1)/2}.
        // The median of Class 2 is a_{n + (n-1)/2}.
        // This is not what the problem implies.
        // The problem implies that the total number of students is 2n.
        // We need to pick n students for one class and n students for another.
        // No, the problem says "each class has odd number of students".
        // The number of students in classes may be equal or different.
        // The total number of students is 2n.
        // Let the sizes be S1 and S2. S1+S2 = 2n. S1, S2 are odd.
        // The smallest possible odd size is 1.
        // The largest possible odd size is 2n-1.
        //
        // Consider the sorted array a_0, a_1, ..., a_{2n-1}.
        // The key insight is that to minimize the difference between medians,
        // we should pick the medians as close as possible in the sorted global array.
        //
        // If we pick a_i as the median of Class A, and a_j as the median of Class B.
        // For a_i to be a median of a class of size 2k+1, there must be k elements <= a_i
        // and k elements >= a_i in that class.
        //
        // The optimal strategy is to pick the two middle elements of the sorted array
        // as the medians of the two classes.
        // These are a[n-1] and a[n].
        //
        // Can we always form two classes with odd sizes such that a[n-1] is the median of one
        // and a[n] is the median of the other?
        //
        // Let Class A have median a[n-1].
        // Let Class B have median a[n].
        //
        // Class A:
        // We need to pick some elements for Class A.
        // We must include a[n-1].
        // We need to pick k_A elements from a[0]...a[n-2] (or smaller than a[n-1])
        // and k_A elements from a[n]...a[2n-1] (or larger than a[n-1]).
        //
        // Class B:
        // We must include a[n].
        // We need to pick k_B elements from a[0]...a[n-1] (or smaller than a[n])
        // and k_B elements from a[n+1]...a[2n-1] (or larger than a[n]).
        //
        // Consider the partition:
        // Class A: {a_0, a_1, ..., a_{n-1}}
        // Class B: {a_n, a_{n+1}, ..., a_{2n-1}}
        //
        // If n is odd:
        // Class A has size n. Median is a_{(n-1)/2}.
        // Class B has size n. Median is a_{n + (n-1)/2}.
        // The difference is |a_{n + (n-1)/2} - a_{(n-1)/2}|.
        // This is not necessarily a[n] - a[n-1].
        //
        // The problem statement implies that the median of 2k+1 elements is b_{k+1}.
        // For a sorted array of 2n elements, a_0, ..., a_{2n-1}.
        // The elements a_{n-1} and a_n are the two "middle" elements.
        //
        // We can always form a class of size 1 with median a[n-1] and another class of size 2n-1 with median a[n].
        // Or vice versa.
        //
        // Let's try to make a[n-1] the median of one class and a[n] the median of the other.
        //
        // Class 1: {a_0, a_1, ..., a_{n-1}}
        // Class 2: {a_n, a_{n+1}, ..., a_{2n-1}}
        //
        // This is a valid partition if n is odd.
        // In this case, the median of Class 1 is a_{(n-1)/2}.
        // The median of Class 2 is a_{n + (n-1)/2}.
        //
        // The example for n=3 (2n=6 students): 1 2 3 4 5 6
        // Sorted: 1 2 3 4 5 6
        // n=3.
        // a[n-1] = a[2] = 3.
        // a[n] = a[3] = 4.
        // The answer is |4-3|=1.
        //
        // The example for n=1 (2n=2 students): 1 1
        // Sorted: 1 1
        // n=1.
        // a[n-1] = a[0] = 1.
        // a[n] = a[1] = 1.
        // The answer is |1-1|=0.
        //
        // The example for n=5 (2n=10 students): 2 3 4 5 8 13 13 16 17 20
        // Sorted: 2 3 4 5 8 13 13 16 17 20
        // n=5.
        // a[n-1] = a[4] = 8.
        // a[n] = a[5] = 13.
        // The answer is |13-8|=5.
        //
        // It seems the answer is always a[n] - a[n-1].
        //
        // Let's prove this.
        // We want to minimize |median(C1) - median(C2)|.
        // Let the sorted array be $a_0, a_1, \dots, a_{2n-1}$.
        //
        // Consider any partition into two classes $C_1$ and $C_2$ with odd sizes.
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        //
        // Suppose $m_1 < m_2$.
        // For $m_1$ to be the median of $C_1$, there must be at least $(|C_1|-1)/2$ elements in $C_1$ that are $\le m_1$
        // and at least $(|C_1|-1)/2$ elements in $C_1$ that are $\ge m_1$.
        //
        // Similarly for $m_2$.
        //
        // The total number of elements less than or equal to $m_1$ in the entire set is at least $(|C_1|-1)/2 + 1 = (|C_1|+1)/2$ (including $m_1$ itself).
        // The total number of elements greater than or equal to $m_2$ in the entire set is at least $(|C_2|-1)/2 + 1 = (|C_2|+1)/2$ (including $m_2$ itself).
        //
        // The number of elements in the original sorted array $a$ that are $\le m_1$ is at least $(|C_1|+1)/2$.
        // The number of elements in the original sorted array $a$ that are $\ge m_2$ is at least $(|C_2|+1)/2$.
        //
        // The index of $m_1$ in the sorted full array $a$ must be at least $(|C_1|-1)/2$.
        // The index of $m_2$ in the sorted full array $a$ must be at most $2n - 1 - ((|C_2|-1)/2)$.
        //
        // Let $m_1 = a_i$ and $m_2 = a_j$.
        //
        // The number of elements $a_k \le a_i$ is $i+1$.
        // So, $i+1 \ge (|C_1|+1)/2$. This means $i \ge (|C_1|-1)/2$.
        //
        // The number of elements $a_k \ge a_j$ is $2n-j$.
        // So, $2n-j \ge (|C_2|+1)/2$. This means $j \le 2n - (|C_2|+1)/2$.
        //
        // We know $|C_1| + |C_2| = 2n$.
        //
        // $i \ge (|C_1|-1)/2$.
        // $j \le 2n - (|C_2|+1)/2 = 2n - (2n - |C_1| + 1)/2 = 2n - n + (|C_1|-1)/2 = n + (|C_1|-1)/2$.
        //
        // So, $j - i \le n + (|C_1|-1)/2 - (|C_1|-1)/2 = n$. This is not useful.
        //
        // Let's use a different argument.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        //
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // Assume $m_1 \le m_2$.
        //
        // The number of elements in $C_1$ that are $\le m_1$ is $(|C_1|+1)/2$.
        // The number of elements in $C_2$ that are $\le m_2$ is $(|C_2|+1)/2$.
        //
        // All elements $a_0, \dots, a_{n-1}$ are less than or equal to $a_{n-1}$.
        // All elements $a_n, \dots, a_{2n-1}$ are greater than or equal to $a_n$.
        //
        // The total count of elements in the entire array that are less than or equal to $m_1$ is at least $(|C_1|+1)/2$.
        // This means $m_1$ must be at least $a_{(|C_1|-1)/2}$.
        //
        // The total count of elements in the entire array that are greater than or equal to $m_2$ is at least $(|C_2|+1)/2$.
        // This means $m_2$ must be at most $a_{2n - 1 - ((|C_2|-1)/2)}$.
        //
        // Let $k_1 = (|C_1|-1)/2$ and $k_2 = (|C_2|-1)/2$.
        // $m_1 \ge a_{k_1}$.
        // $m_2 \le a_{2n - 1 - k_2}$.
        //
        // We want to minimize $m_2 - m_1$.
        // So we want to make $m_1$ as large as possible and $m_2$ as small as possible.
        //
        // The smallest possible value for $m_2$ is $a_{k_1+k_2+1}$ if $m_1$ and $m_2$ are consecutive.
        //
        // The total number of elements is $2n$.
        // The number of elements in $C_1$ is $2k_1+1$.
        // The number of elements in $C_2$ is $2k_2+1$.
        // $(2k_1+1) + (2k_2+1) = 2n \implies 2k_1 + 2k_2 + 2 = 2n \implies k_1 + k_2 + 1 = n$.
        //
        // So, $m_1 \ge a_{k_1}$.
        // $m_2 \le a_{2n - 1 - k_2} = a_{2n - 1 - (n - 1 - k_1)} = a_{2n - 1 - n + 1 + k_1} = a_{n + k_1}$.
        //
        // So we have $m_1 \ge a_{k_1}$ and $m_2 \le a_{n+k_1}$.
        //
        // The minimum possible difference $m_2 - m_1$ is achieved when $m_1$ is as large as possible and $m_2$ is as small as possible.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        //
        // The element $a_{n-1}$ is the $(n)$-th element (1-indexed).
        // The element $a_n$ is the $(n+1)$-th element (1-indexed).
        //
        // We can construct Class A with elements $\{a_0, \dots, a_{n-1}\}$ and Class B with elements $\{a_n, \dots, a_{2n-1}\}$.
        // This is a valid partition if $n$ is odd.
        // In this case, median(A) = $a_{(n-1)/2}$ and median(B) = $a_{n + (n-1)/2}$.
        // The difference is $a_{n + (n-1)/2} - a_{(n-1)/2}$.
        //
        // What if $n$ is even?
        // If $n$ is even, then $2n$ is a multiple of 4.
        // For example, $n=2$, $2n=4$. Students $a_0, a_1, a_2, a_3$.
        // We need two classes of odd size. Possible sizes: (1,3) or (3,1).
        // If sizes are (1,3):
        // Class A: $\{a_i\}$, median $a_i$.
        // Class B: $\{a_j, a_k, a_l\}$, median $a_k$.
        //
        // The problem statement is very simple: "the median of the array $[a_1, a_2, \dots, a_{2k+1}]$ of odd number of elements is defined as follows: let $[b_1, b_2, \dots, b_{2k+1}]$ be the elements of the array in the sorted order. Then median of this array is equal to $b_{k+1}$."
        // This means for an array of size $S$, the median is the element at index $(S-1)/2$ (0-indexed).
        //
        // The crucial observation is that the $n$-th smallest element ($a_{n-1}$ in 0-indexed sorted array) and the $(n+1)$-th smallest element ($a_n$ in 0-indexed sorted array) are the "middle" two elements.
        //
        // We can always form two classes such that $a_{n-1}$ is the median of one and $a_n$ is the median of the other.
        //
        // Consider Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$ and Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This partition is valid if $n$ is odd.
        // In this case, median(Class 1) = $a_{(n-1)/2}$ and median(Class 2) = $a_{n + (n-1)/2}$.
        //
        // What if $n$ is even?
        // For example, $n=2$, $2n=4$. Sorted array $a_0, a_1, a_2, a_3$.
        // $a_{n-1} = a_1$, $a_n = a_2$.
        // We need to form two classes of odd sizes. Possible sizes are (1,3).
        //
        // Let Class A be $\{a_1\}$. Median is $a_1$.
        // Let Class B be $\{a_0, a_2, a_3\}$. Median is $a_2$.
        // The difference is $|a_2 - a_1|$.
        // This works for $n=2$.
        //
        // Let's generalize this.
        // We can always form Class A with median $a_{n-1}$ and Class B with median $a_n$.
        //
        // Class A: $\{a_{n-1}\}$ (size 1). Median is $a_{n-1}$.
        // Class B: $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$ (size $2n-1$).
        // The elements for Class B are all elements except $a_{n-1}$.
        // The median of Class B (size $2n-1$) is the $((2n-1)-1)/2 = (n-1)$-th element (0-indexed) of its sorted list.
        // The sorted list for Class B is $a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}$.
        // The $(n-1)$-th element in this list is $a_n$.
        // So, median(Class B) is $a_n$.
        //
        // This construction always works:
        // Class A: $\{a_{n-1}\}$ (size 1, which is odd). Median is $a_{n-1}$.
        // Class B: All other $2n-1$ students. (size $2n-1$, which is odd).
        // The students in Class B are $a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}$.
        // When sorted, these are $a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}$.
        // The median of Class B (size $2n-1$) is the element at index $((2n-1)-1)/2 = n-1$ in its sorted list.
        // The element at index $n-1$ in the sorted list of Class B is $a_n$.
        //
        // So, we can always achieve a difference of $|a_n - a_{n-1}|$.
        //
        // Can we do better?
        // Let $m_1$ and $m_2$ be the medians of the two classes, with $m_1 \le m_2$.
        // Let $|C_1|$ and $|C_2|$ be their sizes. Both are odd.
        // Let $k_1 = (|C_1|-1)/2$ and $k_2 = (|C_2|-1)/2$.
        // So $|C_1| = 2k_1+1$ and $|C_2| = 2k_2+1$.
        // Total students $2n = (2k_1+1) + (2k_2+1) = 2k_1 + 2k_2 + 2$.
        // This implies $n = k_1 + k_2 + 1$.
        //
        // For $m_1$ to be the median of $C_1$, there must be at least $k_1$ elements in $C_1$ that are $\le m_1$ (excluding $m_1$ itself).
        // And at least $k_1$ elements in $C_1$ that are $\ge m_1$ (excluding $m_1$ itself).
        //
        // For $m_2$ to be the median of $C_2$, there must be at least $k_2$ elements in $C_2$ that are $\le m_2$ (excluding $m_2$ itself).
        // And at least $k_2$ elements in $C_2$ that are $\ge m_2$ (excluding $m_2$ itself).
        //
        // Consider the elements $a_0, \dots, a_{2n-1}$.
        // The element $m_1$ must be one of $a_i$.
        // The element $m_2$ must be one of $a_j$.
        //
        // The number of elements in the full array that are $\le m_1$ must be at least $k_1+1$.
        // So $m_1 \ge a_{k_1}$.
        //
        // The number of elements in the full array that are $\ge m_2$ must be at least $k_2+1$.
        // So $m_2 \le a_{2n - (k_2+1)} = a_{2n - k_2 - 1}$.
        //
        // We know $k_2 = n - k_1 - 1$.
        // So $m_2 \le a_{2n - (n - k_1 - 1) - 1} = a_{2n - n + k_1 + 1 - 1} = a_{n + k_1}$.
        //
        // So we have $m_1 \ge a_{k_1}$ and $m_2 \le a_{n+k_1}$.
        //
        // The difference $m_2 - m_1 \ge a_{k_1} - a_{n+k_1}$ (this is wrong, it should be $m_2 - m_1 \ge a_{k_1} - a_{n+k_1}$ if $a_{n+k_1}$ is smaller than $a_{k_1}$, but $a$ is sorted).
        //
        // We have $m_1 \ge a_{k_1}$ and $m_2 \ge m_1$.
        // Also $m_2 \le a_{n+k_1}$.
        //
        // So $m_2 - m_1 \ge a_{k_1} - a_{n+k_1}$ is not useful.
        //
        // We need to show that $m_2 - m_1 \ge a_n - a_{n-1}$.
        //
        // The elements $a_0, \dots, a_{k_1}$ are $k_1+1$ elements.
        // The elements $a_{n+k_1}, \dots, a_{2n-1}$ are $2n - (n+k_1) = n-k_1$ elements.
        //
        // The elements $a_0, \dots, a_{n-1}$ are $n$ elements.
        // The elements $a_n, \dots, a_{2n-1}$ are $n$ elements.
        //
        // The total number of elements less than $m_2$ is at least $k_1 + k_2 + 1 = n$.
        // This means $m_2$ must be at least $a_n$.
        //
        // The total number of elements greater than $m_1$ is at least $k_1 + k_2 + 1 = n$.
        // This means $m_1$ must be at most $a_{n-1}$.
        //
        // So, $m_1 \le a_{n-1}$ and $m_2 \ge a_n$.
        // Therefore, $m_2 - m_1 \ge a_n - a_{n-1}$.
        //
        // This proves that the minimum possible difference is $a_n - a_{n-1}$.
        // And we showed a construction that achieves this difference.
        //
        // The construction is:
        // Class A: $\{a_{n-1}\}$ (size 1). Median is $a_{n-1}$.
        // Class B: $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$ (size $2n-1$). Median is $a_n$.
        // Both sizes 1 and $2n-1$ are odd. This is always a valid partition.
        //
        // So the algorithm is:
        // 1. Read $n$.
        // 2. Read $2n$ skill levels into a vector.
        // 3. Sort the vector.
        // 4. The answer is $a[n] - a[n-1]$. (using 0-indexed vector)

        std::cout << a[n] - a[n-1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // First, ensure the median element itself is s
    operations += std::abs(a[median_idx] - s);

    // Ensure elements to the left of the median are <= s
    // If a[i] > s for i < median_idx, we must decrease it to s.
    // The cost is a[i] - s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Ensure elements to the right of the median are >= s
    // If a[i] < s for i > median_idx, we must increase it to s.
    // The cost is s - a[i].
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
