int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int b_ptr = 0; // Pointer for elements to be placed (the 'b' array elements)
    int a_ptr = 0; // Pointer for original positions (the 'a' array elements)

    while (b_ptr < n && a_ptr < n) {
        // We want to find an element a[b_ptr] to place at position a[a_ptr]
        // such that a[b_ptr] > a[a_ptr].
        // Since both arrays are sorted, if a[b_ptr] > a[a_ptr],
        // this is a valid match. We increment both pointers and count it.
        // If a[b_ptr] <= a[a_ptr], then a[b_ptr] cannot be placed at a[a_ptr]
        // to satisfy the condition. Also, a[b_ptr] cannot be placed at any
        // subsequent position a[a_ptr+k] because a[a_ptr+k] >= a[a_ptr] >= a[b_ptr].
        // So, a[b_ptr] is too small for the current a[a_ptr] and any subsequent a[a_ptr+k].
        // We must try a larger element from the 'b' array, so we increment b_ptr.
        if (a[b_ptr] > a[a_ptr]) {
            count++;
            b_ptr++;
            a_ptr++;
        } else {
            b_ptr++; // Try a larger element from 'b' for the current 'a_ptr' position
        }
    }

    std::cout << count << std::endl;

    return 0;
}

