// Function to check if Box 1 can be the special box
bool can_be_box1(long long A, long long B, long long C, long long D) {
    // Box 1: (-inf, -1]
    // Requires a negative value with magnitude >= 1.

    // Case 1: Final product is negative.
    // This means the total number of negative factors (A+B) must be odd.
    if ((A + B) % 2 == 1) {
        // We need to ensure the magnitude can be >= 1.
        // If there's at least one toy in Box 1 or Box 4, we can achieve magnitude >= 1.
        // If all toys are from Box 2 and Box 3, the magnitude will always be < 1.
        if (A > 0 || D > 0) {
            return true;
        }
        // If A=0 and D=0, all toys are from Box 2 and Box 3.
        // The product of any number of toys from Box 2 and Box 3 will have magnitude < 1.
        // So, if (A+B) is odd, and A=0, D=0, the result will be in Box 2.
        // Thus, if A=0 and D=0, Box 1 is not possible.
        return false;
    }
    // Case 2: Final product is positive.
    // This means the total number of negative factors (A+B) must be even.
    // To get a negative result, we need to introduce an odd number of negative factors.
    // This is only possible if we can "change" the parity of negative factors.
    // However, the problem states we are looking for the final product.
    // If the final product is positive, it cannot be in Box 1.
    // So, if (A+B) is even, Box 1 is not possible.
    return false;
}

// Function to check if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // Box 2: (-1, 0)
    // Requires a negative value with magnitude < 1.

    // Case 1: Final product is negative.
    // This means the total number of negative factors (A+B) must be odd.
    if ((A + B) % 2 == 1) {
        // We need to ensure the magnitude can be < 1.
        // This is always possible if there's at least one toy in Box 2 or Box 3.
        // If all toys are from Box 1 and Box 4, and A+B is odd, the magnitude will be >= 1.
        // So, if B > 0 or C > 0, we can achieve magnitude < 1.
        if (B > 0 || C > 0) {
            return true;
        }
        // If B=0 and C=0, all toys are from Box 1 and Box 4.
        // If (A+B) is odd, and B=0, C=0, then A must be odd.
        // The product of toys from Box 1 and Box 4 will have magnitude >= 1.
        // So, if B=0 and C=0, Box 2 is not possible.
        return false;
    }
    // Case 2: Final product is positive.
    // If (A+B) is even, Box 2 is not possible.
    return false;
}

// Function to check if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // Box 3: (0, 1)
    // Requires a positive value with magnitude < 1.

    // Case 1: Final product is positive.
    // This means the total number of negative factors (A+B) must be even.
    if ((A + B) % 2 == 0) {
        // We need to ensure the magnitude can be < 1.
        // This is always possible if there's at least one toy in Box 2 or Box 3.
        // If all toys are from Box 1 and Box 4, and A+B is even, the magnitude will be >= 1.
        // So, if B > 0 or C > 0, we can achieve magnitude < 1.
        if (B > 0 || C > 0) {
            return true;
        }
        // If B=0 and C=0, all toys are from Box 1 and Box 4.
        // If (A+B) is even, and B=0, C=0, then A must be even.
        // The product of toys from Box 1 and Box 4 will have magnitude >= 1.
        // So, if B=0 and C=0, Box 3 is not possible.
        return false;
    }
    // Case 2: Final product is negative.
    // If (A+B) is odd, Box 3 is not possible.
    return false;
}

// Function to check if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // Box 4: [1, inf)
    // Requires a positive value with magnitude >= 1.

    // Case 1: Final product is positive.
    // This means the total number of negative factors (A+B) must be even.
    if ((A + B) % 2 == 0) {
        // We need to ensure the magnitude can be >= 1.
        // This is always possible if there's at least one toy in Box 1 or Box 4.
        // If all toys are from Box 2 and Box 3, the magnitude will always be < 1.
        // So, if A > 0 or D > 0, we can achieve magnitude >= 1.
        if (A > 0 || D > 0) {
            return true;
        }
        // If A=0 and D=0, all toys are from Box 2 and Box 3.
        // If (A+B) is even, and A=0, D=0, then B must be even.
        // The product of toys from Box 2 and Box 3 will have magnitude < 1.
        // So, if A=0 and D=0, Box 4 is not possible.
        return false;
    }
    // Case 2: Final product is negative.
    // If (A+B) is odd, Box 4 is not possible.
    return false;
}

