#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_ops: minimum value a[i] must have to be part of an increasing sequence ending at a[i]
    // a[0] must be at least 0
    // a[1] must be at least 1
    // a[i] must be at least i
    // So, a[i] must be >= i for it to be possible to form 0, 1, ..., i
    // If a[i] < i, it's impossible to make a[i] = i.
    // We can only decrease a[i], so if a[i] < i, we can't make it i.
    // The actual value we need is a[i] >= i.
    // Let's check if a[i] >= i for all i from 0 to n-1.
    // This is for the increasing part.
    // For the decreasing part, a[i] must be >= (n-1-i).
    // We need to find a peak k such that a[i] >= i for i < k and a[i] >= (n-1-i) for i > k.
    // And a[k] must be >= k and a[k] must be >= (n-1-k).
    // More precisely, a[i] must be at least i for the increasing part (0-indexed).
    // And a[i] must be at least (n-1-i) for the decreasing part (0-indexed).

    // Check if it's possible to form the increasing part up to some point
    // For each i, we need a[i] >= i. If not, it's impossible to make a[i] = i.
    // The actual value we need for a[i] is at least i.
    // Let's find the first index `i` from the left where `a[i] < i`.
    // If such an `i` exists, then `a[0], ..., a[i]` cannot be `0, 1, ..., i`.
    // So, the increasing part cannot extend beyond `i-1`.
    // Let `left_limit` be the maximum index `j` such that `a[0], ..., a[j]` can be made `0, 1, ..., j`.
    // This means `a[p] >= p` for all `0 <= p <= j`.
    int left_limit = n - 1;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            left_limit = i - 1;
            break;
        }
    }

    // Check if it's possible to form the decreasing part from some point
    // For each i, we need a[i] >= (n-1-i). If not, it's impossible to make a[i] = (n-1-i).
    // Let `right_limit` be the minimum index `j` such that `a[j], ..., a[n-1]` can be made `(n-1-j), ..., 0`.
    // This means `a[p] >= (n-1-p)` for all `j <= p <= n-1`.
    int right_limit = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            right_limit = i + 1;
            break;
        }
    }

    // If there is any index `k` such that `right_limit <= k <= left_limit`,
    // then we can choose `k` as the peak.
    // For such a `k`, we have:
    // 1. `a[i] >= i` for `0 <= i <= k` (from `left_limit` check)
    // 2. `a[i] >= (n-1-i)` for `k <= i <= n-1` (from `right_limit` check)
    // This means we can form `0, 1, ..., k` and `k, k-1, ..., 0` (relative to the peak).
    // The peak value `a[k]` must be at least `k` (for the increasing part) AND at least `(n-1-k)` (for the decreasing part).
    // The condition `right_limit <= left_limit` ensures that there is at least one such `k`.
    // If `right_limit <= left_limit`, then there exists an index `k` such that `a[k] >= k` AND `a[k] >= (n-1-k)`.
    // This is because `left_limit` is the largest index `j` such that `a[p] >= p` for `p <= j`.
    // And `right_limit` is the smallest index `j` such that `a[p] >= (n-1-p)` for `p >= j`.
    // If `right_limit <= left_limit`, then for any `k` in `[right_limit, left_limit]`:
    // `a[k] >= k` (because `k <= left_limit`)
    // `a[k] >= (n-1-k)` (because `k >= right_limit`)
    // So, we can make `a[0]'=0, a[1]'=1, ..., a[k]'=k` and `a[k]'=k, a[k+1]'=k-1, ..., a[n-1]'=0`.
    // The peak value `a[k]'` would be `k`.
    // This is possible if `a[k] >= k`.
    // The conditions `a[i] >= i` for `i <= k` and `a[i] >= (n-1-i)` for `i >= k` are sufficient.

    if (right_limit <= left_limit) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

