#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> is_suffix_perm(n + 1, false);

    // Check prefixes
    std::vector<bool> seen_prefix(n + 1, false);
    int max_val_prefix = 0;
    bool distinct_prefix = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] > n || seen_prefix[a[i]]) { // a[i] > n is an optimization, max_val_prefix check will catch it
            distinct_prefix = false;
        }
        if (distinct_prefix) {
            seen_prefix[a[i]] = true;
            max_val_prefix = std::max(max_val_prefix, a[i]);
            if (max_val_prefix == i + 1) { // If max value seen so far is equal to current length, it's a permutation candidate
                is_prefix_perm[i + 1] = true;
            }
        }
    }

    // Check suffixes
    std::vector<bool> seen_suffix(n + 1, false);
    int max_val_suffix = 0;
    bool distinct_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        int current_len = n - i;
        if (a[i] > n || seen_suffix[a[i]]) { // a[i] > n is an optimization, max_val_suffix check will catch it
            distinct_suffix = false;
        }
        if (distinct_suffix) {
            seen_suffix[a[i]] = true;
            max_val_suffix = std::max(max_val_suffix, a[i]);
            if (max_val_suffix == current_len) { // If max value seen so far is equal to current length, it's a permutation candidate
                is_suffix_perm[current_len] = true;
            }
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

