        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }

        // If all counts are 0 (empty string, not possible by constraints n>=1),
        // or if there's only one character and it's not R, P, S (not possible by constraints),
        // this logic would need adjustment. But for valid inputs, one of R, P, S will have max_count.
        // If n=1, say s="R", then counts['R']=1, max_count=1, most_frequent_bot_move='R'.
        // If n=1, say s="S", then counts['S']=1, max_count=1, most_frequent_bot_move='S'.

        char optimal_player_move = get_winning_move(most_frequent_bot_move);

        for (size_t i = 0; i < s.length(); ++i) {
