        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // Condition for a good array: sum = 2 * xor_sum
    // If current_sum == 2 * current_xor_sum, the array is already good.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
        return;
    }

    // We need to append elements x1, x2, ... such that:
    // (current_sum + x1 + x2 + ...) = 2 * (current_xor_sum ^ x1 ^ x2 ^ ...)

    // Strategy: Append at most 2 elements.
    // Let's try to append two elements, say X and Y.
    // The new sum will be S' = current_sum + X + Y
    // The new XOR sum will be X' = current_xor_sum ^ X ^ Y
    // We want S' = 2 * X'

    // Consider appending X = current_xor_sum.
    // New XOR sum becomes current_xor_sum ^ current_xor_sum = 0.
    // New sum becomes current_sum + current_xor_sum.
    // Now we need (current_sum + current_xor_sum + Y) = 2 * (0 ^ Y)
    // (current_sum + current_xor_sum + Y) = 2 * Y
    // current_sum + current_xor_sum = Y
    // So, Y = current_sum + current_xor_sum.

    // This strategy appends two elements:
    // b1 = current_xor_sum
    // b2 = current_sum + current_xor_sum
    // Let's verify:
    // New sum = current_sum + b1 + b2
    //         = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    //         = 2 * (current_sum + current_xor_sum)
    // New XOR sum = current_xor_sum ^ b1 ^ b2
    //             = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    //             = 0 ^ (current_sum + current_xor_sum)
    //             = current_sum + current_xor_sum
    // The condition S' = 2 * X' becomes:
    // 2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum)
    // This is always true.

    // The problem statement guarantees that a solution always exists by appending at most 3 elements.
    // This strategy uses 2 elements.
    // The values can be large, up to 10^9 for initial elements.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
    // b2 = current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long (10^18).

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << (current_sum + current_xor_sum) << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

