int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_val, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_val, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs that have both same x and same y (i.e., are identical points)
    // These pairs were counted twice: once for same x, once for same y.
    // They should only be counted once.
    for (auto const& [point, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually interact with this 'b'.
            // Each such 'a' will contribute 'count_a' steps to pass this 'b'.
            // When an 'a' passes a 'b', it becomes 'bba'.
            // The 'a' effectively moves past the 'b', and a new 'b' is created.
            // This new 'b' will be to the left of the original 'a' (now 'bba').
            // So, the number of 'a's that need to pass subsequent 'b's effectively doubles.
            // The 'count_a' represents the number of 'a's that are currently "active"
            // and need to pass 'b's to their right.
            // When an 'a' passes a 'b', it consumes 1 step.
            // The 'count_a' 'a's will each pass this 'b'.
            // So, 'count_a' steps are added to total_steps.
            // After these 'count_a' 'a's pass this 'b', they effectively become
            // 'count_a' 'b's and 'count_a' 'a's (the original 'a's).
            // The 'count_a' 'a's are now to the right of this 'b'.
            // The 'count_a' 'b's are to the left of this 'b'.
            // The crucial part is that each 'a' that passes this 'b' also creates a new 'b'.
            // This new 'b' will be to the left of the 'a' that created it.
            // The 'a's that are currently active (represented by `count_a`)
            // will interact with this 'b'.
            // Each such 'a' will contribute `count_a` to the total steps.
            // The number of 'a's that need to pass subsequent 'b's effectively doubles.
            // This is because each 'a' that passes this 'b' will itself become 'bba'.
            // The 'a' part of 'bba' will then need to pass any further 'b's.
            // The 'b' part of 'bba' is a new 'b' that is now to the left of the 'a'.
            // The 'count_a' 'a's that are to the left of the current 'b' will each
            // perform an operation with this 'b'.
            // Each such operation adds 1 to the total steps.
            // So, `total_steps += count_a`.
            // After these operations, each of the `count_a` 'a's has effectively
            // moved past this 'b' and created a new 'b'.
            // The number of 'a's that are now to the left of this 'b' (and need to pass
            // any 'b's further to the left) has effectively doubled.
            // So, `count_a = (count_a * 2) % mod`.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is now active
            // and needs to pass any 'b's to its right.
            // So, we increment the count of active 'a's.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
