// Function to convert a number to its parity pattern string
// The pattern is always 18 characters long, padded with '0's on the left.
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's to make it 18 characters long
    while (pattern.length() < 18) {
        pattern += '0';
    }
    std::reverse(pattern.begin(), pattern.end()); // Reverse to get correct order
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's on the left to 18 characters
            std::string padded_s = s;
            while (padded_s.length() < 18) {
                padded_s = '0' + padded_s;
            }
            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w assuming all '1's

    // Step 1: Determine necessary '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then both w[i-x] and w[i+x] (if they exist) must be '0'.
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    // Construct a candidate s_prime from w
    std::string s_prime(n, '0');
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        // Check w[i-x]
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        // Check w[i+x]
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_prime[i] = '1';
        }
    }

    // Compare s_prime with the given s
    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

