#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let i be the number of items taken from the left (0 <= i <= n)
    // Then n-i items are taken from the right
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += (prefix_sum[i] - prefix_sum[0]) * l;

        // Energy for items taken from the right
        // Items from right are w[i]...w[n-1]
        // If i items are taken from left, then items w[0]...w[i-1] are taken.
        // The remaining items are w[i]...w[n-1].
        // We take n-i items from the right, which are w[n-(n-i)]...w[n-1] = w[i]...w[n-1].
        // This means the items taken from the right are w[n-(n-i)]...w[n-1].
        // The sum of weights for items taken from the right is prefix_sum[n] - prefix_sum[i].
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for imbalance
        int left_count = i;
        int right_count = n - i;

        if (left_count > right_count) {
            // More items taken from left. The last item taken must have been from the left.
            // The difference is (left_count - right_count).
            // We need to add Ql for each extra item from the left, except the first one.
            // So, (left_count - right_count - 1) * Ql if left_count > right_count.
            // This is equivalent to (left_count - right_count - 1) * Ql if left_count > right_count + 1.
            // If left_count == right_count + 1, no penalty.
            // If left_count > right_count + 1, penalty is (left_count - right_count - 1) * Ql.
            // This can be simplified to max(0, left_count - right_count - 1) * Ql.
            current_energy += std::max(0, left_count - right_count - 1) * Ql;
        } else if (right_count > left_count) {
            // More items taken from right. The last item taken must have been from the right.
            // The difference is (right_count - left_count).
            // We need to add Qr for each extra item from the right, except the first one.
            // So, (right_count - left_count - 1) * Qr if right_count > left_count.
            // This is equivalent to (right_count - left_count - 1) * Qr if right_count > left_count + 1.
            // If right_count == left_count + 1, no penalty.
            // If right_count > left_count + 1, penalty is (right_count - left_count - 1) * Qr.
            // This can be simplified to max(0, right_count - left_count - 1) * Qr.
            current_energy += std::max(0, right_count - left_count - 1) * Qr;
        }
        // If left_count == right_count, no penalty.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

