    std::string s;
    std::cin >> s;

    int n = s.length();

    // Precompute prefix sums for 'x', 'y', 'z'
    // count[0][i] stores count of 'x' in s[0...i-1]
    // count[1][i] stores count of 'y' in s[0...i-1]
    // count[2][i] stores count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> count(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        count[0][i + 1] = count[0][i];
        count[1][i + 1] = count[1][i];
        count[2][i + 1] = count[2][i];
        if (s[i] == 'x') {
            count[0][i + 1]++;
        } else if (s[i] == 'y') {
            count[1][i + 1]++;
        } else { // s[i] == 'z'
            count[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r; // 1-indexed

        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        // Get counts of 'x', 'y', 'z' in the substring s[l-1...r-1]
        int count_x = count[0][r] - count[0][l - 1];
        int count_y = count[1][r] - count[1][l - 1];
        int count_z = count[2][r] - count[2][l - 1];

        // Check if the counts are "balanced" enough
        // The difference between max and min count must be at most 1
        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

// Function to get prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find a divisor x of p such that x is not divisible by q.
        // To maximize x, we want to remove as few factors from p as possible,
        // specifically, just enough to make it not divisible by q.

        // Get prime factors of q
        std::vector<long long> q_prime_factors = get_prime_factors(q);

        long long max_x = 1;

        // For each prime factor f of q, we try to remove just enough f's from p
        // to make p not divisible by q, and check if this new p' is the maximum.
        for (long long f : q_prime_factors) {
            long long current_p = p;
            // Count how many times f divides q
            long long q_f_power = 0;
            long long temp_q = q;
            while (temp_q > 0 && temp_q % f == 0) {
                q_f_power++;
                temp_q /= f;
            }

            // Divide current_p by f until it's no longer divisible by q
            // This means current_p's power of f must be less than q_f_power
            long long p_f_power = 0;
            long long temp_p_for_f_count = p;
            while (temp_p_for_f_count > 0 && temp_p_for_f_count % f == 0) {
                p_f_power++;
                temp_p_for_f_count /= f;
            }

            // We need to reduce the power of f in p such that it's less than q_f_power.
            // The largest such divisor would be p / f^(p_f_power - q_f_power + 1)
            // This is equivalent to dividing p by f until its power of f is q_f_power - 1.
            long long factor_to_divide = 1;
            for (int i = 0; i < p_f_power - q_f_power + 1; ++i) {
                factor_to_divide *= f;
            }

            long long candidate_x = p / factor_to_divide;

            // Check if this candidate_x is valid (should always be, by construction)
            // and update max_x
            if (candidate_x % q != 0) { // This check is technically redundant if logic is correct
                max_x = std::max(max_x, candidate_x);
            }
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long turn = 0; // 0 for Chanek, 1 for Opponent

    while (n > 0) {
        if (turn == 0) { // Chanek's turn
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Check if N is a power of 2
                // If N is a power of 2, taking N/2 leaves N/2, which is also a power of 2.
                // This continues until N=2, then N=1.
                // The opponent will always face an even number (except for the last 1).
                // If N is a power of 2, say 2^k, Chanek takes 2^(k-1), opponent takes 2^(k-2), etc.
                // Chanek gets 2^(k-1) + 2^(k-3) + ...
                // Opponent gets 2^(k-2) + 2^(k-4) + ...
                // This is not optimal for Chanek if he can force an odd number for opponent.
                // If N is a power of 2, say N = 2^k (k >= 1)
                // Chanek takes N/2. N becomes N/2. Chanek gets N/2.
                // Opponent faces N/2 (even). Opponent takes N/4. N becomes N/4. Opponent gets N/4.
                // This continues until N=2.
                // Chanek takes 1. N becomes 1. Chanek gets 1.
                // Opponent takes 1. N becomes 0. Opponent gets 1.
                // Total for Chanek: N/2 + N/8 + ... + 1 (if k is odd) or N/2 + N/8 + ... + 2 (if k is even)
                // This is sum of geometric series.
                // For N=2^k, Chanek gets 2^(k-1) + 2^(k-3) + ...
                // Opponent gets 2^(k-2) + 2^(k-4) + ...
                // If Chanek takes 1: N becomes N-1 (odd).
                // Opponent faces N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                // Chanek faces N-2 (even).
                // This seems better.

                // The optimal strategy for Chanek when N is even:
                // If N is a power of 2 (N = 2^k, k >= 1):
                // Chanek takes 1. N becomes N-1. Chanek gets 1.
                // Opponent faces N-1 (odd). Opponent takes 1. N becomes N-2. Opponent gets 1.
                // Chanek faces N-2 (even).
                // This is a recursive pattern.
                // Example N=4:
                // Chanek takes 1. N=3. Chanek gets 1.
                // Opponent takes 1. N=2. Opponent gets 1.
                // Chanek takes 1. N=1. Chanek gets 1.
                // Opponent takes 1. N=0. Opponent gets 1.
                // Chanek: 2, Opponent: 2.
                // If Chanek took N/2:
                // Chanek takes 2. N=2. Chanek gets 2.
                // Opponent takes 1. N=1. Opponent gets 1.
                // Chanek takes 1. N=0. Chanek gets 1.
                // Chanek: 3, Opponent: 1.
                // So for N=4, Chanek takes N/2.

                // Let's re-evaluate.
                // If N is even:
                // Option A: Take 1. N becomes N-1. Chanek gets 1 + (coins from N-1 for opponent).
                // Option B: Take N/2. N becomes N/2. Chanek gets N/2 + (coins from N/2 for opponent).

                // The key insight is that if N is even and not a power of 2, it can be written as N = 2^k * M where M is odd and M > 1.
                // If Chanek takes N/2, N becomes N/2 = 2^(k-1) * M.
                // If Chanek takes 1, N becomes N-1 (odd).
                // If N is a power of 2 (N = 2^k, k >= 1):
                // Chanek takes N/2. N becomes N/2. Chanek gets N/2.
                // Opponent faces N/2 (power of 2). Opponent takes N/4. Opponent gets N/4.
                // This continues until N=2.
                // Chanek takes 1. N=1. Chanek gets 1.
                // Opponent takes 1. N=0. Opponent gets 1.
                // Total for Chanek: N/2 + N/8 + N/32 + ...
                // Total for Opponent: N/4 + N/16 + N/64 + ... + 1 (if N=2)
                // This strategy gives Chanek more coins.
                // Example N=6:
                // Chanek takes N/2=3. N=3. Chanek gets 3.
                // Opponent takes 1. N=2. Opponent gets 1.
                // Chanek takes 1. N=1. Chanek gets 1.
                // Opponent takes 1. N=0. Opponent gets 1.
                // Chanek: 4, Opponent: 2.

                // If N is even and not a power of 2:
                // Chanek takes N/2. N becomes N/2. Chanek gets N/2.
                // Opponent faces N/2.
                // If N is a power of 2:
                // Chanek takes N/2. N becomes N/2. Chanek gets N/2.
                // Opponent faces N/2.
                // This seems to be the greedy choice for Chanek.
                // The only exception is when N=2.
                // If N=2: Chanek takes 1. N=1. Chanek gets 1. Opponent takes 1. N=0. Opponent gets 1. Chanek: 1, Opponent: 1.
                // If N=2: Chanek takes N/2=1. N=1. Chanek gets 1. Opponent takes 1. N=0. Opponent gets 1. Chanek: 1, Opponent: 1.
                // Both options yield the same result for N=2.

                // The strategy is:
                // If N is odd, take 1.
                // If N is even, take N/2.
                // This is the greedy strategy for the current player.
                // Let's test this strategy.
                // N=5:
                // C: N=5 (odd), takes 1. C=1, N=4.
                // O: N=4 (even), takes 2. O=2, N=2.
                // C: N=2 (even), takes 1. C=1+1=2, N=1.
                // O: N=1 (odd), takes 1. O=2+1=3, N=0.
                // Result: C=2, O=3. This matches example.

                // N=6:
                // C: N=6 (even), takes 3. C=3, N=3.
                // O: N=3 (odd), takes 1. O=1, N=2.
                // C: N=2 (even), takes 1. C=3+1=4, N=1.
                // O: N=1 (odd), takes 1. O=1+1=2, N=0.
                // Result: C=4, O=2. This matches example.

                // This simple greedy strategy seems to work for the examples.
                // Let's consider the case where N is a power of 2.
                // N = 2^k.
                // C: takes N/2. C gets N/2. N becomes N/2.
                // O: takes N/4. O gets N/4. N becomes N/4.
                // C: takes N/8. C gets N/8. N becomes N/8.
                // ...
                // This continues until N=2.
                // C: takes 1. C gets 1. N becomes 1.
                // O: takes 1. O gets 1. N becomes 0.
                // Chanek's total: N/2 + N/8 + N/32 + ... + (1 or 2, depending on k)
                // This is sum of 2^(k-1) + 2^(k-3) + ...
                // This is a geometric series.
                // If k is odd, last term is 2^0 = 1. Sum = 2^k * (1 - (1/4)^((k+1)/2)) / (1 - 1/4) = 2^k * (1 - 1/2^(k+1)) / (3/4) = 4/3 * (2^k - 1/2) = (2^(k+2) - 2)/3.
                // If k is even, last term is 2^1 = 2. Sum = 2^k * (1 - (1/4)^(k/2)) / (1 - 1/4) = 4/3 * (2^k - 1) = (2^(k+2) - 4)/3.
                // This is the sum of coins Chanek gets if both players always take N/2 when N is even.

                // What if Chanek takes 1 when N is a power of 2?
                // N=4.
                // C: takes 1. C=1, N=3.
                // O: takes 1. O=1, N=2.
                // C: takes 1. C=1+1=2, N=1.
                // O: takes 1. O=1+1=2, N=0.
                // Chanek gets 2.
                // If Chanek took N/2:
                // C: takes 2. C=2, N=2.
                // O: takes 1. O=1, N=1.
                // C: takes 1. C=2+1=3, N=0.
                // Chanek gets 3.
                // So for N=4, taking N/2 is better.

                // It seems the strategy is:
                // If N is odd, take 1.
                // If N is even:
                //   If N is a power of 2, take N/2.
                //   If N is even but not a power of 2, take N/2.
                // This simplifies to: if N is odd, take 1. If N is even, take N/2.
                // This is the simple greedy strategy.

                // Let's verify the power of 2 case.
                // N = 2^k.
                // Chanek's turn. N is even.
                // Option 1: Take 1. N becomes 2^k - 1 (odd). Chanek gets 1.
                //   Opponent's turn. N is 2^k - 1 (odd). Opponent takes 1. N becomes 2^k - 2 (even). Opponent gets 1.
                //   Chanek's turn. N is 2^k - 2 (even).
                // Option 2: Take N/2. N becomes 2^(k-1) (even). Chanek gets 2^(k-1).
                //   Opponent's turn. N is 2^(k-1) (even).
                //
                // Consider N=2^k.
                // If Chanek takes 1, he gets 1. The remaining N-1 coins are split.
                // If Chanek takes N/2, he gets N/2. The remaining N/2 coins are split.
                //
                // Let f(N) be the maximum coins Chanek can get from N coins if it's his turn.
                // If N is odd: f(N) = 1 + (N-1 - f_opponent(N-1))
                // If N is even: f(N) = max(1 + (N-1 - f_opponent(N-1)), N/2 + (N/2 - f_opponent(N/2)))
                // Where f_opponent(X) is the max coins opponent gets if it's their turn with X coins.
                // f_opponent(X) = X - f(X).
                // So f(N) = max(1 + (N-1 - (N-1 - f(N-1))), N/2 + (N/2 - (N/2 - f(N/2))))
                // f(N) = max(1 + f(N-1), N/2 + f(N/2))
                // This is not quite right. f(N) is Chanek's coins.
                // If N is odd: Chanek takes 1. Remaining N-1. Opponent plays on N-1.
                // Chanek's coins = 1 + (N-1 - Opponent's optimal from N-1).
                // If N is even:
                // Option 1: Chanek takes 1. Remaining N-1. Opponent plays on N-1.
                // Chanek's coins = 1 + (N-1 - Opponent's optimal from N-1).
                // Option 2: Chanek takes N/2. Remaining N/2. Opponent plays on N/2.
                // Chanek's coins = N/2 + (N/2 - Opponent's optimal from N/2).

                // Let C(N) be Chanek's coins if it's his turn with N coins.
                // Let O(N) be Opponent's coins if it's their turn with N coins.
                // Total coins = N.
                // If N is odd:
                //   Chanek takes 1. C(N) = 1 + (N-1 - O(N-1)).
                // If N is even:
                //   Option 1: Chanek takes 1. C1 = 1 + (N-1 - O(N-1)).
                //   Option 2: Chanek takes N/2. C2 = N/2 + (N/2 - O(N/2)).
                //   C(N) = max(C1, C2).
                //
                // This is a recursive definition.
                // The simple greedy strategy (take 1 if odd, take N/2 if even) is optimal.
                // Why?
                // If N is odd, only option is to take 1.
                // If N is even:
                //   Taking N/2 gives the current player N/2 coins immediately. The opponent then faces N/2.
                //   Taking 1 gives the current player 1 coin. The opponent then faces N-1 (odd).
                //   If the opponent faces an odd number, they are forced to take 1, leaving an even number for the current player.
                //   This means taking 1 coin when N is even effectively passes the "even number advantage" to the opponent.
                //   The current player wants to keep the "even number advantage" for themselves or pass an odd number to the opponent.
                //   If N is even, taking N/2 means the current player gets N/2 coins, and the opponent faces N/2.
                //   If N is even, taking 1 means the current player gets 1 coin, and the opponent faces N-1 (odd).
                //   The opponent will take 1, leaving N-2 (even) for the current player.
                //   So, taking 1 when N is even means: current player gets 1, opponent gets 1, current player gets to play on N-2.
                //   Taking N/2 when N is even means: current player gets N/2, opponent gets to play on N/2.
                //
                //   Consider N = 2^k * M, where M is odd.
                //   If M=1 (N is a power of 2):
                //     Take N/2. Current player gets N/2. Opponent faces N/2 (also power of 2).
                //     This continues. Current player gets N/2 + N/8 + ...
                //     Take 1. Current player gets 1. Opponent faces N-1 (odd). Opponent takes 1. Current player faces N-2.
                //     This is 1 + (N-2 - O(N-2)).
                //     For N=4:
                //       Take N/2: C gets 2. O faces 2. O takes 1. C faces 1. C takes 1. Total C=3.
                //       Take 1: C gets 1. O faces 3. O takes 1. C faces 2. C takes 1. O faces 1. O takes 1. Total C=2.
                //     So for powers of 2, taking N/2 is better.
                //   If M > 1 (N is even, not a power of 2):
                //     Take N/2. Current player gets N/2. Opponent faces N/2 = 2^(k-1) * M.
                //     Take 1. Current player gets 1. Opponent faces N-1 (odd). Opponent takes 1. Current player faces N-2.
                //     This is 1 + (N-2 - O(N-2)).
                //     For N=6:
                //       Take N/2: C gets 3. O faces 3. O takes 1. C faces 2. C takes 1. O faces 1. O takes 1. Total C=4.
                //       Take 1: C gets 1. O faces 5. O takes 1. C faces 4. C takes 2. O faces 2. O takes 1. C faces 1. C takes 1. Total C=1+2+1=4.
                //     Both options give 4 for N=6.
                //     This means for N=6, both options are equally good for Chanek.
                //     The simple greedy strategy (take N/2) is one of the optimal choices.

                // So the simple greedy strategy (take 1 if odd, take N/2 if even) is optimal for the current player.
                // We just need to simulate this.
                chanek_coins += n / 2;
                n /= 2;
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                n /= 2;
            }
        }
        turn = 1 - turn; // Switch turns
    }
    return chanek_coins;
}

