#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int p = 0; p <= 9; ++p) {
        std::string coloring(n, ' ');
        char last1 = '0' - 1; // Sentinel for the last digit colored 1
        char last2 = '0' - 1; // Sentinel for the last digit colored 2
        bool possible_p = true;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < (p + '0')) {
                // Must be color 1
                if (current_digit < last1) {
                    possible_p = false;
                    break;
                }
                coloring[i] = '1';
                last1 = current_digit;
            } else if (current_digit > (p + '0')) {
                // Must be color 2
                if (current_digit < last2) {
                    possible_p = false;
                    break;
                }
                coloring[i] = '2';
                last2 = current_digit;
            } else { // current_digit == (p + '0')
                // Can be color 1 or 2
                // Try to put it in color 2 if possible, to keep color 1 digits small
                if (current_digit >= last2) {
                    coloring[i] = '2';
                    last2 = current_digit;
                } else if (current_digit >= last1) {
                    coloring[i] = '1';
                    last1 = current_digit;
                } else {
                    possible_p = false;
                    break;
                }
            }
        }

        if (possible_p) {
            std::cout << coloring << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_part
    long long sum_r_part;
    if (b == 1) { // If b=1, then r must be 0, but r!=0 is required. So no nice integers.
        sum_r_part = 0;
    } else {
        sum_r_part = (b - 1);
        sum_r_part = (sum_r_part * b) / 2;
        sum_r_part %= MOD; // sum_r_part can be large, but it's not multiplied by MOD yet.
                           // The division by 2 is exact.
    }

    // Sum of (k * b + 1) from k=1 to a
    // This is sum_k_part
    // sum_{k=1 to a} (k * b + 1) = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a + 1) / 2) + a
    long long sum_k_part;
    long long sum_k_val = (a * (a + 1)) / 2; // sum_{k=1 to a} k
    sum_k_val %= MOD;

    sum_k_part = (b % MOD * sum_k_val) % MOD; // b * sum_{k=1 to a} k
    sum_k_part = (sum_k_part + a) % MOD;      // + a

    // Total sum = (sum_r_part * sum_k_part) % MOD
    long long total_sum = (sum_r_part * sum_k_part) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <algorithm>
#include <numeric>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];
        adj[c1].insert(c2);
        adj[c2].insert(c1);
        used_in_s.insert(c1);
        used_in_s.insert(c2);
    }
    if (s.length() == 1) {
        used_in_s.insert(s[0]);
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::set<char> visited_in_layout;
    char start_char = '\0';

    // Find a starting character for the path (degree 1 in the required adjacencies)
    for (char c : used_in_s) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }
    // If no degree 1 node, it means all nodes have degree 0 or 2.
    // If all nodes have degree 2, it's a cycle.
    // If all nodes have degree 0, it means s has only one character or is empty (not possible by constraints).
    // If s has only one character, start_char will be that character.
    if (start_char == '\0' && !used_in_s.empty()) {
        // All characters in s must have degree 2, forming a cycle.
        // This is problematic for a linear keyboard.
        // However, if s has only one character, it will be handled by the next block.
        // If s has multiple characters and all have degree 2, it means it's a cycle.
        // A cycle cannot be represented on a linear keyboard unless it's a single edge (2 nodes).
        // But if it's a single edge, the nodes would have degree 1.
        // So, if start_char is still null and used_in_s is not empty, it means there's a cycle of length >= 3.
        // Example: abcda -> a-b, b-c, c-d, d-a. All have degree 2.
        // This cannot be put on a linear keyboard.
        // Exception: if used_in_s has only one character, it means s has length 1.
        // In this case, start_char would be that character.
        // So, if start_char is null and used_in_s is not empty, it implies a cycle of length >= 3.
        // This is impossible.
        // Example: "abacaba" -> a-b, a-c. b-a, c-a.
        // a has degree 2 (b,c), b has degree 1 (a), c has degree 1 (a).
        // Start with b or c.
        // If s = "abc", a-b, b-c. a has deg 1, c has deg 1, b has deg 2. Start with a or c.
        // If s = "ab", a-b. a has deg 1, b has deg 1. Start with a or b.
        // The only case where start_char is null and used_in_s is not empty is if all characters in used_in_s have degree 2.
        // This means they form a cycle. A cycle cannot be mapped to a linear keyboard.
        // Example: "abcda" -> a-b, b-c, c-d, d-a. All have degree 2.
        // This is impossible.
        std::cout << "NO\n";
        return;
    }

    if (used_in_s.empty()) { // s was empty, but constraints say |s| >= 1. So this path is not taken.
        // If s is empty, any layout is fine.
        // This case is not possible due to constraints |s| >= 1.
    } else if (start_char == '\0') { // This means s has only one character.
        start_char = *used_in_s.begin();
    }

    char current = start_char;
    char prev = '\0'; // Sentinel for the first character

    while (current != '\0' && visited_in_layout.find(current) == visited_in_layout.end()) {
        layout += current;
        visited_in_layout.insert(current);

        char next_char = '\0';
        for (char neighbor : adj[current]) {
            if (neighbor != prev) {
                next_char = neighbor;
                break;
            }
        }
        prev = current;
        current = next_char;
    }

    // Check if all characters from s are included in the layout path
    for (char c : used_in_s) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            // This means there's a disconnected component in the required adjacencies
            // that couldn't be reached from the initial path.
            // This implies multiple paths or cycles, which cannot be combined into a single linear layout.
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

