int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_first_char = 0; k_first_char < L; ++k_first_char) {
        char c0 = s[k_first_char]; // The first character Vasya sees

        // Find all possible initial shifts `k_prime` that result in `s[k_prime] == c0`.
        // These are the `k` values Vasya considers possible after seeing `t[0]`.
        std::vector<int> possible_k_after_c0;
        for (int i = 0; i < L; ++i) {
            if (s[i] == c0) {
                possible_k_after_c0.push_back(i);
            }
        }

        if (possible_k_after_c0.size() == 1) {
            // If only one k is possible after seeing t[0], Vasya wins immediately.
            // This k_first_char contributes 1.0 to its part of the total probability.
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal `p` (1 to L-1) to maximize win probability.
        double max_win_prob_for_c0 = 0.0;

        for (int p = 1; p < L; ++p) {
            // For a fixed `c0` and chosen `p`, count how many `k_prime` values
            // lead to a unique pair (c0, cp).
            // `cp` would be `s[(k_prime + p) % L]`.

            std::map<char, int> count_unique_cp_for_p;
            for (int k_prime : possible_k_after_c0) {
                char cp = s[(k_prime + p) % L];
                count_unique_cp_for_p[cp]++;
            }

            int num_unique_k_after_c0_cp = 0;
            for (auto const& [cp_val, count] : count_unique_cp_for_p) {
                if (count == 1) {
                    num_unique_k_after_c0_cp++;
                }
            }

            // The probability of winning for this `c0` and chosen `p` is
            // (number of `k_prime` that become unique) / (total number of `k_prime` initially possible).
            max_win_prob_for_c0 = std::max(max_win_prob_for_c0, 
                                           (double)num_unique_k_after_c0_cp / possible_k_after_c0.size());
        }
        total_win_prob += max_win_prob_for_c0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_val_0 = 0;    // Value if input is 0
    int current_val_1023 = 1023; // Value if input is 1023 (all 1s for 10 bits)

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_0 &= x;
            current_val_1023 &= x;
        } else if (op_char == '|') {
            current_val_0 |= x;
            current_val_1023 |= x;
        } else if (op_char == '^') {
            current_val_0 ^= x;
            current_val_1023 ^= x;
        }
    }

    // Now we have the final state of 0 and 1023 after all operations.
    // Let's determine the equivalent single AND, OR, XOR operations.
    // We need to find A, O, X such that:
    // ( ( ( (input & A) | O ) ^ X ) for all inputs 0..1023
    // is equivalent to the original program.

    // For each bit position (0 to 9):
    // Let x_b be the b-th bit of the input.
    // Let f(x_b) be the b-th bit of the final result.
    // We know f(0) = (current_val_0 >> b) & 1
    // We know f(1) = (current_val_1023 >> b) & 1

    // We want to find a_b, o_b, x_b such that:
    // ( ( (x_b & a_b) | o_b ) ^ x_b ) == f(x_b)

    // Let's analyze the possible (f(0), f(1)) pairs:
    // 1. (0, 0): f(x_b) = 0 for all x_b.
    //    This means the bit is always 0, regardless of input.
    //    This can be achieved by:
    //    (x_b & 0) | 0 = 0. So a_b=0, o_b=0, x_b=0.
    //    Or (x_b & 0) | 1 = 1, then ^1 = 0. So a_b=0, o_b=1, x_b=1.
    //    Simplest: a_b=0, o_b=0, x_b=0. (Equivalent to & 0)
    // 2. (0, 1): f(x_b) = x_b.
    //    This means the bit is unchanged.
    //    This can be achieved by:
    //    (x_b & 1) | 0 = x_b. So a_b=1, o_b=0, x_b=0.
    //    Simplest: a_b=1, o_b=0, x_b=0. (Equivalent to & 1)
    // 3. (1, 0): f(x_b) = 1 - x_b (NOT x_b).
    //    This means the bit is flipped.
    //    This can be achieved by:
    //    (x_b & 1) | 0 = x_b, then ^1 = 1-x_b. So a_b=1, o_b=0, x_b=1.
    //    Simplest: a_b=1, o_b=0, x_b=1. (Equivalent to ^ 1)
    // 4. (1, 1): f(x_b) = 1 for all x_b.
    //    This means the bit is always 1, regardless of input.
    //    This can be achieved by:
    //    (x_b & 0) | 1 = 1. So a_b=0, o_b=1, x_b=0.
    //    Simplest: a_b=0, o_b=1, x_b=0. (Equivalent to | 1)

    // We can combine these into at most 3 operations: one AND, one OR, one XOR.
    // Let's find the constants for these three operations.
    int final_and_const = 1023; // Initialize with all 1s
    int final_or_const = 0;     // Initialize with all 0s
    int final_xor_const = 0;    // Initialize with all 0s

    for (int b = 0; b < 10; ++b) {
        int f0 = (current_val_0 >> b) & 1;
        int f1 = (current_val_1023 >> b) & 1;

        if (f0 == 0 && f1 == 0) { // Bit always becomes 0
            // This bit must be 0 after AND, and 0 after OR, and 0 after XOR.
            // To make it 0, we can set a_b=0.
            final_and_const &= ~(1 << b); // Set b-th bit of AND constant to 0
            // final_or_const remains 0 for this bit
            // final_xor_const remains 0 for this bit
        } else if (f0 == 0 && f1 == 1) { // Bit is unchanged (x_b)
            // This bit must be 1 after AND, and 0 after OR, and 0 after XOR.
            // To keep it unchanged, we can set a_b=1.
            // final_and_const remains 1 for this bit
            // final_or_const remains 0 for this bit
            // final_xor_const remains 0 for this bit
        } else if (f0 == 1 && f1 == 0) { // Bit is flipped (1 - x_b)
            // This bit must be 1 after AND, and 0 after OR, and 1 after XOR.
            // To flip it, we can set a_b=1, x_b=1.
            // final_and_const remains 1 for this bit
            // final_or_const remains 0 for this bit
            final_xor_const |= (1 << b); // Set b-th bit of XOR constant to 1
        } else if (f0 == 1 && f1 == 1) { // Bit always becomes 1
            // This bit must be 0 after AND, and 1 after OR, and 0 after XOR.
            // To make it 1, we can set o_b=1.
            final_and_const &= ~(1 << b); // Set b-th bit of AND constant to 0
            final_or_const |= (1 << b);   // Set b-th bit of OR constant to 1
            // final_xor_const remains 0 for this bit
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_const != 1023) { // If AND constant is not all 1s
        result_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) { // If OR constant is not all 0s
        result_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) { // If XOR constant is not all 0s
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // diff_L[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // for k from 0 to n
    std::vector<int> diff_L(n + 1, 0);
    int s1_L = 0;
    int s2_L = 0;
    for (int k = 0; k < n; ++k) {
        if (a[k] == 1) {
            s1_L++;
        } else {
            s2_L++;
        }
        diff_L[k + 1] = s1_L - s2_L;
    }

    // Calculate suffix sums for the right half (jars n+1 to 2n)
    // diff_R[k] = (count of 1s in a[2n-1...2n-k]) - (count of 2s in a[2n-1...2n-k])
    // for k from 0 to n
    std::vector<int> diff_R(n + 1, 0);
    int s1_R = 0;
    int s2_R = 0;
    for (int k = 0; k < n; ++k) {
        if (a[2 * n - 1 - k] == 1) {
            s1_R++;
        } else {
            s2_R++;
        }
        diff_R[k + 1] = s1_R - s2_R;
    }

    // Store the minimum number of jars eaten from the right to achieve a certain diff_R value
    // map: diff_val -> min_jars_eaten_from_right
    std::map<int, int> min_jars_right;
    for (int k = 0; k <= n; ++k) {
        int current_diff_R = diff_R[k];
        if (min_jars_right.find(current_diff_R) == min_jars_right.end()) {
            min_jars_right[current_diff_R] = k;
        } else {
            min_jars_right[current_diff_R] = std::min(min_jars_right[current_diff_R], k);
        }
    }

    int min_total_eaten = 2 * n; // Max possible jars eaten

    // Iterate through all possible jars eaten from the left (0 to n)
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_diff_L = diff_L[k_L];
        // We need diff_L[k_L] + diff_R[k_R] = 0, so diff_R[k_R] = -diff_L[k_L]
        int target_diff_R = -current_diff_L;

        if (min_jars_right.count(target_diff_R)) {
            int k_R = min_jars_right[target_diff_R];
            min_total_eaten = std::min(min_total_eaten, k_L + k_R);
        }
    }

    std::cout << min_total_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_zero_run(n);
    std::vector<int> right_zero_run(n);
    std::vector<int> left_one_run(n);
    std::vector<int> right_one_run(n);

    // Calculate left_zero_run and left_one_run
    left_zero_run[0] = (a[0] == 0 ? 1 : 0);
    left_one_run[0] = (a[0] == 1 ? 1 : 0);
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zero_run[i] = left_zero_run[i - 1] + 1;
            left_one_run[i] = 0;
        } else {
            left_zero_run[i] = 0;
            left_one_run[i] = left_one_run[i - 1] + 1;
        }
    }

    // Calculate right_zero_run and right_one_run
    right_zero_run[n - 1] = (a[n - 1] == 0 ? 1 : 0);
    right_one_run[n - 1] = (a[n - 1] == 1 ? 1 : 0);
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zero_run[i] = right_zero_run[i + 1] + 1;
            right_one_run[i] = 0;
        } else {
            right_zero_run[i] = 0;
            right_one_run[i] = right_one_run[i + 1] + 1;
        }
    }

    int max_k = 0;
    std::vector<int> final_a = a;

    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // Current element is 0
            // Find nearest 1 to the left
            int l = i - left_one_run[i];
            // Find nearest 1 to the right
            int r = i + right_one_run[i];

            if (l < 0 && r >= n) { // All zeros
                // max_k remains 0, final_a remains all zeros
            } else if (l < 0) { // Only 1s to the right
                int k_val = (right_one_run[i] + 1) / 2;
                max_k = std::max(max_k, k_val);
                if (k_val > 0) {
                    final_a[i] = 0; // Stays 0
                }
            } else if (r >= n) { // Only 1s to the left
                int k_val = (left_one_run[i] + 1) / 2;
                max_k = std::max(max_k, k_val);
                if (k_val > 0) {
                    final_a[i] = 0; // Stays 0
                }
            } else { // 1s on both sides
                int k_val = (std::min(left_one_run[i], right_one_run[i]) + 1) / 2;
                max_k = std::max(max_k, k_val);
                if (k_val > 0) {
                    final_a[i] = 0; // Stays 0
                }
            }
        } else { // Current element is 1
            // Find nearest 0 to the left
            int l = i - left_zero_run[i];
            // Find nearest 0 to the right
            int r = i + right_zero_run[i];

            if (l < 0 && r >= n) { // All ones
                // max_k remains 0, final_a remains all ones
            } else if (l < 0) { // Only 0s to the right
                int k_val = (right_zero_run[i] + 1) / 2;
                max_k = std::max(max_k, k_val);
                if (k_val > 0) {
                    final_a[i] = 1; // Stays 1
                }
            } else if (r >= n) { // Only 0s to the left
                int k_val = (left_zero_run[i] + 1) / 2;
                max_k = std::max(max_k, k_val);
                if (k_val > 0) {
                    final_a[i] = 1; // Stays 1
                }
            } else { // 0s on both sides
                int k_val = (std::min(left_zero_run[i], right_zero_run[i]) + 1) / 2;
                max_k = std::max(max_k, k_val);
                if (k_val > 0) {
                    final_a[i] = 1; // Stays 1
                }
            }
        }
    }

    // Determine final_a based on max_k
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            int l = i - left_one_run[i];
            int r = i + right_one_run[i];

            int dist_to_nearest_one;
            if (l < 0 && r >= n) { // All zeros
                dist_to_nearest_one = n + 1; // Effectively infinity
            } else if (l < 0) { // Only 1s to the right
                dist_to_nearest_one = right_one_run[i];
            } else if (r >= n) { // Only 1s to the left
                dist_to_nearest_one = left_one_run[i];
            } else { // 1s on both sides
                dist_to_nearest_one = std::min(left_one_run[i], right_one_run[i]);
            }

            if (dist_to_nearest_one <= max_k) {
                final_a[i] = 1;
            } else {
                final_a[i] = 0;
            }
        } else { // a[i] == 1
            int l = i - left_zero_run[i];
            int r = i + right_zero_run[i];

            int dist_to_nearest_zero;
            if (l < 0 && r >= n) { // All ones
                dist_to_nearest_zero = n + 1; // Effectively infinity
            } else if (l < 0) { // Only 0s to the right
                dist_to_nearest_zero = right_zero_run[i];
            } else if (r >= n) { // Only 0s to the left
                dist_to_nearest_zero = left_zero_run[i];
            } else { // 0s on both sides
                dist_to_nearest_zero = std::min(left_zero_run[i], right_zero_run[i]);
            }

            if (dist_to_nearest_zero <= max_k) {
                final_a[i] = 0;
            } else {
                final_a[i] = 1;
            }
        }
    }

    std::cout << max_k << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm> // For std::abs, std::min, std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        // Ensure abs_n >= abs_m for simpler logic
        if (abs_n < abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Case 1: k < abs_n (not enough moves to cover the larger coordinate distance)
        if (k < abs_n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k >= abs_n
        // We can reach (abs_n, abs_m) in abs_n moves by making abs_m diagonal moves
        // and (abs_n - abs_m) straight moves along the x-axis.
        // This uses abs_n moves and reaches (abs_n, abs_m).
        // The remaining moves are k - abs_n.
        long long remaining_moves = k - abs_n;

        // If remaining_moves is even, we can use them to toggle parity without changing final position.
        // Each pair of moves (e.g., (1,0) then (-1,0)) or ( (1,1) then (-1,-1) )
        // or ( (1,0) then (0,1) then (-1,0) then (0,-1) ) can be used to consume moves
        // while returning to the same parity or even the same spot.
        // The maximum number of diagonal moves is k.
        // The minimum number of diagonal moves to reach (abs_n, abs_m) is abs_m.
        // The parity of (abs_n + abs_m) must match the parity of k.
