    }

    // Verify the solution
    current_delta.assign(n, 0); // Reset current_delta for verification
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
