// Function to calculate parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    int initial_ones_a = 0;
    for (char c : a) {
        if (c == '1') {
            initial_ones_a++;
        }
    }

    int ones_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_b++;
        }
    }

    // Calculate the maximum possible number of ones in a string derived from 'a'
    // that has the same length as 'b'.
    // This is initial_ones_a + (length_b - length_a) if length_b >= length_a.
    // If length_b < length_a, we can't simply add parities.
    // The maximum number of ones in a string of length L derived from 'a'
    // is initial_ones_a + (L - |a|) if L >= |a|.
    // If L < |a|, we are removing characters. The number of ones can only decrease or stay same.
    // The maximum number of ones in any string derived from 'a' by adding parities
    // and then truncating to length |b| is:
    // initial_ones_a + (parity_bits_added)
    // The number of parity bits added can be at most |b| - |a| if |b| >= |a|.
    // If |b| < |a|, we don't need to add any parity bits to reach length |b|.
    // In this case, the max ones is just initial_ones_a.
    // The maximum number of ones in a string of length |b| that can be formed
    // from 'a' is initial_ones_a + (max_length_increase).
    // The max_length_increase is |b| - |a| if |b| >= |a|, otherwise 0.
    // This is equivalent to:
    // If initial_ones_a is even, we can add '0's. Max ones remains initial_ones_a.
    // If initial_ones_a is odd, we can add '1's. Max ones becomes initial_ones_a + 1.
    // After adding a '1', the count becomes even. Then we add '0's.
    // So, if initial_ones_a is odd, we can always make it initial_ones_a + 1 (by adding a '1').
    // If initial_ones_a is even, we can always make it initial_ones_a (by adding a '0').
    // This means the maximum number of ones we can achieve in a string of length |a| + k
    // is initial_ones_a if initial_ones_a is even, or initial_ones_a + 1 if initial_ones_a is odd.
    // This is equivalent to (initial_ones_a + (initial_ones_a % 2)).
    // Let's call this `max_ones_in_a_prefix`.
    // This is the maximum number of ones in the string `a` itself, or `a` with one '1' appended if `a` has odd parity.
    // Any further appended parities will be '0's if the current string has even parity.
    // So, the maximum number of ones in any string `a'` that can be formed by appending parities
    // is `initial_ones_a` if `initial_ones_a` is even, or `initial_ones_a + 1` if `initial_ones_a` is odd.
    // This can be simplified to `initial_ones_a + (initial_ones_a % 2)`.

    int max_ones_possible_in_a_prefix = initial_ones_a + (initial_ones_a % 2);

    // Condition 1: The number of ones in 'b' must not exceed the maximum possible ones
    // that can be generated from 'a' (considering we can append at most one '1' if initial_ones_a is odd).
    if (ones_b > max_ones_possible_in_a_prefix) {
        std::cout << "NO\n";
        return 0;
    }

    // Condition 2: The length of 'b' must be less than or equal to the length of 'a'
    // plus the number of parity bits we can append.
    // We can append as many parity bits as needed to make 'a' at least as long as 'b'.
    // The only constraint is that we must be able to form 'b' as a suffix.
    // If |b| > |a|, we must append at least |b| - |a| parity bits.
    // This is always possible.
    // The only real constraint is the number of ones.

    // If we can reach `ones_b` ones, and `b` is a suffix of `a` (possibly extended),
    // then it's possible.
    // The logic is:
    // 1. Calculate `max_ones_in_a_prefix`. This is `initial_ones_a` if `initial_ones_a` is even,
    //    or `initial_ones_a + 1` if `initial_ones_a` is odd.
    // 2. If `ones_b` > `max_ones_in_a_prefix`, then it's impossible.
    // 3. Otherwise, it's always possible. Why?
    //    We can always extend `a` by appending parity bits until its length is `|b|`.
    //    If `|a| >= |b|`, we just need to check if `ones_b <= initial_ones_a`.
    //    If `|a| < |b|`, we append `|b| - |a|` parity bits.
    //    The number of ones in `a` can be `initial_ones_a` or `initial_ones_a + 1` (if `initial_ones_a` is odd).
    //    If `ones_b` is less than or equal to `max_ones_in_a_prefix`, it means we can achieve `ones_b` ones.
    //    For example, if `initial_ones_a` is 3, `max_ones_in_a_prefix` is 4.
    //    If `ones_b` is 0, 1, 2, 3, or 4, it's possible.
    //    If `ones_b` is 3, we don't append any '1's.
    //    If `ones_b` is 4, we append one '1'.
    //    If `ones_b` is 0, 1, 2, we can achieve this by removing leading characters from `a`
    //    (or `a` extended with a '1' if `initial_ones_a` was odd and we needed to reach an even number of ones).
    //    The key insight is that we can always make the string long enough, and we can always
    //    adjust the number of ones to be `initial_ones_a` or `initial_ones_a + 1` (if `initial_ones_a` is odd)
    //    by appending at most one '1' and then only '0's.
    //    After that, we can remove leading characters to match `b`.
    //    The only constraint is the total number of '1's.

    std::cout << "YES\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line; // To mark if child has left

    Child(long long v_val, long long d_val, long long p_val, int idx)
        : v(v_val), d(d_val), p(p_val), original_idx(idx), in_line(true) {}
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children;
    children.reserve(n);
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children.emplace_back(v_val, d_val, p_val, i + 1);
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue; // This child has already left
        }

        cured_children_indices.push_back(children[i].original_idx);

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving = 0; // Accumulates d_j from children leaving due to chain reaction

        // Apply v_i effect and initial chain reaction
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry from previous children leaving
            children[j].p -= total_d_cry_from_leaving;

            // Apply current_v_cry effect
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_from_leaving += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

