int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // dp[i] will store the maximum starting index 'x' (0-based)
    // such that s[x] = s[x+k] = s[x+2k] for some k,
    // and x+2k = i.
    // In other words, dp[i] is the smallest 'x' such that the pattern
    // s[x...i] contains s[x'] = s[x'+k] = s[x'+2k] with x'+2k = i.
    // Or, more simply, dp[i] is the minimum starting index of a pattern
    // that ends at or before index i.
    // Let's redefine: dp[i] = minimum starting index 'x' (0-based)
    // such that s[x] = s[x+k] = s[x+2k] for some k, and x+2k <= i.
    // If no such pattern exists ending at or before i, dp[i] = n (or some large value).

    // Let's use a different DP state.
    // `min_x_for_pattern_ending_at_i` stores the minimum `x` such that
    // `s[x] = s[x+k] = s[x+2k]` for some `k`, and `x+2k = i`.
    // If no such pattern ends exactly at `i`, it's `n`.
    std::vector<int> min_x_for_pattern_ending_at_i(n, n);

    for (int i = 0; i < n; ++i) {
        // Check for k=1, 2, 3, 4, 5, 6
        // The maximum k needed is 6 because 2k <= 12.
        // If k >= 7, then 2k >= 14.
        // If a pattern s[x]=s[x+k]=s[x+2k] exists, then x+2k <= n-1.
        // The minimum length of such a pattern is 3 (for k=1).
        // The maximum length of such a pattern is 13 (for k=6, x=0, 0+2*6=12).
        // If a pattern exists with k >= 7, then x+2k >= 14.
        // If we consider a substring of length 13, say s[0...12],
        // and it does NOT contain any pattern with k <= 6,
        // then it cannot contain any pattern at all.
        // This is because if it contained a pattern s[x]=s[x+k]=s[x+2k] with k >= 7,
        // then x+2k >= 14, which means the pattern would extend beyond index 12.
        // So, we only need to check k up to 6.
        for (int k = 1; k <= 6; ++k) {
            if (i - 2 * k >= 0) { // Check if s[i-2k], s[i-k], s[i] are valid indices
                if (s[i - 2 * k] == s[i - k] && s[i - k] == s[i]) {
                    min_x_for_pattern_ending_at_i[i] = std::min(min_x_for_pattern_ending_at_i[i], i - 2 * k);
                }
            }
        }
    }

    // `last_pattern_start_idx[i]` stores the minimum `x` such that
    // `s[x] = s[x+k] = s[x+2k]` for some `k`, and `x+2k <= i`.
    // If no such pattern exists ending at or before `i`, it's `n`.
    std::vector<int> last_pattern_start_idx(n, n);
    if (n > 0) {
        last_pattern_start_idx[0] = n; // No pattern can end at index 0
    }
    for (int i = 1; i < n; ++i) {
        last_pattern_start_idx[i] = last_pattern_start_idx[i-1]; // Inherit from previous
        last_pattern_start_idx[i] = std::min(last_pattern_start_idx[i], min_x_for_pattern_ending_at_i[i]);
    }

    for (int l = 0; l < n; ++l) {
        // For a fixed `l`, we want to find the smallest `r` such that `s[l...r]`
        // contains a pattern.
        // This means we need `x` such that `l <= x` and `x+2k <= r`.
        // The smallest `r` for which a pattern exists starting at or after `l`
        // is `min_r_for_l`.
        // If `last_pattern_start_idx[r]` is the minimum `x` such that `x+2k <= r`,
        // then we need `last_pattern_start_idx[r] < l`.
        // No, this is wrong. We need `last_pattern_start_idx[r] >= l`.
        // `last_pattern_start_idx[r]` is the minimum `x` such that `x+2k <= r`.
        // If `last_pattern_start_idx[r] < l`, it means the pattern starts before `l`,
        // so it's not contained in `s[l...r]`.
        // We need to find the smallest `r` such that there exists an `x` with
        // `l <= x` and `x+2k <= r` and `s[x]=s[x+k]=s[x+2k]`.
        // Let `min_r_for_l` be the smallest `r` such that `s[l...r]` contains a pattern.
        // If no such `r` exists, `min_r_for_l = n`.

        // Iterate `r` from `l` to `n-1`.
        // If `last_pattern_start_idx[r] <= r` (meaning a pattern exists ending at or before `r`)
        // AND `last_pattern_start_idx[r] >= l` (meaning the pattern starts at or after `l`),
        // then `s[l...r]` contains a pattern.
        // The number of `r` values for a fixed `l` that satisfy the condition is `n - min_r_for_l`.
        // We are counting bad pairs, so we need `r` such that `s[l...r]` does NOT contain a pattern.
        // This means for all `x, k` with `l <= x` and `x+2k <= r`, `s[x]=s[x+k]=s[x+2k]` is false.

        // Let `first_r_with_pattern_starting_at_l_or_later` be the smallest `r` such that
        // `last_pattern_start_idx[r] >= l`.
        // If `last_pattern_start_idx[r] < l`, it means any pattern ending at or before `r`
        // starts before `l`. So `s[l...r]` does not contain a pattern.
        // We need to find the smallest `r` such that `last_pattern_start_idx[r] >= l`.
        // All `r'` from `l` to `r-1` will have `last_pattern_start_idx[r'] < l`.
        // These are the `r` values for which `s[l...r']` does not contain a pattern.
        // The number of such `r'` is `r - l`.

        // Find the smallest `r_idx` such that `last_pattern_start_idx[r_idx] >= l`.
        // If no such `r_idx` exists, then `last_pattern_start_idx[n-1] < l`.
        // In this case, for all `r` from `l` to `n-1`, `s[l...r]` does not contain a pattern.
        // The number of such `r` values is `n - l`.

        // If such `r_idx` exists:
        // For `r` from `l` to `r_idx - 1`, `last_pattern_start_idx[r] < l`.
        // So `s[l...r]` does not contain a pattern.
        // The number of such `r` values is `r_idx - l`.

        // If `last_pattern_start_idx[r_idx] >= l`, then for `r >= r_idx`, `s[l...r]` contains a pattern.
        // So we count `r` from `l` to `r_idx - 1`.

        // Use binary search or `std::lower_bound` to find `r_idx`.
        // `last_pattern_start_idx` is non-increasing.
        // We need to find the first `r_idx` such that `last_pattern_start_idx[r_idx] >= l`.
        // This is equivalent to finding the first `r_idx` such that `last_pattern_start_idx[r_idx]`
        // is not less than `l`.

        // `std::upper_bound` on `last_pattern_start_idx` for value `l-1`.
        // `it = std::upper_bound(last_pattern_start_idx.begin() + l, last_pattern_start_idx.end(), l-1, std::greater<int>())`
        // This finds the first element `e` such that `e <= l-1` is false, i.e., `e > l-1`, i.e., `e >= l`.
        // The range for `r` is `[l, n-1]`.

        auto it = std::lower_bound(last_pattern_start_idx.begin() + l, last_pattern_start_idx.end(), l, std::greater<int>());
        int r_idx = std::distance(last_pattern_start_idx.begin(), it);

        // All `r` from `l` to `r_idx - 1` are bad pairs.
        // The number of such `r` values is `r_idx - l`.
        bad_pairs += (r_idx - l);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

