#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Element {
    int value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    long long min_goodness = LLONG_MAX;
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., all in S1).
    // S2 is empty. No pairs across subsequences.
    // f(a_i, a_j) = a_i + a_j for all i, j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    if (n >= 2) {
        long long current_goodness = (long long)a[n-1].value + a[n-2].value - ((long long)a[0].value + a[1].value);
        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            for (int i = 0; i < n; ++i) {
                best_partition[a[i].original_index] = 1;
            }
        }
    } else { // n=1, no pairs, goodness is 0. But problem states n >= 2.
        min_goodness = 0;
        best_partition[a[0].original_index] = 1;
    }


    // Case 2: At least one element in each subsequence.
    // This means there will be pairs (a_i, a_j) with a_i in S1, a_j in S2.
    // These pairs contribute a_i + a_j + h to the set of f values.
    // The minimum possible value for f is a[0].value + a[1].value.
    // The maximum possible value for f is a[n-1].value + a[n-2].value + h (if a[n-1] and a[n-2] are in different groups)
    // or a[n-1].value + a[n-2].value (if they are in the same group).
    //
    // Consider the partition where a[0] is in S1, and all other elements a[1]...a[n-1] are in S2.
    // min_f:
    //   - a[0] + a[1] + h (a[0] in S1, a[1] in S2)
    //   - a[1] + a[2] (a[1], a[2] in S2)
    //   The minimum of these two is min(a[0] + a[1] + h, a[1] + a[2]).
    // max_f:
    //   - a[n-1] + a[n-2] (a[n-1], a[n-2] in S2)
    //   - a[0] + a[n-1] + h (a[0] in S1, a[n-1] in S2)
    //   The maximum of these two is max(a[n-1] + a[n-2], a[0] + a[n-1] + h).
    //
    // Goodness = max(max_f_same, max_f_diff) - min(min_f_same, min_f_diff)
    //
    // Let's fix a[0] to be in S1 and a[n-1] to be in S2.
    // This guarantees that there's at least one pair across subsequences (a[0], a[n-1]).
    //
    // The minimum possible value of f is always a[0].value + a[1].value.
    // This can be achieved either by a[0], a[1] in same group (value a[0]+a[1])
    // or a[0], a[1] in different groups (value a[0]+a[1]+h).
    // If h is large, a[0]+a[1]+h will be larger than a[0]+a[1].
    // So, min_f is either a[0]+a[1] (if a[0], a[1] are in same group)
    // or a[0]+a[k]+h (if a[0] in S1, a[k] in S2, k is smallest index in S2)
    // or a[k]+a[l] (if a[k], a[l] in S2, k,l are smallest indices in S2).
    //
    // The minimum possible value of f is always at least a[0].value + a[1].value.
    // The maximum possible value of f is always at least a[n-1].value + a[n-2].value.
    //
    // Consider the partition where a[0] is in S1, and a[1], ..., a[n-1] are in S2.
    // min_f:
    //   - a[0] + a[1] + h (a[0] in S1, a[1] in S2)
    //   - a[1] + a[2] (a[1], a[2] in S2)
    //   So, min_f = std::min((long long)a[0].value + a[1].value + h, (long long)a[1].value + a[2].value);
    // max_f:
    //   - a[n-1] + a[n-2] (a[n-1], a[n-2] in S2)
    //   - a[0] + a[n-1] + h (a[0] in S1, a[n-1] in S2)
    //   So, max_f = std::max((long long)a[n-1].value + a[n-2].value, (long long)a[0].value + a[n-1].value + h);
    //
    // Goodness = max_f - min_f.
    //
    // This specific partition (a[0] in S1, rest in S2) is one of the candidates.
    // Let's calculate its goodness.
    //
    // min_f_val:
    //   - a[0].value + a[1].value + h (a[0] in S1, a[1] in S2)
    //   - a[1].value + a[2].value (a[1], a[2] in S2)
    //   The minimum of these two is the overall minimum f.
    //   If n=2, only a[0]+a[1]+h is possible.
    long long current_min_f;
    if (n == 2) {
        current_min_f = (long long)a[0].value + a[1].value + h;
    } else {
        current_min_f = std::min((long long)a[0].value + a[1].value + h, (long long)a[1].value + a[2].value);
    }

    // max_f_val:
    //   - a[n-1].value + a[n-2].value (a[n-1], a[n-2] in S2)
    //   - a[0].value + a[n-1].value + h (a[0] in S1, a[n-1] in S2)
    long long current_max_f = std::max((long long)a[n-1].value + a[n-2].value, (long long)a[0].value + a[n-1].value + h);

    long long current_goodness = current_max_f - current_min_f;

    if (current_goodness < min_goodness) {
        min_goodness = current_goodness;
        best_partition[a[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            best_partition[a[i].original_index] = 2;
        }
    }

    // Consider the partition where a[0], a[1] are in S1, and a[2], ..., a[n-1] are in S2.
    // This is not necessarily better.
    //
    // The key insight is that the minimum f value will always involve a[0] and a[1].
    // The maximum f value will always involve a[n-1] and a[n-2].
    //
    // Let min_f_overall = min(a_i + a_j, a_k + a_l + h).
    // Let max_f_overall = max(a_i + a_j, a_k + a_l + h).
    //
    // The minimum possible sum of two elements is a[0].value + a[1].value.
    // The maximum possible sum of two elements is a[n-1].value + a[n-2].value.
    //
    // If we have elements in both groups, then we have values like X + Y + h.
    // The smallest such value is a[0].value + a[k].value + h, where a[k] is the smallest element in the other group.
    // The largest such value is a[n-1].value + a[k].value + h, where a[k] is the largest element in the other group.
    //
    // The minimum possible f value is always a[0].value + a[1].value.
    // The maximum possible f value is always a[n-1].value + a[n-2].value.
    //
    // If we put a[0] in S1 and a[1] in S2, then min_f_diff = a[0]+a[1]+h.
    // If we put a[0] in S1 and a[1] in S1, then min_f_same = a[0]+a[1].
    //
    // The overall minimum f value is always a[0].value + a[1].value.
    // The overall maximum f value is always a[n-1].value + a[n-2].value.
    //
    // The only way to get a smaller goodness than the "all in one group" case is if h is small enough
    // that a[0]+a[n-1]+h is not too large, and a[0]+a[1]+h is not too large.
    //
    // Consider the partition where a[0] is in S1, and a[1], ..., a[n-1] are in S2.
    // min_f = min(a[0]+a[1]+h, a[1]+a[2]) (if n > 2, else a[0]+a[1]+h)
    // max_f = max(a[n-1]+a[n-2], a[0]+a[n-1]+h)
    //
    // The minimum possible value of f is `a[0].value + a[1].value`.
    // The maximum possible value of f is `a[n-1].value + a[n-2].value`.
    //
    // If we have elements in both groups, then the set of f values includes:
    //   - `a[0].value + a[1].value` (if a[0], a[1] are in the same group)
    //   - `a[0].value + a[1].value + h` (if a[0], a[1] are in different groups)
    //   - `a[n-1].value + a[n-2].value` (if a[n-1], a[n-2] are in the same group)
    //   - `a[n-1].value + a[n-2].value + h` (if a[n-1], a[n-2] are in different groups)
    //   - `a[0].value + a[n-1].value + h` (if a[0], a[n-1] are in different groups)
    //
    // The minimum possible f value is `a[0].value + a[1].value`.
    // The maximum possible f value is `a[n-1].value + a[n-2].value + h` (if a[n-1] and a[n-2] are in different groups)
    // or `a[n-1].value + a[n-2].value` (if a[n-1] and a[n-2] are in the same group).
    //
    // The crucial observation is that the minimum f value is always `a[0].value + a[1].value`.
    // This is because if `a[0]` and `a[1]` are in the same group, we get `a[0]+a[1]`.
    // If `a[0]` and `a[1]` are in different groups, we get `a[0]+a[1]+h`.
    // Since `h >= 0`, `a[0]+a[1] <= a[0]+a[1]+h`.
    // So, the minimum possible f value is `a[0].value + a[1].value`.
    //
    // The maximum possible f value is `max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h)`.
    // This is because `a[n-1]+a[n-2]` is the largest sum within a group.
    // And `a[0]+a[n-1]+h` is the largest sum across groups (if a[0] and a[n-1] are in different groups).
    //
    // So, the goodness is `max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h) - (a[0].value + a[1].value)`.
    // This goodness is achieved if we can construct a partition such that:
    // 1. `a[0]` and `a[1]` are in the same group. (to get `a[0]+a[1]` as min_f)
    // 2. `a[0]` and `a[n-1]` are in different groups. (to get `a[0]+a[n-1]+h` as a candidate for max_f)
    // 3. `a[n-1]` and `a[n-2]` are in the same group. (to get `a[n-1]+a[n-2]` as a candidate for max_f)
    //
    // A partition that satisfies these conditions:
    // Put `a[0]` in S1.
    // Put `a[n-1]` in S2.
    // Put `a[1]` in S1 (same as a[0]).
    // Put `a[n-2]` in S2 (same as a[n-1]).
    // For all other elements `a[i]` (where `1 < i < n-2`), put them in S1 or S2.
    // For simplicity, put `a[0]` and `a[1]` in S1, and `a[2]` to `a[n-1]` in S2.
    // This ensures:
    //   - `a[0], a[1]` are in S1, so `a[0]+a[1]` is a value.
    //   - `a[0]` in S1, `a[n-1]` in S2, so `a[0]+a[n-1]+h` is a value.
    //   - `a[n-1], a[n-2]` are in S2, so `a[n-1]+a[n-2]` is a value.
    //
    // This partition is:
    // S1: {a[0], a[1]}
    // S2: {a[2], ..., a[n-1]}
    //
    // This partition is valid if n >= 3.
    // If n=2, this partition is not possible. We already handled n=2 in the previous case.
    //
    // For n >= 3:
    // min_f:
    //   - a[0]+a[1] (from S1)
    //   - a[0]+a[2]+h (from S1, S2)
    //   - a[2]+a[3] (from S2, if n >= 4)
    //   The minimum of these is always a[0]+a[1].
    // max_f:
    //   - a[0]+a[1] (from S1)
    //   - a[n-1]+a[n-2] (from S2, if n >= 4)
    //   - a[0]+a[n-1]+h (from S1, S2)
    //   - a[1]+a[n-1]+h (from S1, S2)
    //   The maximum of these is max(a[n-1]+a[n-2], a[1]+a[n-1]+h).
    //   Note: a[0]+a[n-1]+h <= a[1]+a[n-1]+h.
    //
    // So, for this partition:
    // min_f = (long long)a[0].value + a[1].value;
    // max_f = std::max((long long)a[n-1].value + a[n-2].value, (long long)a[1].value + a[n-1].value + h);
    //
    // Goodness = max_f - min_f.
    //
    // This is the third candidate for goodness.
    if (n >= 3) {
        long long current_min_f_val = (long long)a[0].value + a[1].value;
        long long current_max_f_val = std::max((long long)a[n-1].value + a[n-2].value, (long long)a[1].value + a[n-1].value + h);
        long long current_goodness_val = current_max_f_val - current_min_f_val;

        if (current_goodness_val < min_goodness) {
            min_goodness = current_goodness_val;
            best_partition[a[0].original_index] = 1;
            best_partition[a[1].original_index] = 1;
            for (int i = 2; i < n; ++i) {
                best_partition[a[i].original_index] = 2;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int head_idx = 0;
    int p_idx = 0;

    while (p_idx < m) {
        if (head_idx >= n) {
            return false; // No more heads to cover remaining tracks
        }

        // Find the first head that can reach p_idx
        // Skip heads that are too far to the left to reach p[p_idx]
        while (head_idx < n && h[head_idx] + T < p[p_idx]) {
            head_idx++;
        }

        if (head_idx >= n) {
            return false; // No head can reach current p[p_idx]
        }

        // At this point, h[head_idx] + T >= p[p_idx]
        // This head can cover p[p_idx].
        // Determine the rightmost track this head can cover.
        long long current_head_reach_right = h[head_idx] + T;

        // If h[head_idx] is already to the right of p[p_idx],
        // the head can move left to cover p[p_idx].
        // The leftmost point it can reach is h[head_idx] - T.
        // If p[p_idx] is to the left of h[head_idx] - T, this head cannot cover p[p_idx].
        // This case is handled by the initial while loop: h[head_idx] + T < p[p_idx]
        // If h[head_idx] - T > p[p_idx], then h[head_idx] is too far right.
        // We need to ensure that p[p_idx] is within [h[head_idx] - T, h[head_idx] + T].
        // The condition h[head_idx] + T >= p[p_idx] is already met.
        // We also need h[head_idx] - T <= p[p_idx].
        if (h[head_idx] - T > p[p_idx]) {
            // This head is too far to the right to cover p[p_idx]
            // Even if it moves left for T seconds, it cannot reach p[p_idx].
            // We need to try the next head.
            head_idx++;
            continue; // Try again with the next head for the same p[p_idx]
        }

        // This head h[head_idx] can cover p[p_idx].
        // Now, advance p_idx to cover as many tracks as possible with this head.
        while (p_idx < m && p[p_idx] <= current_head_reach_right) {
            p_idx++;
        }

        // Move to the next head for the remaining tracks.
        head_idx++;
    }

    return true; // All tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
