    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance: 10^10 (max coord) - 1 (min coord) + 10^5 (max N/M) * 1 (move per sec)
                                    // A safe upper bound is 2 * 10^10, or simply max(p_m - h_1, h_n - p_1)
                                    // Max p_m is 10^10, min h_1 is 1. So 10^10 is a good upper bound.
                                    // The difference between max p and min p can be 10^10.
                                    // The difference between max h and min h can be 10^10.
                                    // The maximum time could be roughly max(p_i) - min(h_i) or max(h_i) - min(p_i).
                                    // A safe upper bound is 10^10. Let's use 2 * 10^10 to be absolutely safe.

    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

