void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation always works.
    // Let p = [p_1, p_2, ..., p_n].
    // The sums are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    // Let p' = [p_n, p_{n-1}, ..., p_1].
    // The sums for p' are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // Since addition is commutative, p_i + p_{i+1} = p_{i+1} + p_i.
    // The set of sums for p is {p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n}.
    // The set of sums for p' is {p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1}.
    // These two sets are identical, just in reverse order.
    // Therefore, their sorted versions (fingerprints) will be identical.
    // The only case where p' might be equal to p is if p is a palindrome.
    // However, the problem guarantees that a *different* permutation p' exists.
    // Reversing is the simplest strategy and works for all n >= 2.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

