void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << "\n";
        return;
    }

    // For n > 1, we can construct a number.
    // The number will start with '2' and end with '3'.
    // All intermediate digits will be '4'.
    // This ensures:
    // 1. No digit is '0'.
    // 2. No digit is '1' (to avoid divisibility by 1).
    // 3. The number is not divisible by 2 (ends in 3).
    // 4. The number is not divisible by 3 (sum of digits: 2 + (n-2)*4 + 3 = 5 + 4n - 8 = 4n - 3.
    //    If 4n-3 is divisible by 3, then 4n is divisible by 3, which means n is divisible by 3.
    //    If n is divisible by 3, say n=3k, then 4n-3 = 12k-3, which is divisible by 3.
    //    So, if n is a multiple of 3, this construction might fail for digit 3.
    //    Example: n=3, number is 243. Sum of digits = 9. 243 is divisible by 3.
    //    Example: n=4, number is 2443. Sum of digits = 13. Not div by 3.
    //    Example: n=5, number is 24443. Sum of digits = 17. Not div by 3.
    //    Example: n=6, number is 244443. Sum of digits = 21. Div by 3.
    //
    // A simpler construction that works for all n > 1:
    // Start with '2'.
    // Fill the middle n-2 digits with '3'.
    // End with '9'.
    // Example: n=2 -> 29
    // Example: n=3 -> 239
    // Example: n=4 -> 2339
    //
    // Let's check this construction:
    // Digits are 2, 3, 9. No 0 or 1.
    // Divisibility by 2: The number ends in 9, so it's not divisible by 2.
    // Divisibility by 3: The sum of digits is 2 + (n-2)*3 + 9 = 2 + 3n - 6 + 9 = 3n + 5.
    //    For 3n+5 to be divisible by 3, 5 must be divisible by 3, which is false.
    //    So, the number is never divisible by 3.
    // Divisibility by 9: The sum of digits is 3n+5.
    //    For 3n+5 to be divisible by 9, it must be divisible by 3 (which we just showed it's not).
    //    So, the number is never divisible by 9.
    //
    // This construction works for all n > 1.

    std::cout << '2';
    for (int i = 0; i < n - 2; ++i) {
        std::cout << '3';
    }
    std::cout << '9' << "\n";
}

