    bool T_is_even = (T % 2 == 0);
    long long T_half = T / 2;
    int color_for_T_half = 0; // 0 for white, 1 for black

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T_half) {
            p[i] = 0; // Smaller elements go to white (0)
        } else if (a[i] > T_half) {
            p[i] = 1; // Larger elements go to black (1)
        } else { // a[i] == T_half
            if (T_is_even) {
                p[i] = color_for_T_half;
                color_for_T_half = 1 - color_for_T_half; // Alternate color for T/2 elements
            } else {
                // T is odd, so a[i] == T/2 is impossible for integer a[i]
                // This branch should not be reached if a[i] are integers.
                // However, if T/2 is used as a general threshold, then a[i] == T/2
                // means a[i] is not an integer, which is not allowed by problem constraints.
                // So this else branch implies a[i] == T_half, and T is even.
                // For safety, we can assign based on some default, but it's not strictly necessary.
                // The problem states a_i are integers, so T_half is only relevant if T is even.
                // If T is odd, a[i] can never be T/2.
                // So this else block is only for T_is_even.
                p[i] = color_for_T_half;
                color_for_T_half = 1 - color_for_T_half;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
