    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            max_val_in_row = std::max(max_val_in_row, a[i][j]);
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1. If so, it means n is missing.
    // This happens if the true value n is assigned to some p[k],
    // then max_val_in_row for that k would be n-1.
    // In this case, we need to find the first occurrence of n-1 and change it to n.
    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not present in p, it means one of the p[i] values that should be n
        // was instead calculated as n-1 (because min(n, p_j) = p_j for all p_j < n).
        // We need to find an element that is n-1 and change it to n.
        // Any element that is n-1 can be changed to n, as long as n is not already present.
        // The problem guarantees a solution exists, so there will be at least one n-1.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

