    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the triangle formed by the i-th cut from the apex
        // should be i times the area of one piece.
        // Total area of the carrot = (1/2) * base * height = (1/2) * 1 * h = h/2.
        // Area of one piece = (h/2) / n = h / (2n).
        // Area of triangle up to i-th cut = i * (h / (2n)).
        // Let x_i be the height of this triangle.
        // By similar triangles, base_x_i / x_i = base_h / h = 1 / h.
        // So, base_x_i = x_i / h.
        // Area of triangle up to x_i = (1/2) * base_x_i * x_i
        //                             = (1/2) * (x_i / h) * x_i
        //                             = x_i^2 / (2h).
        // Equating the two expressions for the area:
        // x_i^2 / (2h) = i * (h / (2n))
        // x_i^2 = i * (h^2 / n)
        // x_i = sqrt(i * h^2 / n)
        // x_i = h * sqrt(i / n)
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
