    int p = n - 1;
    while (p > 0 && a[p-1] <= a[p]) {
        p--;
    }
    // Now a[p...n-1] is non-decreasing.
    // If p is 0, the whole array is non-decreasing.

    // Find the rightmost index 'q' such that a[q...p-1] is non-increasing.
    // This is the longest suffix of the prefix a[0...p-1] that is non-increasing.
    // We start from p-1 because a[p...n-1] is already non-decreasing.
    // We are looking for the point where the non-increasing sequence from the right breaks.
    int q = p; // If p is 0, q remains 0. If p is 1, q remains 1.
    while (q > 0 && a[q-1] >= a[q]) {
        q--;
    }
    // Now a[q...p-1] is non-increasing.
    // The array a[q...n-1] is a candidate for a "good" array.
    // The prefix to remove would be a[0...q-1], which has length q.

    std::cout << q << std::endl;
