void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string ans(n, '0');

    // For m=1, the subsegment is just [1]. This is always possible.
    // l = r = pos[1]. min_idx = pos[1], max_idx = pos[1].
    // max_val = 1. Length = 1.
    // So 1 is always beautiful.
    ans[0] = '1';

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Update the range [current_min_idx, current_max_idx] to include pos[m]
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current range [current_min_idx, current_max_idx]
        // satisfies the conditions for m to be beautiful.
        // 1. It must contain all numbers from 1 to m. (This is guaranteed by how we update min/max_idx)
        // 2. The maximum value in p[current_min_idx ... current_max_idx] must be m.
        //    (This is also guaranteed because we are iterating m from 1 to n,
        //     and current_max_idx is the rightmost position of any number from 1 to m,
        //     and current_min_idx is the leftmost position of any number from 1 to m.
        //     So the segment p[current_min_idx ... current_max_idx] contains all numbers 1..m,
        //     and no number greater than m that is not yet processed.)
        // 3. The length of the subsegment must be m.
        //    Length = current_max_idx - current_min_idx + 1.
        if (current_max_idx - current_min_idx + 1 == m) {
            ans[m - 1] = '1';
        }
    }

    std::cout << ans << "\n";
}

