void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    std::vector<std::string> result(4);

    // Box 1: (-inf, -1] (Negative, magnitude >= 1)
    // Box 2: (-1, 0) (Negative, magnitude < 1)
    // Box 3: (0, 1) (Positive, magnitude < 1)
    // Box 4: [1, inf) (Positive, magnitude >= 1)

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (A == 1) result[0] = "Ya"; else result[0] = "Tidak";
        if (B == 1) result[1] = "Ya"; else result[1] = "Tidak";
        if (C == 1) result[2] = "Ya"; else result[2] = "Tidak";
        if (D == 1) result[3] = "Ya"; else result[3] = "Tidak";
        std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << std::endl;
        return;
    }

    // Determine if a positive or negative final value is possible
    // A toy from B1 or B2 is negative. A toy from B3 or B4 is positive.
    // The sign of the final product depends on the parity of negative numbers multiplied.
    // If we can choose an odd number of negative toys to multiply, final is negative.
    // If we can choose an even number of negative toys to multiply, final is positive.
    // Number of negative toys available: A + B
    bool can_be_negative = (A + B > 0); // If there's at least one negative toy, we can make the final product negative.
    bool can_be_positive = true; // Always possible to make positive, unless all toys are negative and A+B is odd.
                                 // If A+B is even, we can make positive.
                                 // If A+B is odd, and there are positive toys (C+D > 0), we can make positive.
                                 // If A+B is odd, and C+D == 0, then all toys are negative, and the final product must be negative.
    if ((A + B) % 2 == 1 && (C + D) == 0) {
        can_be_positive = false;
    }

    // Determine if magnitude < 1 or magnitude >= 1 is possible
    // A toy from B2 or B3 has magnitude < 1. A toy from B1 or B4 has magnitude >= 1.
    // If we multiply a toy with magnitude < 1 by anything, the result can be < 1.
    // If we multiply a toy with magnitude >= 1 by anything, the result can be >= 1.
    // If there are any toys in B2 or B3, we can potentially make the final magnitude < 1.
    // If there are any toys in B1 or B4, we can potentially make the final magnitude >= 1.

    // Can final magnitude be < 1?
    // Yes, if there is at least one toy in B2 or B3.
    // Or, if there are no toys in B2 or B3, but we can make a product of two B1/B4 toys that results in B2/B3.
    // Example: -2 * -0.5 = 1 (not <1)
    // Example: -2 * 0.5 = -1 (not <1)
    // Example: 2 * 0.5 = 1 (not <1)
    // Example: -2 * -0.2 = 0.4 (B3)
    // Example: 2 * 0.2 = 0.4 (B3)
    // Example: -2 * 0.2 = -0.4 (B2)
    // Example: 2 * -0.2 = -0.4 (B2)
    // If we have any B2 or B3 toys, we can always make the final magnitude < 1.
    // If we only have B1 and B4 toys, can we make magnitude < 1?
    // No, because multiplying two numbers with magnitude >= 1 always results in a number with magnitude >= 1.
    // So, can_be_mag_lt_1 is true if B + C > 0.
    bool can_be_mag_lt_1 = (B + C > 0);

    // Can final magnitude be >= 1?
    // Yes, if there is at least one toy in B1 or B4.
    // Or, if there are no toys in B1 or B4, but we can make a product of two B2/B3 toys that results in B1/B4.
    // Example: -0.5 * -0.5 = 0.25 (B3)
    // Example: -0.5 * 0.5 = -0.25 (B2)
    // Example: 0.5 * 0.5 = 0.25 (B3)
    // If we only have B2 and B3 toys, can we make magnitude >= 1?
    // No, because multiplying two numbers with magnitude < 1 always results in a number with magnitude < 1.
    // So, can_be_mag_ge_1 is true if A + D > 0.
    bool can_be_mag_ge_1 = (A + D > 0);

    // Special case: If all toys are in B2 and B3 (A=0, D=0), then the final product must have magnitude < 1.
    if (A == 0 && D == 0) {
        can_be_mag_ge_1 = false;
    }
    // Special case: If all toys are in B1 and B4 (B=0, C=0), then the final product must have magnitude >= 1.
    if (B == 0 && C == 0) {
        can_be_mag_lt_1 = false;
    }

    // Box 1: Negative, magnitude >= 1
    result[0] = (can_be_negative && can_be_mag_ge_1) ? "Ya" : "Tidak";

    // Box 2: Negative, magnitude < 1
    result[1] = (can_be_negative && can_be_mag_lt_1) ? "Ya" : "Tidak";

    // Box 3: Positive, magnitude < 1
    result[2] = (can_be_positive && can_be_mag_lt_1) ? "Ya" : "Tidak";

    // Box 4: Positive, magnitude >= 1
    result[3] = (can_be_positive && can_be_mag_ge_1) ? "Ya" : "Tidak";

    std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << std::endl;
}

