    while (T--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    std::vector<long long> prefix_min_ops(n);
    prefix_min_ops[0] = 0; // a[0] must be at least 0
    for (int i = 1; i < n; ++i) {
        // To satisfy a'_i > a'_{i-1}, we need a'_i >= a'_{i-1} + 1.
        // The minimum value for a'_{i-1} is prefix_min_ops[i-1].
        // So, a'_i must be at least prefix_min_ops[i-1] + 1.
        // Also, a'_i cannot be greater than a[i].
        // So, prefix_min_ops[i] = min(a[i], prefix_min_ops[i-1] + 1).
        // This is equivalent to saying a[i] must be at least i to allow 0,1,2,...,i
        // Or more generally, a[i] must be at least prefix_min_ops[i-1] + 1.
        // The actual value we need for a_i is i.
        // So, prefix_min_ops[i] = min(a[i], (long long)i);
        prefix_min_ops[i] = std::min(a[i], prefix_min_ops[i-1] + 1);
    }

    std::vector<long long> suffix_min_ops(n);
    suffix_min_ops[n - 1] = 0; // a[n-1] must be at least 0
    for (int i = n - 2; i >= 0; --i) {
        // To satisfy a'_i > a'_{i+1}, we need a'_i >= a'_{i+1} + 1.
        // The minimum value for a'_{i+1} is suffix_min_ops[i+1].
        // So, a'_i must be at least suffix_min_ops[i+1] + 1.
        // Also, a'_i cannot be greater than a[i].
        // So, suffix_min_ops[i] = min(a[i], suffix_min_ops[i+1] + 1).
        // The actual value we need for a_i is (n-1-i).
        // So, suffix_min_ops[i] = min(a[i], (long long)(n-1-i));
        suffix_min_ops[i] = std::min(a[i], suffix_min_ops[i+1] + 1);
    }

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        // For a peak at index k, we need:
        // 1. a'_k >= prefix_min_ops[k] (from left side)
        // 2. a'_k >= suffix_min_ops[k] (from right side)
        // 3. a'_k must be strictly positive if n > 1 and k is not 0 or n-1.
        //    However, the definition of sharpened allows a_k to be 0 if it's the only element.
        //    The conditions a_1 < ... < a_k and a_k > ... > a_n imply a_k >= max(k-1, n-1-k).
        //    If k=0, a_0 must be >= 0. If k=n-1, a_{n-1} must be >= 0.
        //    If 0 < k < n-1, then a_k must be >= 1 (since a_k > a_{k-1} and a_k > a_{k+1}).
        //    The values prefix_min_ops[k] and suffix_min_ops[k] already capture the minimum required values.
        //    If a[k] is large enough to satisfy both prefix_min_ops[k] and suffix_min_ops[k],
        //    then we can choose a'_k = min(a[k], max(prefix_min_ops[k], suffix_min_ops[k])).
        //    This a'_k will be >= prefix_min_ops[k] and >= suffix_min_ops[k].
        //    The condition for a peak at k is that a[k] must be at least max(prefix_min_ops[k], suffix_min_ops[k]).
        //    And also, a[k] must be at least 0.
        //    The values prefix_min_ops[k] and suffix_min_ops[k] are already non-negative.
        //    So we just need a[k] >= max(prefix_min_ops[k], suffix_min_ops[k]).
        if (a[k] >= std::max(prefix_min_ops[k], suffix_min_ops[k])) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

