#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2; // For 0-indexed array, this is the middle element

    // Cost for the median element itself
    operations += std::abs(a[mid_idx] - s);

    // Elements to the left of median must be <= s
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of median must be >= s
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int left_ptr = 0; // Pointer for the 'original' sorted array elements
    int right_ptr = 0; // Pointer for the 'permuted' sorted array elements

    while (right_ptr < n) {
        // We are trying to find an element a[right_ptr]
        // that is strictly greater than a[left_ptr].
        // If a[right_ptr] is greater, we can form a pair.
        // Both pointers advance.
        if (a[right_ptr] > a[left_ptr]) {
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            // If a[right_ptr] is not greater than a[left_ptr],
            // it means a[right_ptr] <= a[left_ptr].
            // This a[right_ptr] cannot be used to beat a[left_ptr].
            // Since a[left_ptr] is the smallest available 'original' element,
            // and a[right_ptr] is the smallest available 'permuted' element,
            // a[right_ptr] also cannot beat any a[k] where k > left_ptr.
            // So, we must try a larger 'permuted' element.
            // Only right_ptr advances.
            right_ptr++;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    std::sort(a_elements.begin(), a_elements.end(), compareElements);
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    std::vector<long long> result_a(m);
    for (int i = 0; i < m; ++i) {
        result_a[b_elements[i].original_index] = a_elements[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_R_pos = 0; // Represents the position of the last 'R' or the starting point (cell 0)
                            // If last_R_pos is 0, it means the frog is at cell 0.
                            // If last_R_pos is i, it means the frog is at cell i.

        // Iterate through the string s, which represents cells 1 to n.
        // s[i] corresponds to cell i+1.
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // If we encounter an 'R' at cell i+1, it means the frog can jump right from here.
                // The gap is the distance from the previous 'R' (or cell 0) to this 'R'.
                // The current cell is i+1. The previous 'R' was at last_R_pos.
                // The distance is (i+1) - last_R_pos.
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update last_R_pos to the current cell (i+1)
            }
        }

        // After iterating through all characters, we need to consider the jump from the last 'R'
        // (or cell 0 if no 'R's were found) to the target cell n+1.
        // The distance is (n+1) - last_R_pos.
        max_gap = std::max(max_gap, (static_cast<int>(s.length()) + 1) - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) { // Should not happen based on constraints (m >= 1), but good practice
            std::cout << 0 << "\n";
            continue;
        }

        long long count = n / m;

        if (count == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Calculate the sum of last digits for one full cycle of 10 multiples
        // i.e., (1*m)%10 + (2*m)%10 + ... + (10*m)%10
        long long sum_of_cycle_digits = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_of_cycle_digits += (static_cast<long long>(i) * m) % 10;
        }

        // Number of full cycles of 10 multiples
        long long num_full_cycles = count / 10;
        long long total_sum = num_full_cycles * sum_of_cycle_digits;

        // Remaining multiples after full cycles
        long long remaining_multiples = count % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <algorithm>
