int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks to minimize the absolute difference between medians.
        // Let the sorted array be a_0, a_1, ..., a_{2n-1}.
        //
        // Consider the case where one class has size S1 and the other has size S2.
        // S1 + S2 = 2n, and S1, S2 must be odd.
        //
        // Let's try to prove that the optimal partition always involves taking
        // the smallest n elements for one class and the largest n elements for the other,
        // or some other specific structure.
        //
        // The median of an array of size 2k+1 is the (k+1)-th element after sorting.
        //
        // If we sort the entire array a_0, a_1, ..., a_{2n-1}.
        //
        // Consider the two classes. Let their sizes be S1 = 2k1+1 and S2 = 2k2+1.
        // Then (2k1+1) + (2k2+1) = 2n => 2k1 + 2k2 + 2 = 2n => k1 + k2 + 1 = n.
        //
        // The median of the first class will be its (k1+1)-th element.
        // The median of the second class will be its (k2+1)-th element.
        //
        // Let's consider the specific partition where the first class takes elements
        // from a_0 to a_{n-1} and the second class takes elements from a_n to a_{2n-1}.
        // This is not a valid partition because both classes would have size n, which might be even.
        //
        // The key insight is that to minimize the difference between medians, we want the medians
        // to be as close as possible.
        //
        // Consider the sorted array a_0, a_1, ..., a_{2n-1}.
        //
        // If we pick the first class to be {a_0, ..., a_{n-1}} and the second class to be {a_n, ..., a_{2n-1}},
        // this is not valid because n can be even.
        //
        // The problem states that each class must have an odd number of students.
        //
        // Let's consider the two "middle" elements in the sorted array: a_{n-1} and a_n.
        //
        // If we form one class with elements up to a_{n-1} and another with elements from a_n onwards,
        // this is not necessarily valid.
        //
        // The crucial observation is that if we sort the entire array $a_0, a_1, \dots, a_{2n-1}$,
        // the median of any class will be one of these $a_i$ values.
        //
        // Consider the two classes. Let $M_1$ be the median of class 1 and $M_2$ be the median of class 2.
        // We want to minimize $|M_1 - M_2|$.
        //
        // Let's try to construct a partition.
        //
        // If we take the first $n$ elements $a_0, \dots, a_{n-1}$ and the last $n$ elements $a_n, \dots, a_{2n-1}$.
        // This is not a valid partition because $n$ can be even.
        //
        // The problem is simpler than it looks.
        //
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        //
        // We need to pick $S_1$ students for class 1 and $S_2$ students for class 2, where $S_1, S_2$ are odd and $S_1+S_2=2n$.
        //
        // Let's consider the two elements $a_{n-1}$ and $a_n$.
        //
        // Can we always form two classes such that $a_{n-1}$ is the median of one class and $a_n$ is the median of the other?
        //
        // If $a_{n-1}$ is the median of class 1, then class 1 must have $2k_1+1$ elements, and $a_{n-1}$ must be the $(k_1+1)$-th element.
        // This means there are $k_1$ elements smaller than or equal to $a_{n-1}$ in class 1, and $k_1$ elements greater than or equal to $a_{n-1}$ in class 1.
        //
        // If $a_n$ is the median of class 2, then class 2 must have $2k_2+1$ elements, and $a_n$ must be the $(k_2+1)$-th element.
        // This means there are $k_2$ elements smaller than or equal to $a_n$ in class 2, and $k_2$ elements greater than or equal to $a_n$ in class 2.
        //
        // The total number of elements is $2n$.
        //
        // Consider the partition where Class 1 consists of $a_0, a_1, \dots, a_{n-1}$ and Class 2 consists of $a_n, a_{n+1}, \dots, a_{2n-1}$.
        // Each class has $n$ students.
        // If $n$ is odd, this is a valid partition.
        // The median of Class 1 would be $a_{(n-1)/2}$.
        // The median of Class 2 would be $a_{n + (n-1)/2}$.
        //
        // However, $n$ can be even.
        //
        // The problem is much simpler. The minimum difference is always $a_n - a_{n-1}$.
        //
        // Let's prove this.
        //
        // Consider any partition into two classes, $C_1$ and $C_2$, with odd sizes $S_1$ and $S_2$.
        // Let $M_1$ be the median of $C_1$ and $M_2$ be the median of $C_2$.
        //
        // Let $S_1 = 2k_1+1$ and $S_2 = 2k_2+1$. We know $k_1+k_2+1 = n$.
        //
        // $M_1$ is the $(k_1+1)$-th element of $C_1$ when sorted.
        // $M_2$ is the $(k_2+1)$-th element of $C_2$ when sorted.
        //
        // In the original sorted array $a_0, \dots, a_{2n-1}$:
        //
        // $M_1$ must be at least $a_{k_1}$ (because there are $k_1$ elements in $C_1$ smaller than or equal to $M_1$, and these must come from $a_0, \dots, a_{k_1-1}$ at least).
        // $M_2$ must be at least $a_{k_2}$ (similarly).
        //
        // More precisely, $M_1$ is some $a_i$ and $M_2$ is some $a_j$.
        //
        // There are $k_1$ elements in $C_1$ that are $\le M_1$.
        // There are $k_1$ elements in $C_1$ that are $\ge M_1$.
        //
        // There are $k_2$ elements in $C_2$ that are $\le M_2$.
        // There are $k_2$ elements in $C_2$ that are $\ge M_2$.
        //
        // Total elements $\le M_1$ in $C_1$ is $k_1+1$.
        // Total elements $\le M_2$ in $C_2$ is $k_2+1$.
        //
        // Total elements $\ge M_1$ in $C_1$ is $k_1+1$.
        // Total elements $\ge M_2$ in $C_2$ is $k_2+1$.
        //
        // Assume $M_1 \le M_2$.
        //
        // The number of elements in the entire set $A$ that are $\le M_1$ is at least $k_1+1$.
        // So $M_1 \ge a_{k_1}$.
        //
        // The number of elements in the entire set $A$ that are $\ge M_2$ is at least $k_2+1$.
        // So $M_2 \le a_{2n - (k_2+1)}$.
        //
        // This doesn't seem to lead directly to $a_n - a_{n-1}$.
        //
        // Let's use a different argument.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ (the first $n$ elements) and $a_n, \dots, a_{2n-1}$ (the last $n$ elements).
        //
        // We need to form two classes $C_1, C_2$ of odd sizes $S_1, S_2$.
        //
        // Let $M_1$ be the median of $C_1$ and $M_2$ be the median of $C_2$.
        //
        // Suppose $M_1 < a_{n-1}$ and $M_2 > a_n$.
        // This is possible. For example, if $n=3$, $2n=6$. $a_0, \dots, a_5$.
        // $a_{n-1} = a_2$, $a_n = a_3$.
        // Class 1: $\{a_0, a_1, a_2\}$. Median $a_1$. $S_1=3$, $k_1=1$. $M_1=a_1$.
        // Class 2: $\{a_3, a_4, a_5\}$. Median $a_4$. $S_2=3$, $k_2=1$. $M_2=a_4$.
        // Difference is $a_4 - a_1$.
        // In this case, $a_n - a_{n-1} = a_3 - a_2$.
        // $a_4 - a_1$ could be larger than $a_3 - a_2$.
        //
        // The example $n=3$, $a = [1, 2, 3, 4, 5, 6]$. Sorted: $[1, 2, 3, 4, 5, 6]$.
        // $a_{n-1} = a_2 = 3$. $a_n = a_3 = 4$.
        // $a_n - a_{n-1} = 4 - 3 = 1$.
        //
        // Example partition from problem:
        // Class 1: $[6, 4, 2]$. Sorted: $[2, 4, 6]$. Median is $4$.
        // Class 2: $[5, 1, 3]$. Sorted: $[1, 3, 5]$. Median is $3$.
        // Difference $|4-3|=1$.
        //
        // This matches $a_n - a_{n-1}$.
        //
        // Let's try to prove that $a_n - a_{n-1}$ is always achievable.
        //
        // We need to construct two classes $C_1, C_2$ such that $M_1 = a_{n-1}$ and $M_2 = a_n$.
        //
        // Class 1: $a_0, a_1, \dots, a_{n-1}$. This has $n$ elements.
        // Class 2: $a_n, a_{n+1}, \dots, a_{2n-1}$. This has $n$ elements.
        //
        // If $n$ is odd:
        // Class 1 has $n$ elements. Median is $a_{(n-1)/2}$.
        // Class 2 has $n$ elements. Median is $a_{n + (n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // The problem statement is: "Among such partitions, you want to choose one in which the absolute difference between skill levels of the classes is minimized."
        //
        // The minimum possible difference is $a_n - a_{n-1}$.
        //
        // Proof:
        // Let $C_1$ and $C_2$ be the two classes, with medians $M_1$ and $M_2$.
        // Let $S_1 = 2k_1+1$ and $S_2 = 2k_2+1$ be their sizes.
        // We know $k_1+k_2+1 = n$.
        //
        // Without loss of generality, assume $M_1 \le M_2$.
        //
        // $M_1$ is the $(k_1+1)$-th smallest element in $C_1$.
        // This means there are at least $k_1+1$ elements in $C_1$ that are $\le M_1$.
        //
        // $M_2$ is the $(k_2+1)$-th smallest element in $C_2$.
        // This means there are at least $k_2+1$ elements in $C_2$ that are $\le M_2$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$. There are $n$ such elements.
        // Consider the elements $a_n, \dots, a_{2n-1}$. There are $n$ such elements.
        //
        // The total number of elements in $A$ that are less than or equal to $M_1$ is at least $k_1+1$.
        // So $M_1 \ge a_{k_1}$.
        //
        // The total number of elements in $A$ that are greater than or equal to $M_2$ is at least $k_2+1$.
        // So $M_2 \le a_{2n - (k_2+1)}$.
        //
        // This is not quite right.
        //
        // Let's use the property that $M_1$ is the $(k_1+1)$-th element of $C_1$.
        // This means there are $k_1$ elements in $C_1$ that are smaller than $M_1$.
        // And there are $k_1$ elements in $C_1$ that are larger than $M_1$.
        //
        // Similarly for $M_2$.
        //
        // Consider the element $a_{n-1}$.
        // There are $n-1$ elements $a_0, \dots, a_{n-2}$ that are $\le a_{n-1}$.
        // There are $n$ elements $a_n, \dots, a_{2n-1}$ that are $\ge a_{n-1}$.
        //
        // Consider the element $a_n$.
        // There are $n$ elements $a_0, \dots, a_{n-1}$ that are $\le a_n$.
        // There are $n-1$ elements $a_{n+1}, \dots, a_{2n-1}$ that are $\ge a_n$.
        //
        // Let $M_1$ and $M_2$ be the medians.
        // Suppose $M_1 < a_{n-1}$ and $M_2 > a_n$.
        //
        // The number of elements in $A$ that are $\le M_1$ is at least $k_1+1$.
        // The number of elements in $A$ that are $\ge M_2$ is at least $k_2+1$.
        //
        // The total number of elements in $A$ that are $\le M_1$ or $\ge M_2$ is at least $(k_1+1) + (k_2+1) = k_1+k_2+2 = n+1$.
        //
        // This means that there are at most $2n - (n+1) = n-1$ elements strictly between $M_1$ and $M_2$.
        //
        // This is not a direct proof that $M_2 - M_1 \ge a_n - a_{n-1}$.
        //
        // Let's try to construct a partition that achieves $a_n - a_{n-1}$.
        //
        // We need to assign $a_{n-1}$ to one class and $a_n$ to the other.
        //
        // Let $C_1$ be the class containing $a_{n-1}$.
        // Let $C_2$ be the class containing $a_n$.
        //
        // We want $M_1 = a_{n-1}$ and $M_2 = a_n$.
        //
        // To make $a_{n-1}$ the median of $C_1$, we need to pick $k_1$ elements smaller than $a_{n-1}$ and $k_1$ elements larger than $a_{n-1}$ for $C_1$.
        // To make $a_n$ the median of $C_2$, we need to pick $k_2$ elements smaller than $a_n$ and $k_2$ elements larger than $a_n$ for $C_2$.
        //
        // We have $n$ elements $a_0, \dots, a_{n-1}$ and $n$ elements $a_n, \dots, a_{2n-1}$.
        //
        // Consider the partition:
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        //
        // This partition is valid if $n$ is odd.
        // If $n$ is odd, then $S_1=n$ and $S_2=n$.
        // Median of Class 1 is $a_{(n-1)/2}$.
        // Median of Class 2 is $a_{n + (n-1)/2}$.
        // The difference is $a_{n+(n-1)/2} - a_{(n-1)/2}$. This is not $a_n - a_{n-1}$.
        //
        // The example $n=3$, $a = [1, 2, 3, 4, 5, 6]$.
        // $a_2=3, a_3=4$. Difference $1$.
        // The example partition was Class 1: $[2,4,6]$ (median 4), Class 2: $[1,3,5]$ (median 3). Difference 1.
        //
        // This partition is not $\{a_0, a_1, a_2\}$ and $\{a_3, a_4, a_5\}$.
        //
        // The key is that $a_{n-1}$ and $a_n$ are the two middle elements in the sorted array.
        //
        // Let $M_1$ and $M_2$ be the medians of the two classes.
        //
        // Claim: $M_1 \le a_n$ and $M_2 \ge a_{n-1}$.
        //
        // Proof by contradiction:
        // Suppose $M_1 > a_n$.
        // This means $C_1$ contains $M_1$ and $k_1$ elements larger than $M_1$.
        // So $C_1$ contains at least $k_1+1$ elements that are $> a_n$.
        // The elements $> a_n$ are $a_{n+1}, \dots, a_{2n-1}$. There are $n-1$ such elements.
        // So $k_1+1 \le n-1$.
        //
        // Suppose $M_2 < a_{n-1}$.
