int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it can potentially be paired with
            // all 'a's to its left that are currently active.
            // Each such 'a' will eventually move past this 'b'.
            // When an 'a' moves past a 'b', it creates a new 'b'.
            // So, if we have `count_a` 'a's to the left of this 'b',
            // this 'b' will cause `count_a` operations.
            // After these operations, this 'b' will be to the left of all those 'a's.
            // The new 'b's created will also be to the left of those 'a's.
            // The key insight is that each 'a' to the left of a 'b' will eventually
            // pass that 'b'. When it passes, it contributes 1 to the total steps
            // and effectively doubles the number of 'a's that are "active"
            // for subsequent 'b's to its left.
            // This is because the 'a' moves past the 'b', and a new 'b' is inserted.
            // The 'a' is now to the right of the original 'b' and the new 'b'.
            // The 'a' effectively "carries" its potential to interact with 'b's.
            // The number of 'a's that can interact with 'b's to their left effectively doubles.

            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it adds to the count of 'a's
            // that are to the left of any 'b's we encounter later (to its left in the string).
            // This 'a' itself will eventually need to move past any 'b's to its right.
            // For the purpose of counting operations for 'b's to its left,
            // this 'a' is now available.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

