// Function to convert a number to its parity pattern string
// The pattern string will always have 18 characters, padded with '0's from the left.
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the right to make it 18 characters long
    // This effectively pads with '0's from the left in the original number's representation
    // because we built the string from right to left.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    // Reverse to get the correct order (most significant parity digit first)
    // No, wait, the problem says "i-th from the right digit".
    // So if we build it from right to left, the string is already in the correct order for comparison.
    // Example: 92 -> '1' (for 9), '0' (for 2). String becomes "10".
    // Pattern 010.
    // If we pad "10" to "100000000000000000" and pattern "010" to "010000000000000000"
    // This is not what the example implies.
    // "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // "If the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This means we should align them by their rightmost digit.
    // So, for 92, its parity pattern is "10".
    // For 010, its pattern is "010".
    // To compare, we need to pad the shorter one with '0's from the left.
    // Example: 92 (parity "10"), pattern "010".
    // Padded 92: "010" (from "092")
    // Padded pattern: "010"
    // They match.
    // This means we should always store the pattern as a fixed-length string, say 18,
    // by padding with '0's from the left.
    // My current `pattern` string is built from right to left.
    // So for 92, `pattern` becomes "01".
    // For 2212, `pattern` becomes "0100".
    // We need to pad this to 18 characters with '0's at the end (which corresponds to left padding in the number).
    // Then reverse it to get the standard representation.
    // Let's re-evaluate.
    // Number 92. Rightmost digit 2 (even) -> 0. Next digit 9 (odd) -> 1.
    // So the parity string for 92 is "10".
    // Pattern "010".
    // To compare, we need to align them.
    // "010" (pattern)
    // " 10" (number 92)
    // Pad number with '0' from left: "010"
    // They match.
    // This means we should store the canonical form of the parity pattern as a fixed-length string (e.g., 18 chars)
    // by padding with '0's from the LEFT.
    // My current `pattern` string is built from right to left.
    // For 92, `pattern` is "01".
    // For 2212, `pattern` is "0100".
    // To get the canonical 18-char string, we need to pad `pattern` with '0's at the end, then reverse.
    // Example: 92 -> "01". Pad to 18: "010000000000000000". Reverse: "000000000000000010". This is the canonical form.
    std::reverse(pattern.begin(), pattern.end());
    std::string canonical_pattern(18 - pattern.length(), '0');
    canonical_pattern += pattern;
    return canonical_pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;
        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to make it 18 characters long
            std::string query_pattern(18 - s.length(), '0');
            query_pattern += s;
            std::cout << counts[query_pattern] << "\n";
        }
    }

    return 0;
}

