#include <iostream>
#include <vector>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long min_x = -2000000000LL; // Effectively negative infinity
    long long max_x = 2000000000LL;  // Effectively positive infinity
    long long min_y = -2000000000LL; // Effectively negative infinity
    long long max_y = 2000000000LL;  // Effectively positive infinity

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1 = 1: can move left (x-1, y). If f1=0, cannot move left.
        // This means the robot cannot reach any point to its left.
        // So, the target X must be >= current x.
        if (f1 == 0) { // Cannot move left
            min_x = std::max(min_x, x);
        }
        // f3 = 1: can move right (x+1, y). If f3=0, cannot move right.
        // This means the robot cannot reach any point to its right.
        // So, the target X must be <= current x.
        if (f3 == 0) { // Cannot move right
            max_x = std::min(max_x, x);
        }
        // f4 = 1: can move down (x, y-1). If f4=0, cannot move down.
        // This means the robot cannot reach any point below it.
        // So, the target Y must be >= current y.
        if (f4 == 0) { // Cannot move down
            min_y = std::max(min_y, y);
        }
        // f2 = 1: can move up (x, y+1). If f2=0, cannot move up.
        // This means the robot cannot reach any point above it.
        // So, the target Y must be <= current y.
        if (f2 == 0) { // Cannot move up
            max_y = std::min(max_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // The problem guarantees that if a solution exists, one exists within [-10^5, 10^5].
        // We can pick any point within the valid range.
        // For example, (min_x, min_y) is a valid point.
        // We need to clamp it to the guaranteed range if it falls outside,
        // but since the problem guarantees a solution within [-10^5, 10^5]
        // if one exists, and our bounds are initialized to much larger values,
        // min_x and min_y will naturally be within the required range if a solution exists.
        // The coordinates are up to 10^5, so the bounds can be up to 10^5.
        // The problem statement says "both X and Y should not exceed 10^5 by absolute value".
        // So, we should output a point (X, Y) where -10^5 <= X, Y <= 10^5.
        // The calculated min_x and min_y will be within this range if a solution exists.
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
        std::cout << 0 << "\n";
    }
}

