void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
        return;
    }

    // We need to append elements x, y, z such that (current_sum + x + y + z) = 2 * (current_xor_sum ^ x ^ y ^ z)
    // Let's try to append at most 2 elements first.
    // If we append one element 'x':
    // (current_sum + x) = 2 * (current_xor_sum ^ x)
    // This is hard to solve directly for x.

    // Let's try to append two elements.
    // A common strategy for these problems is to make the XOR sum equal to some value,
    // and then adjust the sum.
    // Let's try to make the final XOR sum equal to current_xor_sum.
    // This can be done by appending current_xor_sum and 0.
    // Or by appending current_xor_sum and current_xor_sum.
    // Or by appending current_xor_sum and current_xor_sum, and then 0.

    // Consider appending two elements: current_xor_sum and current_sum + current_xor_sum.
    // Let x1 = current_xor_sum
    // Let x2 = current_sum + current_xor_sum
    // New XOR sum: X' = current_xor_sum ^ x1 ^ x2
    // X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    // X' = 0 ^ (current_sum + current_xor_sum)
    // X' = current_sum + current_xor_sum

    // New sum: S' = current_sum + x1 + x2
    // S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    // S' = 2 * (current_sum + current_xor_sum)

    // Check if S' = 2 * X'
    // S' = 2 * (current_sum + current_xor_sum)
    // X' = current_sum + current_xor_sum
    // So, S' = 2 * X' is satisfied.

    // The appended elements are current_xor_sum and current_sum + current_xor_sum.
    // These are non-negative.
    // current_xor_sum can be up to 2^30 - 1 (max a_i is 10^9, so XOR sum is also bounded by 2^30).
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // So current_sum + current_xor_sum can be up to 10^14 + 2^30, which fits in long long.
    // The problem states appended elements can be up to 10^18. This is fine.

    std::cout << 2 << "\n";
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
}

