#include <iostream>

long long sum_arithmetic_series(long long n) {
    if (n <= 0) return 0;
    long long MOD = 1000000007;
    long long n_mod = n % MOD;
    long long n_plus_1_mod = (n + 1) % MOD;
    long long term1 = (n_mod * n_plus_1_mod) % MOD;
    long long inv2 = 500000004; // Modular inverse of 2 modulo 10^9 + 7
    return (term1 * inv2) % MOD;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // The sum is sum_{k=1 to a} sum_{r=1 to b-1} (r * (k * b + 1))
    // This can be rewritten as:
    // (sum_{k=1 to a} (k * b + 1)) * (sum_{r=1 to b-1} r)

    // Calculate sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    long long sum_r_term = sum_arithmetic_series(b - 1);

    // Calculate sum_{k=1 to a} (k * b + 1)
    // This is sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // = b * (sum_{k=1 to a} k) + a
    // = b * (a * (a+1) / 2) + a
    long long sum_k_term_part1 = (b % MOD * sum_arithmetic_series(a)) % MOD;
    long long sum_k_term_part2 = a % MOD;
    long long sum_k_term = (sum_k_term_part1 + sum_k_term_part2) % MOD;

    long long total_sum = (sum_k_term * sum_r_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

