    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char c1_actual = s[k_actual];

        // For a fixed k_actual, Vasya knows c1_actual.
        // He needs to choose p optimally to maximize his win probability for this k_actual.
        // This is equivalent to maximizing the probability of winning given c1_actual.
        // The problem statement says "at any moment of the game Vasya wants to maximize the probability of his win."
        // This implies that for each possible c1_actual, Vasya chooses p to maximize his win probability.
        // Since k_actual is chosen uniformly, we average over k_actual.

        // For a given c1_actual, Vasya considers all k' such that s[k'] == c1_actual.
        // Let S_c1 be the set of all such k'.
        // Vasya wants to choose p such that for the maximum number of k' in S_c1,
        // the pair (s[k'], s[(k'+p)%L]) is unique among all k'' in S_c1.

        // Let's rephrase: Vasya knows c1_actual. He wants to choose p.
        // For each possible p, he calculates how many k' (where s[k'] == c1_actual)
        // would lead to a unique (c1_actual, s[(k'+p)%L]) pair.
        // He picks the p that maximizes this count.

        // For a fixed k_actual, c1_actual = s[k_actual].
        // Vasya will choose p to maximize the number of k' such that s[k'] == c1_actual
        // AND (s[k'], s[(k'+p)%L]) is unique among all k'' where s[k''] == c1_actual.

        // Let's iterate over all possible p (from 1 to L-1).
        // For each p, we count how many k' (such that s[k'] == c1_actual)
        // would result in a unique (c1_actual, s[(k'+p)%L]) pair.

        int max_unique_count_for_c1 = 0;

        for (int p = 1; p < L; ++p) {
            std::map<char, int> counts_c2; // counts of s[(k'+p)%L] for k' where s[k'] == c1_actual
            for (int k_prime : char_indices[c1_actual - 'a']) {
                counts_c2[s[(k_prime + p) % L]]++;
            }

            int current_unique_count = 0;
            for (int k_prime : char_indices[c1_actual - 'a']) {
                if (counts_c2[s[(k_prime + p) % L]] == 1) {
                    current_unique_count++;
                }
            }
            max_unique_count_for_c1 = std::max(max_unique_count_for_c1, current_unique_count);
        }
        total_win_prob += static_cast<double>(max_unique_count_for_c1);
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

