int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize two "test" values: 0 and 1023 (all bits set)
    // We track how these values change after all operations.
    // This allows us to determine the final state of each bit.
    int val0 = 0;    // Represents the state of a bit that was initially 0
    int val1023 = 1023; // Represents the state of a bit that was initially 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1023 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1023 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1023 ^= x;
        }
    }

    // Now, for each bit position j (0 to 9):
    // If the j-th bit of val0 is 0 and j-th bit of val1023 is 0:
    //   The bit always becomes 0, regardless of initial state. (x_j -> 0)
    // If the j-th bit of val0 is 1 and j-th bit of val1023 is 1:
    //   The bit always becomes 1, regardless of initial state. (x_j -> 1)
    // If the j-th bit of val0 is 0 and j-th bit of val1023 is 1:
    //   The bit remains unchanged. (x_j -> x_j)
    // If the j-th bit of val0 is 1 and j-th bit of val1023 is 0:
    //   The bit is flipped. (x_j -> !x_j)

    // We want to find constants A, B, C such that:
    // ( (x & A) | B ) ^ C  is equivalent to the final state.
    // Or, more generally, a sequence of at most 5 operations.
    // A single AND, OR, XOR operation is sufficient.
    // Let's find the combined effect for each bit.

    int final_and_const = 1023; // All bits 1 initially
    int final_or_const = 0;     // All bits 0 initially
    int final_xor_const = 0;    // All bits 0 initially

    for (int j = 0; j < 10; ++j) {
        int bit_val0 = (val0 >> j) & 1;
        int bit_val1023 = (val1023 >> j) & 1;

        if (bit_val0 == 0 && bit_val1023 == 0) {
            // x_j -> 0. This means we need to force the bit to 0.
            // This can be achieved by ANDing with 0 at this bit position.
            final_and_const &= ~(1 << j); // Set j-th bit of final_and_const to 0
        } else if (bit_val0 == 1 && bit_val1023 == 1) {
            // x_j -> 1. This means we need to force the bit to 1.
            // This can be achieved by ORing with 1 at this bit position.
            final_or_const |= (1 << j); // Set j-th bit of final_or_const to 1
        } else if (bit_val0 == 0 && bit_val1023 == 1) {
            // x_j -> x_j. Bit remains unchanged.
            // ANDing with 1, ORing with 0, XORing with 0 achieves this.
            // No change needed for final_and_const, final_or_const, final_xor_const at this bit.
        } else { // bit_val0 == 1 && bit_val1023 == 0
            // x_j -> !x_j. Bit is flipped.
            // This can be achieved by XORing with 1 at this bit position.
            final_xor_const |= (1 << j); // Set j-th bit of final_xor_const to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_const != 1023) { // If any bit needs to be forced to 0
        result_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) { // If any bit needs to be forced to 1
        result_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) { // If any bit needs to be flipped
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

