#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        long long good_substrings_count = 0;

        // Precompute positions of '1's
        std::vector<int> ones_pos;
        for (int i = 0; i < n; ++i) {
            if (s[i] == '1') {
                ones_pos.push_back(i);
            }
        }

        for (int i = 0; i < n; ++i) {
            // Case 1: Substring starts with '1'
            // s[i] is '1'
            if (s[i] == '1') {
                long long current_val = 0;
                for (int j = i; j < n; ++j) {
                    current_val = current_val * 2 + (s[j] - '0');
                    int len = j - i + 1;

                    // Optimization: If current_val exceeds a reasonable bound, break.
                    // Max len is 2e5. Max value for len=20 is 2^20 ~ 1e6.
                    // If current_val > n + 20 (approx), it's too large.
                    // A safe upper bound for current_val is n + max_leading_zeros_to_check (e.g., 20)
                    // If len > 20, current_val will be very large.
                    // If current_val > n + 20, it's unlikely to be equal to len.
                    // The maximum possible value for len is n.
                    // If current_val > n + 20, it's definitely not equal to len.
                    // The maximum value of len for which len = 2^(len-1) is true is len=2.
                    // For len=3, 3 < 4. For len=4, 4 < 8.
                    // So if s[i] == '1', current_val >= 2^(len-1).
                    // We need len = current_val.
                    // This implies len >= 2^(len-1). This is only true for len=1, 2.
                    // For len >= 3, len < 2^(len-1).
                    // So if s[i] == '1', and len >= 3, then len != current_val.
                    // This means we only need to check len=1, 2 for s[i]=='1'.
                    // This logic is flawed. current_val is not necessarily 2^(len-1).
                    // It's 2^(len-1) + ...
                    // The condition is len = current_val.
                    // If len is large, current_val will be much larger than len.
                    // For example, if len = 20, current_val >= 2^19.
                    // So if current_val > n + 20 (a loose upper bound for len), we can break.
                    if (current_val > n + 20) { // A safe upper bound for current_val to be equal to len
                        break;
                    }

                    if (current_val == len) {
                        good_substrings_count++;
                    }
                }
            }
            // Case 2: Substring starts with '0'
            // s[i] is '0'
            else {
                // Find the next '1' after or at index i.
                // If there's no '1' after i, then all subsequent substrings starting at i are '0's.
                // f(00...0) = 0. Length must be 0, which is impossible.
                // So we only care about substrings like 0...01...
                auto it = std::upper_bound(ones_pos.begin(), ones_pos.end(), i);
                if (it == ones_pos.end()) {
                    // No '1's from index i onwards. All substrings starting with s[i] will be all '0's.
                    // f(0...0) = 0. Length must be 0. No good substrings.
                    continue;
                }

                int first_one_idx = *it;

                // The number of leading zeros is first_one_idx - i.
                // Let k = first_one_idx - i be the count of leading zeros.
                // The substring is s[i...j].
                // The value is f(s[i...j]) = f(s[first_one_idx...j]).
                // The length is j - i + 1.
                // We need j - i + 1 = f(s[first_one_idx...j]).

                long long current_val = 0;
                for (int j = first_one_idx; j < n; ++j) {
                    current_val = current_val * 2 + (s[j] - '0');

                    // Optimization: If current_val exceeds a reasonable bound, break.
                    if (current_val > n + 20) { // Same logic as above
                        break;
                    }

                    int len = j - i + 1;

                    // The number of leading zeros is first_one_idx - i.
                    // The length of the '1'-prefixed part is j - first_one_idx + 1.
                    // The total length is len = (first_one_idx - i) + (j - first_one_idx + 1).
                    // We need len = current_val.
                    // So, (first_one_idx - i) + (j - first_one_idx + 1) = current_val.
                    // This means (j - first_one_idx + 1) = current_val - (first_one_idx - i).
                    // Let L_prime = j - first_one_idx + 1 be the length of the suffix starting with '1'.
                    // We need L_prime = current_val - (first_one_idx - i).
                    // The number of leading zeros is k = first_one_idx - i.
                    // We need len = current_val.
                    // len = k + L_prime.
                    // So k = current_val - L_prime.
                    // We need to check if k (number of leading zeros) is equal to current_val - L_prime.
                    // And k must be non-negative.

                    if (current_val >= (j - first_one_idx + 1)) { // current_val must be at least the length of the '1'-prefixed part
                        int required_leading_zeros = static_cast<int>(current_val - (j - first_one_idx + 1));
                        if (required_leading_zeros == (first_one_idx - i)) {
                            good_substrings_count++;
                        }
                    }
                }
            }
        }
        std::cout << good_substrings_count << "\n";
    }
    return 0;
}

