void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left part (jars 1 to n)
    // and suffix sums for the right part (jars n+1 to 2n)
    // Convert 1 to +1, 2 to -1
    // The balance is (count of 1s) - (count of 2s)

    // Balances for the left part (jars 1 to n)
    // left_balances[k] = balance of jars [n-k+1, n]
    // This is equivalent to prefix sums from right to left for jars 1 to n
    // Or, if we consider jars 1 to n as indices 0 to n-1:
    // left_balances[k] = balance of jars [n-k, n-1]
    std::map<int, int> left_balances_map; // balance -> max_k (number of jars from left part)
    left_balances_map[0] = 0; // Keeping 0 jars from the left part gives balance 0

    int current_balance_left = 0;
    for (int i = n - 1; i >= 0; --i) {
        current_balance_left += (a[i] == 1 ? 1 : -1);
        if (left_balances_map.find(current_balance_left) == left_balances_map.end()) {
            left_balances_map[current_balance_left] = (n - i);
        }
    }

    // Balances for the right part (jars n+1 to 2n)
    // right_balances[k] = balance of jars [n+1, n+k]
    // This is equivalent to prefix sums from left to right for jars n+1 to 2n
    // Or, if we consider jars n+1 to 2n as indices n to 2n-1:
    // right_balances[k] = balance of jars [n, n+k-1]
    std::map<int, int> right_balances_map; // balance -> max_k (number of jars from right part)
    right_balances_map[0] = 0; // Keeping 0 jars from the right part gives balance 0

    int current_balance_right = 0;
    for (int i = n; i < 2 * n; ++i) {
        current_balance_right += (a[i] == 1 ? 1 : -1);
        if (right_balances_map.find(current_balance_right) == right_balances_map.end()) {
            right_balances_map[current_balance_right] = (i - n + 1);
        }
    }

    int min_removed = 2 * n; // Initialize with maximum possible removed jars

    // Iterate through all possible balances from the left part
    // For each left_balance, we need to find a right_balance such that left_balance + right_balance = 0
    // i.e., right_balance = -left_balance
    for (auto const& [l_bal, l_len] : left_balances_map) {
        int target_r_bal = -l_bal;
        if (right_balances_map.count(target_r_bal)) {
            int r_len = right_balances_map[target_r_bal];
            int kept_jars = l_len + r_len;
            min_removed = std::min(min_removed, 2 * n - kept_jars);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    for (int split_val = 0; split_val <= 9; ++split_val) {
        std::vector<int> colors(n);
        int last1 = -1; // Last digit colored 1
        int last2 = -1; // Last digit colored 2
        bool possible = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < split_val) {
                // Must be color 1
                if (d[i] < last1) {
                    possible = false;
                    break;
                }
                colors[i] = 1;
                last1 = d[i];
            } else if (d[i] > split_val) {
                // Must be color 2
                if (d[i] < last2) {
                    possible = false;
                    break;
                }
                colors[i] = 2;
                last2 = d[i];
            } else { // d[i] == split_val
                // Can be color 1 or 2. Prefer 2 if possible to keep 1s small.
                if (d[i] >= last2) { // Can be color 2
                    colors[i] = 2;
                    last2 = d[i];
                } else if (d[i] >= last1) { // Must be color 1
                    colors[i] = 1;
                    last1 = d[i];
                } else { // Cannot be color 1 or 2
                    possible = false;
                    break;
                }
            }
        }

        if (possible) {
            // Final check: last1 <= first2.
            // This is implicitly handled by the logic.
            // If a digit is colored 1, it must be <= split_val.
            // If a digit is colored 2, it must be >= split_val.
            // So last1 (max of color 1 digits) will be <= split_val.
            // And first2 (min of color 2 digits) will be >= split_val.
            // Thus last1 <= first2 is always true.

            for (int i = 0; i < n; ++i) {
                std::cout << colors[i];
            }
            std::cout << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            long long current_prime = i;
            long long p_copy = p;
            long long count_p = 0;
            while (p_copy > 0 && p_copy % current_prime == 0) {
                p_copy /= current_prime;
                count_p++;
            }

            long long count_q = 0;
            while (temp_q % current_prime == 0) {
                temp_q /= current_prime;
                count_q++;
            }

            // We need to remove at least one factor of current_prime from p
            // such that the resulting x is not divisible by q.
            // The largest such x would be p / (current_prime ^ (count_q - 1 + 1))
            // which is p / (current_prime ^ count_q)
            // This ensures that x has one less factor of current_prime than q,
            // so x is not divisible by q (specifically, not divisible by current_prime^count_q).
            // But we need x to not be divisible by q.
            // If p is divisible by q, then p has at least count_q factors of current_prime.
            // To make x not divisible by q, we need to remove enough factors of current_prime
            // from p such that x no longer has count_q factors of current_prime.
            // The largest such x would be p / (current_prime ^ (count_p - (count_q - 1)))
            // which simplifies to p / (current_prime ^ (count_p - count_q + 1))
            // No, this is wrong.
            // We need to find the largest x = p / (current_prime ^ k) such that x % q != 0.
            // If p is divisible by q, then p has at least count_q factors of current_prime.
            // To make x not divisible by q, we must ensure that x does not have count_q factors of current_prime.
            // The largest such x would be p / (current_prime ^ (count_p - (count_q - 1)))
            // This is p / (current_prime ^ (count_p - count_q + 1)).
            // This is the largest divisor of p that has exactly (count_q - 1) factors of current_prime.
            // This x is guaranteed not to be divisible by current_prime^count_q, and thus not by q.
            // We need to find the largest x that is a divisor of p and x % q != 0.
            // For each prime factor `current_prime` of `q`, let `q_power` be the exponent of `current_prime` in `q`.
            // Let `p_power` be the exponent of `current_prime` in `p`.
            // Since `p % q == 0`, we know `p_power >= q_power`.
            // To make `x` not divisible by `q`, `x` must not be divisible by `current_prime^q_power`.
            // The largest divisor of `p` that is not divisible by `current_prime^q_power` is `p / (current_prime^q_power)`.
            // This is because `p / (current_prime^q_power)` has `p_power - q_power` factors of `current_prime`.
            // Since `p_power - q_power >= 0`, this is a valid divisor.
            // And `p_power - q_power < q_power` is not necessarily true.
            // Example: p=12, q=6. p=2^2*3, q=2*3.
            // current_prime=2. q_power=1. p_power=2.
            // x = p / (2^1) = 6. But 6 % 6 == 0. This is wrong.
            // The logic should be: we want to remove just enough factors of `current_prime` from `p`
            // such that the resulting `x` is no longer divisible by `q`.
            // If `p` is divisible by `q`, then `p` has at least `count_q` factors of `current_prime`.
            // To make `x` not divisible by `q`, we must ensure that `x` does not have `count_q` factors of `current_prime`.
            // The largest such `x` would be `p / (current_prime ^ count_q)`.
            // This `x` has `count_p - count_q` factors of `current_prime`.
            // This `x` is guaranteed not to be divisible by `current_prime ^ count_q`.
            // So, `x` is not divisible by `q`.
            // We need to find the maximum `x` among all such candidates.
            max_x = std::max(max_x, p / static_cast<long long>(std::pow(current_prime, count_q)));
        }
    }

    if (temp_q > 1) { // temp_q is a prime factor itself
        long long current_prime = temp_q;
        long long p_copy = p;
        long long count_p = 0;
        while (p_copy > 0 && p_copy % current_prime == 0) {
            p_copy /= current_prime;
            count_p++;
        }
        long long count_q = 1; // temp_q is prime, so its power is 1
        max_x = std::max(max_x, p / static_cast<long long>(std::pow(current_prime, count_q)));
    }

    return max_x;
}

