#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// The sum can exceed 2^31-1.
// x can also exceed n temporarily, but it's checked against n after each step.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a_1 is set for each run, so we only read a_2 to a_n.
    // We'll use 1-based indexing for convenience, so vector size n+1.
    // a[0] will be unused. a[1] will be set dynamically.
    std::vector<long long> a(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    // dp[i] stores the result for starting x=i, y=0.
    // dp[i].first is the final x value, dp[i].second is the final y value.
    // We use -1 for x to indicate non-termination.
    std::vector<std::pair<long long, long long>> dp(n + 1, {-2, -2}); // Initialize with sentinel values

    // Function to compute result for a given starting x_val
    // This is a recursive function with memoization.
    // It returns {final_x, final_y}
    auto solve = [&](auto self, int current_x) -> std::pair<long long, long long> {
        if (current_x <= 0 || current_x > n) {
            return {current_x, 0}; // Base case: terminated
        }
        if (dp[current_x].first != -2) {
            return dp[current_x]; // Memoized result
        }

        // Mark as currently computing to detect cycles
        dp[current_x] = {-1, -1}; // Sentinel for "currently computing" or "infinite loop"

        // Step 1: x = x + a[x], y = y + a[x]
        long long val_ax = a[current_x];
        long long next_x1 = current_x + val_ax;
        long long current_y_contribution = val_ax;

        // Check termination after step 1
        if (next_x1 <= 0 || next_x1 > n) {
            dp[current_x] = {next_x1, current_y_contribution};
            return dp[current_x];
        }

        // Step 2: y = y + a[x'], x = x' - a[x']
        long long val_ax_prime = a[next_x1];
        long long next_x2 = next_x1 - val_ax_prime;
        current_y_contribution += val_ax_prime;

        // Recursively call for the next state
        std::pair<long long, long long> res = self(self, next_x2);

        if (res.first == -1) { // If recursive call detected an infinite loop
            dp[current_x] = {-1, -1};
        } else {
            dp[current_x] = {res.first, current_y_contribution + res.second};
        }
        return dp[current_x];
    };

    for (int i = 1; i < n; ++i) {
        // Reset dp table for each run, except for the values that are fixed (a_2 to a_n)
        // We only need to clear dp[1] for each run, as a[1] changes.
        // However, the problem states "Suppose for each i (1 <= i <= n - 1) we run the program on the sequence i, a_2, a_3, ..., a_n."
        // This implies a fresh run for each i, so the entire dp table should be cleared or recomputed.
        // Since a[1] is the only changing value, we can recompute only paths that depend on a[1].
        // But a simpler approach is to clear the whole dp table for each i, or compute it from scratch.
        // Given N up to 2*10^5, N*N complexity is too high.
        // The key observation is that the values a_2...a_n are fixed.
        // Only a_1 changes.
        // The DP state (x, y) depends on a[x].
        // If we start at x=1, the first step uses a[1].
        // All subsequent steps use a[x] where x >= 2.
        // So, we can precompute results for starting positions x=2 to n.
        // Then for each i, we just compute the first step using a[1]=i, and then use the precomputed result.

        // Clear dp table for this run.
        // This is inefficient if done naively.
        // Instead, we can compute dp for x=2 to n once.
        // Then for each i, we compute the first step and use the precomputed dp.

        // Let's re-evaluate the DP state.
        // dp[x] stores the result if we start the *loop* at x.
        // The loop starts with x=1, y=0.
        // First, x becomes 1+a[1], y becomes a[1].
        // Then, x becomes (1+a[1]) - a[1+a[1]], y becomes a[1] + a[1+a[1]].
        // This is exactly what the `solve` function does.
        // The `solve` function computes the result for a given `current_x` assuming `a[current_x]` is fixed.
        // The `a` array is mostly fixed, except for `a[1]`.
        // So, we can compute `dp[x]` for `x=2...n` once.
        // For `x=1`, `a[1]` changes.

        // Reset dp table for this specific run.
        // This is the crucial part. If we reset the whole dp table for each i, it's O(N^2).
        // We need to avoid that.
        // The `solve` function is called with `current_x`.
        // If `current_x` is 1, `a[1]` is `i`.
        // If `current_x` is > 1, `a[current_x]` is fixed.
        // So, we can compute `dp[x]` for `x=2...n` once.
        // Then for each `i`, we compute `dp[1]` using `a[1]=i`.

        // Reset dp table for this run.
        // Only dp[1] needs to be reset for each iteration.
        // Other dp[x] (x > 1) can be computed once.
        // Let's use a separate dp table for the fixed part.
        static std::vector<std::pair<long long, long long>> fixed_dp(n + 1, {-2, -2});
        static bool fixed_dp_computed = false;

        if (!fixed_dp_computed) {
            // Compute fixed_dp for x = 2 to n
            // For this, we need a temporary a[1] value, but it won't be used.
            // The solve function will only be called for x >= 2.
            for (int k = 2; k <= n; ++k) {
                if (fixed_dp[k].first == -2) { // If not computed yet
                    // Use a lambda that captures 'a' and 'fixed_dp'
                    std::function<std::pair<long long, long long>(int)> fixed_solve = 
                        [&](int current_x_fixed) -> std::pair<long long, long long> {
                        if (current_x_fixed <= 0 || current_x_fixed > n) {
                            return {current_x_fixed, 0};
                        }
                        if (fixed_dp[current_x_fixed].first != -2) {
                            return fixed_dp[current_x_fixed];
                        }

                        fixed_dp[current_x_fixed] = {-1, -1}; // Mark as computing/cycle detected

                        long long val_ax = a[current_x_fixed];
                        long long next_x1 = current_x_fixed + val_ax;
                        long long current_y_contribution = val_ax;

                        if (next_x1 <= 0 || next_x1 > n) {
                            fixed_dp[current_x_fixed] = {next_x1, current_y_contribution};
                            return fixed_dp[current_x_fixed];
                        }

                        long long val_ax_prime = a[next_x1];
                        long long next_x2 = next_x1 - val_ax_prime;
                        current_y_contribution += val_ax_prime;

                        std::pair<long long, long long> res = fixed_solve(next_x2);

                        if (res.first == -1) {
                            fixed_dp[current_x_fixed] = {-1, -1};
                        } else {
                            fixed_dp[current_x_fixed] = {res.first, current_y_contribution + res.second};
                        }
                        return fixed_dp[current_x_fixed];
                    };
                    fixed_solve(k);
                }
            }
            fixed_dp_computed = true;
        }

        // Now, for each i, we set a[1] = i and compute the result.
        a[1] = i;

        // The actual solve function for the current run.
        // It will use a[1] = i, and for x > 1, it will use fixed_dp.
        std::function<std::pair<long long, long long>(int)> current_solve = 
            [&](int current_x_run) -> std::pair<long long, long long> {
            if (current_x_run <= 0 || current_x_run > n) {
                return {current_x_run, 0};
            }

            // If current_x_run is 1, we need to compute it.
            // If current_x_run > 1, we can use fixed_dp.
            if (current_x_run > 1) {
                return fixed_dp[current_x_run];
            }

            // This part is only for current_x_run == 1
            // We need a temporary dp[1] for this specific run.
            // We can't use the global dp[1] because it changes.
            // Let's just compute it directly without memoization for x=1,
            // as it's only one path.

            // This is the first step for x=1.
            long long val_a1 = a[1];
            long long next_x1_from_1 = 1 + val_a1;
            long long current_y_contribution_from_1 = val_a1;

            if (next_x1_from_1 <= 0 || next_x1_from_1 > n) {
                return {next_x1_from_1, current_y_contribution_from_1};
            }

            long long val_ax_prime_from_1 = a[next_x1_from_1];
            long long next_x2_from_1 = next_x1_from_1 - val_ax_prime_from_1;
            current_y_contribution_from_1 += val_ax_prime_from_1;

            // Now, from next_x2_from_1, we can use the fixed_dp.
            std::pair<long long, long long> res = fixed_dp[next_x2_from_1];

            if (res.first == -1) { // If fixed_dp detected an infinite loop
                return {-1, -1};
            } else {
                return {res.first, current_y_contribution_from_1 + res.second};
            }
        };

        std::pair<long long, long long> result = current_solve(1);

        if (result.first == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << result.second << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, LLONG_MAX); // b[i] stores the maximum possible initial value for a[i]

    // Process type 2 operations in reverse to find upper bounds for b[i]
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 2) {
            long long current_max_val = ops[i].val;
            long long current_delta_sum = 0; // Sum of d's applied to elements in this range *after* this operation
            for (int j = i + 1; j < m; ++j) {
                if (ops[j].type == 1) {
                    if (ops[j].l <= ops[i].r && ops[j].r >= ops[i].l) { // If ranges overlap
                        current_delta_sum += ops[j].val;
                    }
                }
            }

            // For each element k in the range [ops[i].l, ops[i].r],
            // its initial value a_0[k] must be <= current_max_val - current_delta_sum.
            // We want to find the tightest upper bound for a_0[k], so we take the minimum.
            for (int k = ops[i].l; k <= ops[i].r; ++k) {
                b[k] = std::min(b[k], current_max_val - current_delta_sum);
            }
        }
    }

    // Initialize a_0 based on b. If b[i] is still LLONG_MAX, it means no type 2 operation
    // constrained it. We can set it to 0 (or any value within [-10^9, 10^9]).
    // A value of 0 is safe and satisfies the absolute value constraint.
    std::vector<long long> a0(n);
    for (int i = 0; i < n; ++i) {
        if (b[i] == LLONG_MAX) {
            a0[i] = 0;
        } else {
            a0[i] = b[i];
        }
        // Ensure a0[i] is within the allowed range [-10^9, 10^9]
        // If b[i] was constrained to be less than -10^9, it's an issue.
        // If b[i] was constrained to be greater than 10^9, it's an issue.
        // However, b[i] is an upper bound. If it's e.g. -1.5*10^9, we must set a0[i] <= -1.5*10^9.
        // If it's 1.5*10^9, we must set a0[i] <= 1.5*10^9.
        // The problem states initial values didn't exceed 10^9 in absolute value.
        // So if b[i] < -10^9, it's impossible. If b[i] > 10^9, we can cap it at 10^9.
        // The problem asks for *a* suitable array, so we can pick the largest possible value for a0[i]
        // that satisfies the constraints and the |a_i| <= 10^9 condition.
        a0[i] = std::min(a0[i], 1000000000LL);
        a0[i] = std::max(a0[i], -1000000000LL);
    }

    // Verify the constructed a0
    std::vector<long long> current_a = a0;
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int k = op.l; k <= op.r; ++k) {
                current_a[k] += op.val;
            }
        } else { // type 2
            long long max_val_in_range = LLONG_MIN;
            for (int k = op.l; k <= op.r; ++k) {
                max_val_in_range = std::max(max_val_in_range, current_a[k]);
            }
            if (max_val_in_range != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a0[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false; // This child goes to the doctor

        long long current_v_cry = children[i].v;
        long long accumulated_d_cry = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated_d_cry from previous children who ran away
            if (accumulated_d_cry > 0) {
                children[j].p -= accumulated_d_cry;
            }

            // Apply current_v_cry from the child in the doctor's office
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--; // Volume decreases for children further back
            }

            // Check if child j runs away
            if (children[j].p < 0) {
                children[j].in_line = false;
                accumulated_d_cry += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

// Function to calculate parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of a
    int parity_a = calculate_parity(a);

    // If parity_a is 0, it means an even number of '1's.
    // We can append '0' to 'a' without changing its parity.
    // So, effectively, we can always make the number of '1's in 'a' even
    // by appending '0's until its length is sufficient.
    // If parity_a is 1, it means an odd number of '1's.
    // We can append '1' to 'a', which makes the number of '1's even.
    // After that, we can append '0's.
    // So, if 'a' has an odd number of '1's, we can effectively add one '1' to its count.
    // This means the maximum number of '1's we can achieve in 'a' (considering appending parity)
    // is its current count if parity_a is 0, or current count + 1 if parity_a is 1.
    // This is equivalent to (current_ones_count + parity_a).

    int ones_in_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_in_a++;
        }
    }

    int max_ones_a_can_have = ones_in_a + parity_a;

    // Calculate number of '1's in b
    int ones_in_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_in_b++;
        }
    }

    // Condition 1: The number of '1's in 'b' must be less than or equal to
    // the maximum number of '1's we can effectively have in 'a' after
    // potentially appending one '1' (if initial parity is odd).
    if (ones_in_b > max_ones_a_can_have) {
        std::cout << "NO\n";
        return 0;
    }

    // Condition 2: The length of 'b' must be less than or equal to the length of 'a'
    // plus the number of '1's we effectively added (which is parity_a).
    // This is because each '1' we add (if parity_a is 1) increases the length by 1.
    // Each '0' we add also increases the length by 1.
    // The total length we can achieve is |a| + (number of parity appends).
    // The minimum number of parity appends needed to reach length |b| is max(0, |b| - |a|).
    // If we need to append '1' (because parity_a is 1), that uses one append operation.
    // The remaining appends will be '0's.
    // So, the maximum length 'a' can become while satisfying the '1's count is
    // |a| + (max_ones_a_can_have - ones_in_a) + (some number of '0's).
    // The crucial part is that we can always append '0's if the current parity is even.
    // If we have `max_ones_a_can_have` '1's, the parity of that string is even.
    // So we can append as many '0's as needed to reach any length >= current length.
    // Therefore, if `ones_in_b <= max_ones_a_can_have`, we can always construct a string
    // with `ones_in_b` ones and an even parity, and then append '0's to reach length `|b|`.
    // The only constraint is that the length of 'b' must not exceed the maximum length
    // we can achieve with the available '1's and '0's.
    // The maximum length we can achieve is effectively infinite, as we can always append '0's.
    // However, we must be able to form 'b' by taking a suffix of 'a' (possibly extended).
    // The length of 'b' must be less than or equal to the length of 'a' after
    // considering the potential addition of one '1' (if parity_a is 1).
    // This means the effective length of 'a' that can be used to form 'b' is |a| + parity_a.
    // If |b| > |a| + parity_a, then we cannot form 'b'.

    if (b.length() > a.length() + parity_a) {
        std::cout << "NO\n";
        return 0;
    }

    std::cout << "YES\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    int n = s.length();

    // Check for k=1
    // A single cut divides s into s1 and s2.
    // We can form s1+s2 (original) or s2+s1.
    // We need s2+s1 to be a palindrome and s2+s1 != s.
    // Iterate through all possible cut positions.
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // For k=2, we need to cut s into s1, s2, s3.
    // We can rearrange them.
    // The problem statement guarantees s is a palindrome.
    // If all characters in s are the same (e.g., "aaaa"),
    // then any rearrangement of its substrings will result in the same string,
    // and it will always be a palindrome. In this case, it's impossible.
    // We can check this by counting unique characters.
    bool all_same_char = true;
    if (n > 0) {
        for (int i = 1; i < n; ++i) {
            if (s[i] != s[0]) {
                all_same_char = false;
                break;
            }
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work,
    // then k=2 is always possible.
    // Consider s = "nolon". k=1 fails.
    // s[0] != s[1], so not all same char.
    // We can cut s into s[0...i-1], s[i], s[i+1...n-1].
    // For example, cut "nolon" into "no", "l", "on".
    // Rearrange to "on", "l", "no" -> "onlno". This is a palindrome and != "nolon".
    // This strategy works for any palindrome s that is not composed of all identical characters.
    // The minimum number of cuts is 2.
    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // All pairs (a_i, a_j) are in the same subsequence.
    // f(a_i, a_j) = a_i + a_j.
    // Min f = a[0].value + a[1].value
    // Max f = a[n-1].value + a[n-2].value
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 1].value + a[n - 2].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences.
    // The optimal strategy for minimizing goodness is to put a[0] in one subsequence
    // and a[1] in the other, or a[n-1] in one and a[n-2] in the other, etc.
    // The key observation is that if h is large, we want to avoid pairs in different subsequences.
    // If h is small, we might want to mix.
    //
    // Consider the partition where a[0] is in S1, and all other elements are in S2.
    // This is a common strategy for minimizing range when h is large.
    //
    // Pairs in S1: None (if n > 1, a[0] is alone in S1)
    // Pairs in S2: (a[i], a[j]) for i,j >= 1.
    //   Min S2 sum: a[1].value + a[2].value
    //   Max S2 sum: a[n-1].value + a[n-2].value
    // Pairs (a_i, a_j) with a_i in S1 and a_j in S2: (a[0], a[k]) for k >= 1.
    //   Min S1-S2 sum: a[0].value + a[1].value + h
    //   Max S1-S2 sum: a[0].value + a[n-1].value + h
    //
    // Overall min f: min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    // Overall max f: max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h)
    //
    // This specific partition (a[0] in S1, rest in S2) is one of the candidates.
    // Let's analyze the values:
    // min_same = a[1].value + a[2].value (if n >= 3, else infinity)
    // max_same = a[n-1].value + a[n-2].value (if n >= 3, else 0)
    // min_diff = a[0].value + a[1].value + h
    // max_diff = a[0].value + a[n-1].value + h
    //
    // If n=2: a[0] in S1, a[1] in S2. Only one pair (a[0], a[1]), different subsequences.
    // f(a[0], a[1]) = a[0].value + a[1].value + h. Min f = Max f. Goodness = 0.
    // This is a special case.
    if (n == 2) {
        std::cout << 0 << std::endl;
        std::vector<int> result_partition(n);
        result_partition[a[0].original_index] = 1;
        result_partition[a[1].original_index] = 2;
        for (int i = 0; i < n; ++i) {
            std::cout << result_partition[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // For n >= 3:
    long long min_f_val_case2, max_f_val_case2;

    // The minimum possible sum from elements in S2 (a[1]...a[n-1])
    long long min_same_S2 = a[1].value + a[2].value;
    // The maximum possible sum from elements in S2 (a[1]...a[n-1])
    long long max_same_S2 = a[n-1].value + a[n-2].value;

    // The minimum possible sum from elements in different subsequences (a[0] vs a[k] for k>=1)
    long long min_diff_S1S2 = a[0].value + a[1].value + h;
    // The maximum possible sum from elements in different subsequences (a[0] vs a[k] for k>=1)
    long long max_diff_S1S2 = a[0].value + a[n-1].value + h;

    min_f_val_case2 = std::min(min_same_S2, min_diff_S1S2);
    max_f_val_case2 = std::max(max_same_S2, max_diff_S1S2);

    long long goodness2 = max_f_val_case2 - min_f_val_case2;
    std::vector<int> partition2(n);
    partition2[a[0].original_index] = 1; // a[0] in S1
    for (int i = 1; i < n; ++i) {
        partition2[a[i].original_index] = 2; // rest in S2
    }

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
    } else {
        std::cout << goodness2 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }

    return 0;
}

