int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::sqrt(n));

    // If n is a perfect square, k*k = n.
    // If n is not a perfect square, k*k < n.
    // We want to ensure that the number of blocks is at least k.
    // The number of blocks will be ceil(n/k).
    // If k*k < n, then ceil(n/k) > k.
    // If k*k = n, then ceil(n/k) = k.
    // This construction aims for LIS = k and LDS = ceil(n/k).
    // To achieve this, we can use blocks of size k, and reverse each block.
    // The last block might be smaller.

    // Example: n=4, k=2
    // Blocks: [1,2], [3,4]
    // Reversed: [2,1], [4,3] -> 2 1 4 3. LIS=2, LDS=2. Sum=4.
    // The example output is 3 4 1 2. LIS=2, LDS=2. Sum=4.
    // My construction: 2 1 4 3. LIS: [2,4], [1,4], [2,3], [1,3]. Length 2.
    // LDS: [2,1], [4,3]. Length 2. Sum 4.

    // Example: n=5, k=2
    // Blocks: [1,2], [3,4], [5]
    // Reversed: [2,1], [4,3], [5] -> 2 1 4 3 5.
    // LIS: [2,4,5], [1,4,5], [2,3,5], [1,3,5]. Length 3.
    // LDS: [2,1], [4,3]. Length 2. Sum 5.
    // ceil(n/k) = ceil(5/2) = 3.
    // LIS = k = 2. LDS = ceil(n/k) = 3.
    // This construction gives LIS = ceil(n/k) and LDS = k.
    // Let's verify:
    // The elements within each block are decreasing. So any increasing subsequence can pick at most one element from each block.
    // There are ceil(n/k) blocks. So LIS <= ceil(n/k).
    // The elements across blocks are increasing (e.g., max of block 1 < min of block 2).
    // E.g., 2 1 | 4 3 | 5.
    // LIS: [1,3,5] or [2,4,5]. Length 3. This is ceil(n/k).
    // LDS: [2,1], [4,3]. Length 2. This is k.
    // So LIS = ceil(n/k) and LDS = k.
    // Sum = k + ceil(n/k). This is optimal.

    for (int i = 0; i < n; ++i) {
        int block_start_val = (i / k) * k + 1;
        int block_idx_in_block = i % k;

        // Calculate the value for the current position
        // It's block_start_val + (k - 1 - block_idx_in_block)
        // But we need to handle the last block which might be smaller.
        // The numbers are 1-indexed.
        // The current number is `i+1`.
        // The block it belongs to is `(i+1-1)/k`.
        // The first element of this block (in sorted order) is `(i/k)*k + 1`.
        // The last element of this block (in sorted order) is `min(n, (i/k)*k + k)`.
        // We want to print elements in decreasing order within each block.
        // So for block `j` (0-indexed), elements are `(j*k+k), (j*k+k-1), ..., (j*k+1)`.
        // But we need to cap at `n`.

        // Let's iterate through blocks.
        // Block `b` (0-indexed) contains numbers from `b*k + 1` to `min(n, (b+1)*k)`.
        // We want to print them in reverse order.
        // So for block `b`, print `min(n, (b+1)*k)`, then `min(n, (b+1)*k) - 1`, ..., `b*k + 1`.
    }

    for (int b = 0; b * k < n; ++b) { // Iterate through blocks
        int block_start = b * k + 1;
        int block_end = std::min(n, (b + 1) * k);
        for (int val = block_end; val >= block_start; --val) {
            std::cout << val << (val == block_start && (b + 1) * k >= n ? "" : " ");
        }
    }
    std::cout << std::endl;

    return 0;
