            //   We need to find the smallest `b_i` in this set such that `b_i >= prev_val`.
            //   If `prev_val` is in `[a_i, m-1]`:
            //     Then `b_i = prev_val` is possible.
            //     This means `a_i <= prev_val <= m-1`.
            //     This is valid. `prev_val` for next iteration remains `prev_val`.
            //   Else if `prev_val` is in `[0, val_after_mid]`:
            //     Then `b_i = prev_val` is possible.
            //     This means `0 <= prev_val <= val_after_mid`.
            //     This is valid. `prev_val` for next iteration remains `prev_val`.
            //   Else (`prev_val` is not in either range):
            //     This means `val_after_mid < prev_val < a_i`.
            //     No `b_i` can be chosen. Impossible.
            //
            // Let's try this logic:
            // We need to find `b_i` such that `b_i >= prev_val` and `b_i` is reachable from `a_i` with `x <= mid` operations.
            //
            // Case 1: `a_i >= prev_val`.
            //   We can potentially keep `b_i = a_i`. This requires `x=0` operations, which is `<= mid`.
            //   So `a_i` is a valid candidate for `b_i`.
            //   Can we make `b_i = prev_val`? This would be better for future elements.
            //   To make `b_i = prev_val`, we need `(a_i + x) % m = prev_val` for some `x <= mid`.
            //   If `a_i = prev_val`, then `x=0` works.
            //   If `a_i > prev_val`, then `x` must be `prev_val + m - a_i`.
            //   If `prev_val + m - a_i <= mid`, then we can set `b_i = prev_val`.
            //   Otherwise, we must set `b_i = a_i`.
            //   So, if `a_i >= prev_val`:
            //     If `prev_val + m - a_i <= mid`: `prev_val` for next iteration remains `prev_val`.
            //     Else: `prev_val` for next iteration becomes `a_i`.
            //
            // Case 2: `a_i < prev_val`.
            //   We must increment `a_i`.
            //   We need `(a_i + x) % m >= prev_val` for some `x <= mid`.
            //   The smallest value `a_i` can become that is `>= prev_val` is `prev_val` itself.
            //   To reach `prev_val` from `a_i` (without wrapping), we need `x = prev_val - a_i` operations.
            //   If `prev_val - a_i <= mid`:
            //     We can set `b_i = prev_val`. `prev_val` for next iteration remains `prev_val`.
            //   Else (`prev_val - a_i > mid`):
            //     This means we cannot reach `prev_val` without wrapping.
            //     The values `a_i` can become are `a_i, a_i+1, ..., m-1, 0, 1, ..., (a_i+mid)%m`.
            //     Since `a_i < prev_val`, we must use values from `0` to `(a_i+mid)%m`.
            //     If `(a_i + mid) % m < prev_val`, then it's impossible to make `b_i >= prev_val`.
            //     So, `possible = false`.
            //     Otherwise (`(a_i + mid) % m >= prev_val`), it is possible.
            //     We can set `b_i = prev_val`. `prev_val` for next iteration remains `prev_val`.
            //
            // Combining these:
            // If `a_i >= prev_val`:
            //   If `prev_val + m - a_i <= mid`: // Can wrap around to `prev_val`
            //     `prev_val` remains `prev_val`.
            //   Else: // Cannot wrap around to `prev_val`, must use `a_i` or higher
            //     `prev_val` becomes `a_i`.
            // Else (`a_i < prev_val`):
            //   If `prev_val - a_i <= mid`: // Can reach `prev_val` without wrapping
            //     `prev_val` remains `prev_val`.
            //   Else: // Cannot reach `prev_val` without wrapping, must wrap
            //     // Check if `(a_i + mid) % m` is large enough.
            //     // If `a_i + mid` wraps, then `(a_i + mid) % m` is the largest value reachable after wrap.
            //     // If `(a_i + mid) % m < prev_val`, then it's impossible.
            //     // Note: `a_i + mid` is the value before modulo.
            //     // If `a_i + mid < m`, then `(a_i + mid) % m = a_i + mid`.
            //     // If `a_i + mid >= m`, then `(a_i + mid) % m` is the wrapped value.
            //     // The condition `prev_val - a_i > mid` implies `a_i + mid < prev_val`.
            //     // So if `a_i + mid < m`, then `a_i + mid < prev_val`, which means we can't reach `prev_val`.
            //     // So we must have `a_i + mid >= m` (i.e., wrap-around).
            //     // In this case, the values reachable are `a_i, ..., m-1, 0, ..., (a_i+mid)%m`.
            //     // Since `a_i < prev_val`, we must use values from `0` to `(a_i+mid)%m`.
            //     // If `(a_i + mid) % m < prev_val`, then it's impossible.
            //     if ((a_i + mid) % m < prev_val) {
            //         possible = false;
            //         break;
            //     }
            //     // Else, it is possible to reach `prev_val` by wrapping.
            //     // `prev_val` remains `prev_val`.
            //
            // This logic seems correct.

            if (a[i] >= prev_val) {
                // Option 1: Keep a[i] as is. This is valid if 0 operations are needed, which is <= mid.
                // Option 2: Try to make it prev_val by wrapping around.
                // This requires (prev_val + m - a[i]) operations.
                // If this is <= mid, we can make it prev_val.
                if (prev_val + m - a[i] <= mid) {
                    // We can make it prev_val. Keep prev_val for next iteration.
                    // prev_val = prev_val; (no change)
                } else {
                    // Cannot make it prev_val by wrapping. Must use a[i] or higher.
                    // The smallest value >= prev_val we can make is a[i].
                    prev_val = a[i];
                }
            } else { // a[i] < prev_val
                // Option 1: Try to make it prev_val without wrapping.
                // This requires (prev_val - a[i]) operations.
                // If this is <= mid, we can make it prev_val.
                if (prev_val - a[i] <= mid) {
                    // We can make it prev_val. Keep prev_val for next iteration.
                    // prev_val = prev_val; (no change)
                } else {
                    // Cannot make it prev_val without wrapping.
                    // We must wrap around. The largest value we can reach is (a[i] + mid) % m.
                    // If this value is still less than prev_val, it's impossible.
                    if ((a[i] + mid) % m < prev_val) {
                        possible = false;
                        break;
                    }
                    // Else, it is possible to reach prev_val by wrapping.
                    // prev_val = prev_val; (no change)
                }
            }
        }

        if (possible) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int head_idx = 0;
    for (int p_idx = 0; p_idx < m; ++p_idx) {
        // Find the first head that can potentially cover p[p_idx]
        // A head h[head_idx] can cover p[p_idx] if h[head_idx] + T >= p[p_idx]
        // We need to find a head such that h[head_idx] - T <= p[p_idx] <= h[head_idx] + T
        // Or, p[p_idx] - T <= h[head_idx] <= p[p_idx] + T

        // Advance head_idx until h[head_idx] is within range [p[p_idx] - T, infinity)
        // i.e., h[head_idx] >= p[p_idx] - T
        while (head_idx < n && h[head_idx] < p[p_idx] - T) {
            head_idx++;
        }

        if (head_idx == n) {
            // No more heads available, and p[p_idx] is not covered.
            return false;
        }

        // Now h[head_idx] >= p[p_idx] - T.
        // We need to cover p[p_idx]. The current head h[head_idx] can cover up to h[head_idx] + T.
        // We want to cover as many subsequent p_i's as possible with this head.
        // The current head h[head_idx] covers the range [p[p_idx], h[head_idx] + T].
        // We need to find the largest p_k such that p_k <= h[head_idx] + T.
        // All p_i from p[p_idx] to p_k are covered by this head.

        long long current_head_reach = h[head_idx] + T;

        // Find the last track p_k that can be covered by the current head h[head_idx]
        // All tracks p[p_idx]...p[k] are covered.
        // The loop for p_idx will then continue from p[k+1].
        while (p_idx < m && p[p_idx] <= current_head_reach) {
            p_idx++;
        }
        p_idx--; // Decrement p_idx because the outer loop will increment it.
                 // This ensures the next iteration starts with the first uncovered track.

        head_idx++; // Move to the next head for the next uncovered track.
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible difference between p_i and h_j is 10^10.
                                    // So T can be up to 10^10.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_zero_block_len(n, 0);
    std::vector<int> right_zero_block_len(n, 0);
    std::vector<int> left_one_block_len(n, 0);
    std::vector<int> right_one_block_len(n, 0);

    // Calculate block lengths for initial sequence
    // Left zero block lengths
    if (a[0] == 0) left_zero_block_len[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zero_block_len[i] = left_zero_block_len[i - 1] + 1;
        } else {
            left_zero_block_len[i] = 0;
        }
    }
    // Right zero block lengths
    if (a[n - 1] == 0) right_zero_block_len[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zero_block_len[i] = right_zero_block_len[i + 1] + 1;
        } else {
            right_zero_block_len[i] = 0;
        }
    }
    // Left one block lengths
    if (a[0] == 1) left_one_block_len[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == 1) {
            left_one_block_len[i] = left_one_block_len[i - 1] + 1;
        } else {
            left_one_block_len[i] = 0;
        }
    }
    // Right one block lengths
    if (a[n - 1] == 1) right_one_block_len[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 1) {
            right_one_block_len[i] = right_one_block_len[i + 1] + 1;
        } else {
            right_one_block_len[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // 0s can become 1s
            if (left_one_block_len[i - 1] > 0 && right_one_block_len[i + 1] > 0) {
                // This 0 is surrounded by 1s. It will become 1.
                // The number of steps depends on the minimum length of the surrounding 1-blocks.
                max_k = std::max(max_k, std::min(left_one_block_len[i - 1], right_one_block_len[i + 1]));
            }
        } else { // 1s can become 0s
            if (left_zero_block_len[i - 1] > 0 && right_zero_block_len[i + 1] > 0) {
                // This 1 is surrounded by 0s. It will become 0.
                // The number of steps depends on the minimum length of the surrounding 0-blocks.
                max_k = std::max(max_k, std::min(left_zero_block_len[i - 1], right_zero_block_len[i + 1]));
            }
        }
    }

    std::cout << max_k << std::endl;

    std::vector<int> result_a = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) {
            if (left_one_block_len[i - 1] > 0 && right_one_block_len[i + 1] > 0) {
                if (std::min(left_one_block_len[i - 1], right_one_block_len[i + 1]) <= max_k) {
                    result_a[i] = 1;
                }
            }
        } else { // a[i] == 1
            if (left_zero_block_len[i - 1] > 0 && right_zero_block_len[i + 1] > 0) {
                if (std::min(left_zero_block_len[i - 1], right_zero_block_len[i + 1]) <= max_k) {
                    result_a[i] = 0;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << result_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}
